/**
 * ═══════════════════════════════════════════════════════════════════════════
 *  bmg_patches_combined.js  —  BookMyGame / SpörtoBook  (MASTER COMBINED)
 * ═══════════════════════════════════════════════════════════════════════════
 *
 *  REPLACES ALL of the following files (do NOT load them separately):
 *    bmg_master_fix.js, bmg_master_fix_v2.js, bmg_master_fix_v4.js,
 *    bmg_master_patch_v3.js, bmg_all_fixes_final.js,
 *    bmg_all_fixes_final__1_.js, bmg_comprehensive_fix.js,
 *    bmg_final_fix.js, bmg_fixes_v4.js, bmg_instant_fixes.js,
 *    bmg_earnings_admin_fix_v3.js, bmg_earnings_collection_fix.js,
 *    bmg_earnings_fix_v2.js, bmg_cf_bypass.js, bmg_fix_canaddground.js,
 *    app_payment_integration.js
 *
 *  LOAD ORDER in index.html (end of <body>):
 *    <script src="https://sdk.cashfree.com/js/v3/cashfree.js"></script>
 *    <script src="paymentService.js"></script>
 *    <script src="app.js"></script>
 *    <script src="bmg_patches_combined.js"></script>   ← this file, LAST
 *
 * ═══════════════════════════════════════════════════════════════════════════
 *
 *  FEATURES INCLUDED:
 *
 *  [P]  Payment integration helpers (handleBookingPayment, handleTournamentPayment,
 *       showOwnerRegistrationPayment, setupPayButton, stripEmptyFields)
 *  [S]  Slot renderer: booked slots show RED "Booked" badge professionally;
 *       real-time Firestore listener; expired lock cleanup
 *  [T]  Tournament: QR entry pass, auto-confirm, spots counter, My Bookings tab,
 *       owner QR verification, _showTournamentJoinedSuccess with QR
 *  [O]  Owner: canAddGround with registrationVerified auto-fix; congratulations
 *       screen; registration login fix
 *  [E]  Earnings: owner earnings with per-booking history + tournament;
 *       Admin/CEO earnings tab; bmgAdminTransferPaymentV3
 *  [A]  Admin/CEO dashboard: owner list, bookings tab, payout list,
 *       Owner Earnings tab injection
 *  [I]  Instant fixes: Firestore-only tournament payment recovery (no CF calls);
 *       deduplication of bmg:paymentConfirmed; CF bypass stubs
 *  [H]  Home page: nearby venues with geolocation, shimmer skeleton, city filter
 *  [Q]  QR scanner: booking + tournament verification, compact QR format
 *  [U]  UI patches: image viewer, profile photo sheet, QR scanner animation,
 *       ground step navigation, tournament form fields
 *  [G]  Guards: cleanupExpiredLocks auth guard; handleRegister alias;
 *       initCashfree stub; 404 script suppression
 *
 * ═══════════════════════════════════════════════════════════════════════════
 */

/* ══════════════════════════════════════════════════════════════════════════
 * §0  GLOBAL VARIABLE GUARDS (synchronous — before anything else)
 * ══════════════════════════════════════════════════════════════════════════*/
if (typeof window.tournamentCurrentStep === 'undefined') window.tournamentCurrentStep = 1;
if (typeof window.tournamentTotalSteps  === 'undefined') window.tournamentTotalSteps  = 4;
if (typeof window.currentGroundStep     === 'undefined') window.currentGroundStep     = 1;
if (typeof window.totalGroundSteps      === 'undefined') window.totalGroundSteps      = 3;
if (typeof window._ivTranslateX        === 'undefined') { window._ivTranslateX = 0; window._ivTranslateY = 0; }

/* ══════════════════════════════════════════════════════════════════════════
 * §1  CF BYPASS — stub checkOrderStatus Cloud Function (CORS blocked)
 * ══════════════════════════════════════════════════════════════════════════*/
(function _installCFBypass() {
  const CF_BLOCK = ['checkOrderStatus'];
  const _origFetch = window.fetch.bind(window);

  window.fetch = function (input, init) {
    const url = typeof input === 'string' ? input : (input?.url || '');
    if (CF_BLOCK.some(p => url.includes(p))) {
      console.log('[BMG] CF bypass: stubbing', url);
      return Promise.resolve(
        new Response(JSON.stringify({ status: 'PENDING', bypassed: true }), {
          status: 200, headers: { 'Content-Type': 'application/json' },
        })
      );
    }
    return _origFetch(input, init);
  };

  // Deduplicate bmg:paymentConfirmed events
  const _fired = new Set();
  const _origDispatch = window.dispatchEvent.bind(window);
  window.dispatchEvent = function (event) {
    if (event?.type === 'bmg:paymentConfirmed') {
      const oid = event.detail?.orderId;
      if (oid) {
        if (_fired.has(oid)) { console.log('[BMG] Deduplicated paymentConfirmed', oid); return true; }
        _fired.add(oid);
        setTimeout(() => _fired.delete(oid), 5 * 60 * 1000);
      }
    }
    return _origDispatch(event);
  };

  console.log('[BMG] CF bypass + event deduplication active');
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §2  UTILITY HELPERS
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  function _esc(s) {
    return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }
  window._esc = _esc;

  function _fmt(v) {
    return typeof window.formatCurrency === 'function'
      ? window.formatCurrency(v)
      : '₹' + Number(v || 0).toLocaleString('en-IN');
  }

  function _toast(msg, type, dur) {
    if (typeof window.showToast === 'function') window.showToast(msg, type || 'info', dur || 4000);
  }

  function _showLoading(msg) { if (typeof window.showLoading === 'function') window.showLoading(msg); }
  function _hideLoading() { if (typeof window.hideLoading === 'function') window.hideLoading(); }

  function waitFor(name, cb, ms, maxMs) {
    if (typeof window[name] !== 'undefined') { cb(window[name]); return; }
    const start = Date.now();
    const t = setInterval(() => {
      if (typeof window[name] !== 'undefined') { clearInterval(t); cb(window[name]); return; }
      if (Date.now() - start > (maxMs || 12000)) { clearInterval(t); }
    }, ms || 120);
  }

  function onReady(fn) {
    if (document.readyState !== 'loading') fn();
    else document.addEventListener('DOMContentLoaded', fn);
  }

  // Expose helpers on window for use across IIFEs
  window._bmgFmt = _fmt;
  window._bmgToast = _toast;
  window._bmgShowLoading = _showLoading;
  window._bmgHideLoading = _hideLoading;
  window._bmgWaitFor = waitFor;
  window._bmgOnReady = onReady;

  /* ── Stubs for missing globals ─────────────────────────────────── */
  if (typeof window.handleRegister === 'undefined') {
    window.handleRegister = function (e) {
      if (typeof window.handleUserRegister === 'function') return window.handleUserRegister(e);
    };
  }
  if (typeof window.initCashfree === 'undefined') {
    window.initCashfree = function () {
      console.log('[BMG] initCashfree() stub — managed by paymentService.js');
    };
  }
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §3  PAYMENT INTEGRATION HELPERS
 *     (replaces app_payment_integration.js + related helpers)
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  // ── [P1] Ground booking payment ──────────────────────────────────────
  async function handleBookingPayment(bookingDetails) {
    const safe = JSON.parse(JSON.stringify(bookingDetails));
    const paymentData = {
      groundId      : String(safe.groundId      || ''),
      groundName    : String(safe.groundName    || ''),
      venueName     : String(safe.venueName     || ''),
      venueAddress  : String(safe.venueAddress  || ''),
      groundAddress : String(safe.groundAddress || ''),
      sportType     : String(safe.sportType     || ''),
      ownerId       : String(safe.ownerId       || ''),
      isPlotOwner   : Boolean(safe.isPlotOwner  || false),
      date          : String(safe.date          || ''),
      slotTime      : String(safe.slotTime      || ''),
      amount        : Number(safe.amount),
      originalAmount: Number(safe.originalAmount || safe.amount),
      userName      : String(safe.userName  || window.currentUser?.name  || ''),
      userEmail     : String(safe.userEmail || window.currentUser?.email || ''),
      userPhone     : String(safe.userPhone || window.currentUser?.phone || ''),
      ownerAmount   : Number(safe.ownerAmount || 0),
      promoCode     : String(safe.promoCode   || ''),
      appliedOffer  : String(safe.appliedOffer || ''),
    };
    await window.startPayment(paymentData, 'booking');
  }

  function setupPayButton(bookingDetails) {
    const btn = document.getElementById('cashfree-pay-btn');
    if (!btn) return;
    const fresh = btn.cloneNode(true);
    btn.parentNode.replaceChild(fresh, btn);
    fresh.addEventListener('click', async (e) => {
      e.preventDefault();
      await handleBookingPayment(bookingDetails);
    });
  }

  function showBookingPage(bookingDetails) {
    const safe = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val ?? ''; };
    safe('booking-ground-name', bookingDetails.groundName);
    safe('booking-date',        bookingDetails.date);
    safe('booking-time',        bookingDetails.slotTime);
    safe('booking-amount',      window._bmgFmt(bookingDetails.amount));
    safe('payment-amount',      window._bmgFmt(bookingDetails.amount));
    safe('platform-fee',        window._bmgFmt(bookingDetails.amount * 0.10));
    safe('final-amount',        window._bmgFmt(bookingDetails.amount));
    try { sessionStorage.setItem('currentBookingDetails', JSON.stringify(bookingDetails)); } catch (_) {}
    setupPayButton(bookingDetails);
    if (typeof window.showPage === 'function') window.showPage('booking-page');
  }

  // ── [P2] Owner onboarding ─────────────────────────────────────────────
  async function showOwnerRegistrationPayment() {
    const cu = window.currentUser;
    if (!cu) { window._bmgToast('Please log in first', 'warning'); return; }
    const db = window.db;
    try {
      const snap = await db.collection('owners').doc(cu.uid).get();
      if (snap.exists) {
        const o = snap.data();
        if (o.isActive && o.paymentDone) { window._bmgToast('Your account is already active!', 'success'); return; }
      }
      const owner = snap.exists ? snap.data() : {};
      await window.startPayment({
        ownerId  : String(cu.uid),
        userName : String(cu.name  || owner.name  || ''),
        userEmail: String(cu.email || owner.email || ''),
        userPhone: String(cu.phone || owner.phone || ''),
        amount   : 5,
      }, 'owner_onboarding');
    } catch (err) { window._bmgToast('Error: ' + err.message, 'error'); }
  }

  // ── [P3] Tournament payment ───────────────────────────────────────────
  window.handleTournamentPayment = async function (tournament, teamName = '') {
    const cu = window.currentUser;
    if (!cu) { window._bmgToast('Please log in to register', 'warning'); return; }
    if (!tournament?.entryFee || tournament.entryFee <= 0) { window._bmgToast('Invalid entry fee', 'error'); return; }

    const db = window.db;
    const existing = await db.collection('tournament_entries')
      .where('tournamentId', '==', tournament.id).where('userId', '==', cu.uid).limit(1).get();
    if (!existing.empty) { window._bmgToast('You are already registered for this tournament.', 'warning'); return; }

    const safe = JSON.parse(JSON.stringify(tournament));
    const paymentData = {
      tournamentId  : String(safe.id            || ''),
      tournamentName: String(safe.name || safe.tournamentName || ''),
      amount        : Number(safe.entryFee),
      userId        : String(cu.uid),
      userName      : String(cu.name   || ''),
      userEmail     : String(cu.email  || ''),
      userPhone     : String(cu.phone  || ''),
      teamName      : String(teamName  || ''),
      sport         : String(safe.sport  || ''),
      date          : String(safe.date   || ''),
      venue         : String(safe.venue  || ''),
    };

    // Save reg data before startPayment (for page-reload recovery)
    try {
      sessionStorage.setItem(`bmg_tournReg_${paymentData.tournamentId}`, JSON.stringify({
        ...paymentData, savedAt: Date.now()
      }));
    } catch (_) {}

    await window.startPayment(paymentData, 'tournament');
  };

  // ── [P4] Strip empty fields helper ───────────────────────────────────
  window.stripEmptyFields = function (obj) {
    return Object.fromEntries(
      Object.entries(obj).filter(([, v]) => {
        if (v === null || v === undefined) return false;
        if (typeof v === 'string' && v === '') return false;
        if (typeof v === 'number' && Number.isNaN(v)) return false;
        return true;
      })
    );
  };

  // ── [P5] Payment confirmed event router ───────────────────────────────
  window.addEventListener('bmg:paymentConfirmed', (e) => {
    const { orderId, paymentType, result } = e.detail;
    console.log('✅ Payment confirmed:', paymentType, orderId);

    switch (paymentType) {
      case 'booking':
        if (typeof window.showBookingSuccessConfirmation === 'function') {
          window.showBookingSuccessConfirmation(result || { bookingId: orderId });
        }
        // Store bookingId for entry pass
        const bid = result?.bookingId || orderId;
        if (bid) {
          window._lastConfirmedBookingId = bid;
          try { sessionStorage.setItem('lastBookingId', bid); } catch (_) {}
        }
        break;
      case 'owner_onboarding':
        window._bmgToast('🎉 Account activated! You can now list your ground.', 'success', 6000);
        setTimeout(() => _showOwnerCongratulationsScreen(), 400);
        break;
      case 'tournament':
        window._bmgToast('🏆 Tournament registration confirmed! Check "My Tournaments".', 'success', 6000);
        if (typeof window.loadMyTournaments === 'function') window.loadMyTournaments();
        break;
    }
  });

  // ── Expose globals ────────────────────────────────────────────────────
  window.handleBookingPayment           = handleBookingPayment;
  window.showOwnerRegistrationPayment   = showOwnerRegistrationPayment;
  window.processRegistrationPayment     = showOwnerRegistrationPayment;
  window.initiateOwnerOnboardingPayment = showOwnerRegistrationPayment;
  window.showBookingPage                = showBookingPage;
  window.setupPayButton                 = setupPayButton;

  /* ── Owner congratulations screen ────────────────────────────────── */
  function _showOwnerCongratulationsScreen() {
    const existing = document.getElementById('bmg-owner-congrats');
    if (existing) existing.remove();

    const el = document.createElement('div');
    el.id = 'bmg-owner-congrats';
    el.style.cssText = 'position:fixed;inset:0;z-index:99999;background:linear-gradient(135deg,#1b2e6c,#2563eb);display:flex;flex-direction:column;align-items:center;justify-content:center;padding:32px;animation:bmgFadeIn .4s ease;';
    el.innerHTML = `
      <div style="text-align:center;color:#fff;max-width:380px;">
        <div style="font-size:72px;margin-bottom:16px;">🎉</div>
        <h1 style="font-size:26px;font-weight:800;margin:0 0 8px;">Congratulations!</h1>
        <p style="font-size:16px;opacity:.85;margin:0 0 8px;">You're now a Real Businessman</p>
        <p style="font-size:14px;opacity:.7;margin:0 0 32px;">Your owner account is active. Start listing your grounds and earning!</p>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:28px;">
          <div style="background:rgba(255,255,255,.15);border-radius:14px;padding:16px;">
            <div style="font-size:24px;">🏟️</div>
            <div style="font-size:13px;margin-top:6px;font-weight:600;">List Grounds</div>
          </div>
          <div style="background:rgba(255,255,255,.15);border-radius:14px;padding:16px;">
            <div style="font-size:24px;">💰</div>
            <div style="font-size:13px;margin-top:6px;font-weight:600;">Earn Money</div>
          </div>
        </div>
        <button id="bmg-congrats-cta" style="width:100%;padding:16px;background:#fff;color:#1b2e6c;border:none;border-radius:16px;font-size:16px;font-weight:800;cursor:pointer;">
          Go to Owner Dashboard 🚀
        </button>
      </div>`;
    document.body.appendChild(el);
    el.querySelector('#bmg-congrats-cta').addEventListener('click', () => {
      el.remove();
      if (typeof window.loadOwnerDashboard === 'function') window.loadOwnerDashboard();
      if (typeof window.showPage === 'function') window.showPage('owner-dashboard');
    });
  }
  window._showOwnerCongratulationsScreen = _showOwnerCongratulationsScreen;
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §4  SLOT RENDERER & REAL-TIME LISTENER
 *     Professional slot UI: booked=RED, available=GREEN, past=GRAY
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  /* ── CSS ─────────────────────────────────────────────────────────────── */
  function _injectSlotCSS() {
    if (document.getElementById('bmg-slot-css')) return;
    const s = document.createElement('style');
    s.id = 'bmg-slot-css';
    s.textContent = `
/* ── SLOT GRID ──────────────────────────────────────────────── */
.slots-grid { display:grid; grid-template-columns:repeat(3,1fr); gap:10px; padding:4px 0; }
.time-slot {
  position:relative; display:flex; flex-direction:column;
  align-items:center; justify-content:center; gap:4px;
  padding:10px 6px; border-radius:12px; border:2px solid #e5e7eb;
  background:#fff; font-size:12px; font-weight:600; cursor:pointer;
  transition:all .2s cubic-bezier(.4,0,.2,1); overflow:hidden;
  min-height:64px; user-select:none;
}
.time-slot .slot-time-text { font-size:11.5px; font-weight:700; letter-spacing:-.2px; line-height:1.2; text-align:center; }
.time-slot .slot-status-tag {
  font-size:9.5px; font-weight:700; letter-spacing:.3px;
  text-transform:uppercase; padding:2px 7px; border-radius:20px;
}
.time-slot .slot-icon { font-size:13px; margin-bottom:1px; }

/* AVAILABLE */
.time-slot.available {
  border-color:#22c55e;
  background:linear-gradient(135deg,#f0fdf4,#dcfce7);
  color:#166534; box-shadow:0 2px 8px rgba(34,197,94,.12);
}
.time-slot.available .slot-status-tag { background:rgba(34,197,94,.15); color:#15803d; }
.time-slot.available:hover { transform:translateY(-3px) scale(1.03); box-shadow:0 6px 20px rgba(34,197,94,.25); border-color:#16a34a; }

/* SELECTED */
.time-slot.available.selected, .time-slot.selected {
  background:linear-gradient(135deg,#1b2e6c,#2563eb);
  border-color:#1b2e6c; color:#fff;
  transform:scale(1.04); box-shadow:0 6px 20px rgba(27,46,108,.35);
}

/* CONFIRMED / BOOKED  ← RED — the most important fix */
.time-slot.confirmed, .time-slot.booked {
  border-color:#ef4444 !important;
  background:linear-gradient(135deg,#fef2f2,#fee2e2) !important;
  color:#991b1b !important;
  cursor:not-allowed !important;
  pointer-events:none !important;
}
.time-slot.confirmed .slot-status-tag,
.time-slot.booked .slot-status-tag {
  background:rgba(239,68,68,.18) !important;
  color:#dc2626 !important;
  font-weight:800 !important;
}
.time-slot.confirmed .slot-icon,
.time-slot.booked .slot-icon { filter:drop-shadow(0 0 4px rgba(239,68,68,.4)); }

/* PAST */
.time-slot.past {
  border-color:#d1d5db; background:linear-gradient(135deg,#f9fafb,#f3f4f6);
  color:#9ca3af; cursor:not-allowed; opacity:.75;
}
.time-slot.past .slot-time-text { text-decoration:line-through; text-decoration-color:#d1d5db; }
.time-slot.past .slot-status-tag { background:rgba(156,163,175,.15); color:#9ca3af; }

/* LOCKED / PROCESSING */
.time-slot.locked {
  border-color:#f59e0b; background:linear-gradient(135deg,#fffbeb,#fef3c7);
  color:#92400e; cursor:not-allowed;
}
.time-slot.locked .slot-status-tag { background:rgba(245,158,11,.15); color:#d97706; }

/* CLOSED */
.time-slot.closed {
  border-color:#9ca3af; background:#f9fafb; color:#9ca3af; cursor:not-allowed; opacity:.6;
}

/* LEGEND */
.slot-legend { display:flex; gap:14px; flex-wrap:wrap; padding:10px 0 14px; font-size:11px; font-weight:600; color:#6b7280; }
.slot-legend-item { display:flex; align-items:center; gap:5px; }
.slot-legend-dot { width:10px; height:10px; border-radius:50%; flex-shrink:0; }
.slot-legend-dot.available { background:#22c55e; }
.slot-legend-dot.booked    { background:#ef4444; }
.slot-legend-dot.past      { background:#d1d5db; }
.slot-legend-dot.locked    { background:#f59e0b; }

/* SLOT BADGES */
.bmg-sb { display:inline-block; font-size:9px; font-weight:700; letter-spacing:.04em;
  text-transform:uppercase; padding:2px 5px; border-radius:4px; margin-left:4px; vertical-align:middle; }
.bmg-sb.booked  { background:#fee2e2; color:#dc2626; }
.bmg-sb.locked  { background:#fef3c7; color:#d97706; }
.bmg-sb.mine    { background:#d1fae5; color:#059669; }

/* SLOT RELEASED TOAST */
.slot-released-toast {
  position:fixed; bottom:90px; left:50%; transform:translateX(-50%);
  background:linear-gradient(135deg,#1b2e6c,#2563eb); color:#fff;
  padding:12px 20px; border-radius:14px; font-size:13px; font-weight:600;
  z-index:99997; display:flex; align-items:center; gap:8px;
  box-shadow:0 8px 24px rgba(27,46,108,.3); animation:toastIn .3s ease;
  max-width:320px; text-align:center;
}
@keyframes toastIn { from{opacity:0;transform:translateX(-50%) translateY(20px)} to{opacity:1;transform:translateX(-50%) translateY(0)} }
@keyframes bmgFadeIn { from{opacity:0;transform:scale(.92)} to{opacity:1;transform:scale(1)} }
`;
    document.head.appendChild(s);
  }

  /* ── Slot element upgrader ───────────────────────────────────────────── */
  const SLOT_LABELS = {
    available : { label:'Available',   icon:'🟢' },
    confirmed : { label:'Booked',      icon:'🔴' },
    booked    : { label:'Booked',      icon:'🔴' },
    past      : { label:'Time Passed', icon:'⏳' },
    locked    : { label:'Processing…', icon:'🔒' },
    pending   : { label:'Processing…', icon:'🔒' },
    closed    : { label:'Closed',      icon:'🚫' },
    selected  : { label:'Selected',    icon:'✅' },
  };

  function _upgradeSlotEl(el) {
    if (el.dataset.bmgUpgraded) return;
    el.dataset.bmgUpgraded = '1';

    const slotAttr = el.dataset.slot || '';
    const raw = (el.textContent || '').trim();
    const timeDisplay = slotAttr
      ? slotAttr.replace('-', ' – ')
      : raw.replace(/Available|Booked|Confirmed|Past|Locked|Processing|Closed|Selected|Time Passed/gi, '').trim();

    let status = 'available';
    for (const c of ['confirmed','booked','past','locked','pending','closed','selected']) {
      if (el.classList.contains(c)) { status = c; break; }
    }

    const info = SLOT_LABELS[status] || SLOT_LABELS.available;
    el.innerHTML = `
      <span class="slot-icon">${info.icon}</span>
      <span class="slot-time-text">${timeDisplay || '—'}</span>
      <span class="slot-status-tag">${info.label}</span>`;
  }

  function _upgradeContainer(c) {
    if (!c) return;
    if (!c.classList.contains('slots-grid')) c.classList.add('slots-grid');
    c.querySelectorAll('.time-slot').forEach(_upgradeSlotEl);

    // Legend
    let leg = c.previousElementSibling;
    if (!leg || !leg.classList.contains('slot-legend')) {
      leg = document.createElement('div');
      leg.className = 'slot-legend';
      leg.innerHTML = `
        <div class="slot-legend-item"><div class="slot-legend-dot available"></div>Available</div>
        <div class="slot-legend-item"><div class="slot-legend-dot booked"></div>Booked</div>
        <div class="slot-legend-item"><div class="slot-legend-dot past"></div>Time Passed</div>
        <div class="slot-legend-item"><div class="slot-legend-dot locked"></div>Processing</div>`;
      c.parentNode.insertBefore(leg, c);
    }
  }

  /* ── Real-time slot loading (replaces loadSlots) ─────────────────────── */
  let _slotUnsub = null;

  async function _loadSlotsRealtime(groundId, date) {
    const container = document.getElementById('time-slots');
    if (!container) return;

    container.innerHTML = `
      <div style="padding:2rem;text-align:center;">
        <div class="loader-spinner"></div>
        <p style="margin-top:1rem;color:var(--gray-500);">Loading slots…</p>
      </div>`;

    if (_slotUnsub) { try { _slotUnsub(); } catch (_) {} _slotUnsub = null; }

    const db = window.db;
    if (!db) return;

    // Release expired locks first
    _releaseExpiredLocks(groundId, date);

    _slotUnsub = db.collection('slots')
      .where('groundId', '==', groundId)
      .where('date', '==', date)
      .onSnapshot(snapshot => {
        const statusMap = {}, lockMap = {};
        snapshot.forEach(doc => {
          const s = doc.data();
          const k = `${s.startTime}-${s.endTime}`;
          statusMap[k] = s.status;
          lockMap[k] = s.lockedBy || s.lockOrderId || null;
        });
        _renderSlotGrid(container, statusMap, lockMap, date);
      }, () => {
        if (typeof window._origLoadSlots === 'function') window._origLoadSlots(groundId, date);
      });
  }

  function _renderSlotGrid(container, statusMap, lockMap, date) {
    const cu = window.currentUser;
    const now = new Date();
    const curMin = now.getHours() * 60 + now.getMinutes();
    const isToday = date === now.toISOString().split('T')[0];
    const sel = window.selectedSlot || null;
    const myOrd = sessionStorage.getItem('bmg_currentOrderId') || '';

    let html = '';
    for (let h = 0; h < 24; h++) {
      const s = `${String(h).padStart(2,'0')}:00`;
      const e = `${String(h+1).padStart(2,'0')}:00`;
      const key = `${s}-${e}`;
      const raw = statusMap[key] || 'available';
      const lk = lockMap[key];
      const mine = lk && cu && (lk === cu.uid || lk === myOrd);

      let cls = 'available', dis = false, icon = '🟢', label = 'Available';

      if (isToday && h * 60 <= curMin) {
        cls = 'past'; dis = true; icon = '⏳'; label = 'Time Passed';
      } else {
        switch (raw) {
          case 'booked': case 'confirmed':
            cls = 'confirmed'; dis = true; icon = '🔴'; label = 'Booked';
            break;
          case 'locked': case 'pending':
            if (mine) { cls = 'selected'; icon = '✅'; label = 'Your Slot'; }
            else { cls = 'locked'; dis = true; icon = '🔒'; label = 'Processing…'; }
            break;
          case 'closed': case 'blocked':
            cls = 'closed'; dis = true; icon = '🚫'; label = 'Closed';
            break;
        }
      }

      html += `
        <div class="time-slot ${cls}${sel === key ? ' selected' : ''}"
          data-slot="${key}" data-status="${dis ? 'disabled' : raw}"
          ${!dis ? 'data-available="true"' : ''}
          style="${cls === 'confirmed' || cls === 'booked' ? 'border-color:#ef4444!important;background:linear-gradient(135deg,#fef2f2,#fee2e2)!important;color:#991b1b!important;' : ''}">
          <span class="slot-icon">${icon}</span>
          <span class="slot-time-text">${key.replace('-', ' – ')}</span>
          <span class="slot-status-tag">${label}</span>
        </div>`;
    }

    container.innerHTML = html;
    if (!container.classList.contains('slots-grid')) container.classList.add('slots-grid');

    // Wire click handlers
    container.querySelectorAll('.time-slot[data-available="true"]').forEach(el => {
      el.addEventListener('click', () => {
        if (typeof window.selectSlot === 'function') window.selectSlot(el.dataset.slot);
      });
    });

    // Add legend
    let leg = container.previousElementSibling;
    if (!leg || !leg.classList.contains('slot-legend')) {
      leg = document.createElement('div');
      leg.className = 'slot-legend';
      leg.innerHTML = `
        <div class="slot-legend-item"><div class="slot-legend-dot available"></div>Available</div>
        <div class="slot-legend-item"><div class="slot-legend-dot booked"></div>Booked</div>
        <div class="slot-legend-item"><div class="slot-legend-dot past"></div>Time Passed</div>
        <div class="slot-legend-item"><div class="slot-legend-dot locked"></div>Processing</div>`;
      container.parentNode.insertBefore(leg, container);
    }
  }

  async function _releaseExpiredLocks(groundId, date) {
    const db = window.db;
    if (!db) return;
    try {
      const snap = await db.collection('slots')
        .where('groundId','==',groundId).where('date','==',date)
        .where('status','in',['locked','pending']).get();
      const now = Date.now(), batch = db.batch();
      let changed = false;
      snap.forEach(doc => {
        const d = doc.data();
        const exp = d.lockExpiresAtMs || d.lockExpiresAt?.toMillis?.() || 0;
        if (exp && now > exp) {
          batch.update(doc.ref, {
            status:'available', lockOrderId:null, lockExpiresAt:null,
            lockExpiresAtMs:null, lockedBy:null,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
          });
          changed = true;
        }
      });
      if (changed) await batch.commit();
    } catch (_) {}
  }

  // ── Mark slot BOOKED immediately after payment ────────────────────────
  function _markSlotBookedInUI(groundId, date, slotTime) {
    document.querySelectorAll('.slot-item, .time-slot, [data-slot-time]').forEach(el => {
      const elSlot   = el.dataset.slotTime || el.dataset.slot || '';
      const elGround = el.dataset.groundId || el.closest('[data-ground-id]')?.dataset?.groundId || '';
      const elDate   = el.dataset.date || el.closest('[data-date]')?.dataset?.date || '';

      const slotMatch  = elSlot && slotTime && slotTime.includes(elSlot.split('-')[0]);
      const groundMatch= !elGround || elGround === groundId;
      const dateMatch  = !elDate   || elDate   === date;

      if (slotMatch && groundMatch && dateMatch) {
        el.classList.remove('available','selected','locked','pending');
        el.classList.add('booked','confirmed');
        el.style.cssText += 'background:linear-gradient(135deg,#fef2f2,#fee2e2)!important;border-color:#ef4444!important;color:#991b1b!important;pointer-events:none!important;cursor:not-allowed!important;';

        const icon  = el.querySelector('.slot-icon');
        const badge = el.querySelector('.slot-status-tag');
        if (icon)  icon.textContent  = '🔴';
        if (badge) { badge.textContent = 'Booked'; badge.style.cssText = 'background:rgba(239,68,68,.18)!important;color:#dc2626!important;font-weight:800!important;'; }

        delete el.dataset.available;
        el.dataset.status = 'disabled';
        el.dataset.bmgUpgraded = ''; // allow re-upgrade
        console.log('[BMG] Slot marked BOOKED instantly:', elSlot);
      }
    });

    // Also update Firestore (fire-and-forget)
    const db = window.db;
    if (!db || !groundId || !date || !slotTime) return;
    const startTime = slotTime.split('-')[0].trim();
    db.collection('slots')
      .where('groundId','==',groundId).where('date','==',date).where('startTime','==',startTime).limit(1)
      .get().then(snap => {
        if (!snap.empty) snap.docs[0].ref.update({
          status:'booked', updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
      }).catch(() => {});

    // Also lock it as booked (creates doc if missing)
    const [start, end] = slotTime.split('-').map(t => t.trim());
    db.collection('slots')
      .where('groundId','==',groundId).where('date','==',date).where('startTime','==',start).limit(1)
      .get().then(snap => {
        const FV = firebase.firestore.FieldValue;
        const payload = {
          groundId, date, startTime:start, endTime:end||'',
          status:'booked', lockedBy:null, lockExpiresAt:null, lockOrderId:null, lockExpiresAtMs:null,
          bookedAt:FV.serverTimestamp(), updatedAt:FV.serverTimestamp(),
        };
        if (snap.empty) {
          db.collection('slots').add(payload);
        } else {
          snap.docs[0].ref.update(payload);
        }
      }).catch(() => {});
  }

  // ── Instant slot release ─────────────────────────────────────────────
  async function _releaseMySlot() {
    const db = window.db; if (!db) return;
    let li = null;
    try { li = JSON.parse(sessionStorage.getItem('slotLock') || 'null'); } catch (_) {}
    if (!li?.orderId) return;
    try {
      const snap = await db.collection('slots').where('lockOrderId','==',li.orderId).limit(1).get();
      if (!snap.empty) await snap.docs[0].ref.update({
        status:'available', lockOrderId:null, lockExpiresAt:null, lockExpiresAtMs:null, lockedBy:null,
        updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
      });
      await db.collection('pending_payments').doc(li.orderId).delete().catch(() => {});
    } catch (_) {}
    sessionStorage.removeItem('slotLock');
  }

  // ── Payment events → slot updates ────────────────────────────────────
  window.addEventListener('bmg:paymentConfirmed', async (e) => {
    const { paymentType, result, orderId } = e.detail || {};
    if (paymentType !== 'booking') return;
    const d = result || {};
    if (d.groundId && d.date && d.slotTime) {
      setTimeout(() => _markSlotBookedInUI(d.groundId, d.date, d.slotTime), 200);
      setTimeout(() => _markSlotBookedInUI(d.groundId, d.date, d.slotTime), 1000);
    }
    sessionStorage.removeItem('slotLock');
  });

  window.addEventListener('bmg:paymentCancelled', () => _releaseMySlot());
  window.addEventListener('bmg:paymentFailed',    () => _releaseMySlot());

  document.addEventListener('visibilitychange', () => { if (!document.hidden) _checkStaleSlotLock(); });
  window.addEventListener('pageshow', e => { if (e.persisted) _checkStaleSlotLock(); });

  async function _checkStaleSlotLock() {
    const lock = (() => { try { return JSON.parse(sessionStorage.getItem('slotLock') || 'null'); } catch { return null; } })();
    if (!lock) return;
    const overlay = document.querySelector('#payment-processing-overlay,.payment-processing-overlay');
    if (overlay && overlay.offsetParent !== null) return;
    if (Date.now() - (lock.lockedAt || 0) > 10 * 60 * 1000) await _releaseMySlot();
  }

  // Release on page navigation away from booking
  window.addEventListener('DOMContentLoaded', () => {
    const stale = sessionStorage.getItem('slotLock_needsRelease');
    if (stale && window.db) {
      sessionStorage.removeItem('slotLock_needsRelease');
      window.db.collection('slots').where('lockOrderId','==',stale).limit(1).get()
        .then(s => { if (!s.empty) s.docs[0].ref.update({ status:'available', lockOrderId:null, lockExpiresAt:null, lockExpiresAtMs:null, lockedBy:null, updatedAt:firebase.firestore.FieldValue.serverTimestamp() }); }).catch(() => {});
      window.db.collection('pending_payments').doc(stale).delete().catch(() => {});
    }
  });

  window.addEventListener('beforeunload', () => {
    try { const li = JSON.parse(sessionStorage.getItem('slotLock') || 'null'); if (li?.orderId) sessionStorage.setItem('slotLock_needsRelease', li.orderId); } catch (_) {}
  });

  // ── Boot ─────────────────────────────────────────────────────────────
  window._bmgOnReady(function () {
    _injectSlotCSS();

    // Replace loadSlots with realtime version
    window._bmgWaitFor('loadSlots', () => {
      window._origLoadSlots = window.loadSlots;
      window.loadSlots = _loadSlotsRealtime;
      console.log('✅ [BMG] loadSlots → real-time Firestore');
    });

    // Upgrade any existing slot elements
    document.querySelectorAll('#slots-container,.slots-container,[id*="slot"]').forEach(el => {
      if (el.querySelector('.time-slot')) _upgradeContainer(el);
    });

    // Watch for dynamically added slots
    new MutationObserver(muts => {
      for (const m of muts) for (const n of m.addedNodes) {
        if (n.nodeType !== 1) continue;
        if (n.classList?.contains('time-slot')) _upgradeSlotEl(n);
        const inner = n.querySelectorAll?.('.time-slot');
        if (inner?.length) {
          inner.forEach(_upgradeSlotEl);
          const c = n.classList?.contains('slots-container') ? n : n.querySelector('#slots-container,.slots-container');
          if (c) _upgradeContainer(c);
        }
      }
    }).observe(document.body, { childList: true, subtree: true });
  });

  window._bmgWatchSlotsRealtime = _loadSlotsRealtime;
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §5  TOURNAMENT FEATURES
 *     QR entry pass, spots counter, My Bookings tab, owner verification
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  /* ── Generate QR data URL ────────────────────────────────────────────── */
  async function _genQR(payload, size) {
    const str = typeof payload === 'string' ? payload : JSON.stringify(payload);
    if (typeof QRCode !== 'undefined' && typeof QRCode.toDataURL === 'function') {
      try { return await QRCode.toDataURL(str, { width: size || 200, margin: 2, errorCorrectionLevel: 'M' }); } catch (_) {}
    }
    if (typeof window.QRCode === 'function') {
      return new Promise(resolve => {
        const tmp = document.createElement('div');
        tmp.style.cssText = 'position:absolute;left:-9999px;top:-9999px;';
        document.body.appendChild(tmp);
        try { new window.QRCode(tmp, { text: str, width: size||200, height: size||200 }); } catch (_) {}
        setTimeout(() => {
          const img = tmp.querySelector('img');
          const url = img?.src || '';
          try { document.body.removeChild(tmp); } catch (_) {}
          resolve(url);
        }, 400);
      });
    }
    return '';
  }

  /* ── Tournament entry pass modal ─────────────────────────────────────── */
  async function showTournamentEntryPass(entryId) {
    const db = window.db; if (!db) return;
    window._bmgShowLoading('Generating tournament pass...');
    try {
      let entryDoc = await db.collection('tournament_entries').doc(entryId).get();
      if (!entryDoc.exists) {
        const snap = await db.collection('tournament_entries').where('orderId','==',entryId).limit(1).get();
        if (!snap.empty) entryDoc = snap.docs[0];
      }
      if (!entryDoc || !entryDoc.exists) { window._bmgToast('Entry not found','error'); return; }
      const entry = entryDoc.data ? entryDoc.data() : entryDoc;
      const id    = entryDoc.id || entryId;

      const qrPayload = {
        appId:'BookMyGame', type:'tournament',
        entryId:id, tournamentId:entry.tournamentId||'',
        tournamentName:entry.tournamentName||'', userId:entry.userId||'',
        userName:entry.userName||'', teamName:entry.teamName||'',
        sport:entry.sport||'', date:entry.date||'', venue:entry.venue||'',
        amount:entry.amount||entry.entryFee||0,
        validFrom:new Date(Date.now()-24*60*60*1000).toISOString(),
        validTo  :new Date(Date.now()+30*24*60*60*1000).toISOString(),
      };
      const qrDataUrl = await _genQR(qrPayload, 180);
      document.getElementById('bmg-tourn-pass-modal')?.remove();

      const modal = document.createElement('div');
      modal.id = 'bmg-tourn-pass-modal';
      modal.style.cssText='position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,.75);display:flex;align-items:center;justify-content:center;padding:20px;';
      modal.innerHTML=`
        <div style="background:#fff;border-radius:20px;max-width:400px;width:100%;padding:28px 24px;position:relative;box-shadow:0 20px 60px rgba(0,0,0,.4);max-height:90vh;overflow-y:auto;">
          <button onclick="document.getElementById('bmg-tourn-pass-modal').remove();"
            style="position:absolute;top:14px;right:14px;border:none;background:none;font-size:22px;cursor:pointer;color:#666;">✕</button>
          <div style="text-align:center;margin-bottom:20px;">
            <div style="width:56px;height:56px;border-radius:50%;background:linear-gradient(135deg,#10b981,#059669);display:inline-flex;align-items:center;justify-content:center;margin-bottom:10px;">
              <i class="fas fa-trophy" style="color:#fff;font-size:22px;"></i>
            </div>
            <h3 style="margin:0;font-size:20px;font-weight:700;color:#111;">Tournament Entry Pass</h3>
          </div>
          <div style="background:#f9fafb;border-radius:14px;padding:16px;margin-bottom:16px;">
            <div style="display:flex;justify-content:space-between;margin-bottom:8px;"><span style="color:#6b7280;font-size:13px;">Tournament</span><span style="font-weight:600;font-size:13px;">${window._esc(entry.tournamentName||'N/A')}</span></div>
            <div style="display:flex;justify-content:space-between;margin-bottom:8px;"><span style="color:#6b7280;font-size:13px;">Player</span><span style="font-weight:600;font-size:13px;">${window._esc(entry.userName||'N/A')}</span></div>
            ${entry.teamName?`<div style="display:flex;justify-content:space-between;margin-bottom:8px;"><span style="color:#6b7280;font-size:13px;">Team</span><span style="font-weight:600;font-size:13px;">${window._esc(entry.teamName)}</span></div>`:''}
            ${entry.sport?`<div style="display:flex;justify-content:space-between;margin-bottom:8px;"><span style="color:#6b7280;font-size:13px;">Sport</span><span style="font-weight:600;font-size:13px;">${window._esc(entry.sport)}</span></div>`:''}
            ${entry.date?`<div style="display:flex;justify-content:space-between;margin-bottom:8px;"><span style="color:#6b7280;font-size:13px;">Date</span><span style="font-weight:600;font-size:13px;">${entry.date}</span></div>`:''}
            ${entry.venue?`<div style="display:flex;justify-content:space-between;margin-bottom:8px;"><span style="color:#6b7280;font-size:13px;">Venue</span><span style="font-weight:600;font-size:13px;">${window._esc(entry.venue)}</span></div>`:''}
            <div style="display:flex;justify-content:space-between;"><span style="color:#6b7280;font-size:13px;">Entry ID</span><span style="font-family:monospace;font-size:11px;">${id.slice(0,16)}…</span></div>
          </div>
          <div style="text-align:center;padding:20px;background:#fff;border:2px dashed #e5e7eb;border-radius:14px;margin-bottom:16px;">
            ${qrDataUrl?`<img src="${qrDataUrl}" alt="QR" style="width:180px;height:180px;">`:`<div style="width:180px;height:180px;display:inline-flex;align-items:center;justify-content:center;background:#f3f4f6;border-radius:8px;color:#9ca3af;font-size:13px;">QR unavailable</div>`}
            <p style="margin:10px 0 0;font-size:12px;color:#6b7280;">Show this QR to the organiser for entry</p>
          </div>
          <div style="text-align:center;padding:10px;background:#ecfdf5;border-radius:10px;">
            <span style="color:#059669;font-weight:700;font-size:14px;"><i class="fas fa-check-circle"></i> Registration Confirmed</span>
          </div>
        </div>`;
      document.body.appendChild(modal);
      modal.addEventListener('click', e => { if (e.target===modal) modal.remove(); });
    } catch (err) {
      console.error('[BMG] showTournamentEntryPass error:', err);
      window._bmgToast('Error loading entry pass','error');
    } finally { window._bmgHideLoading(); }
  }
  window.showTournamentEntryPass = showTournamentEntryPass;

  /* ══════════════════════════════════════════════════════════════════
   *  BMG PROFESSIONAL VERIFICATION RESULT MODAL
   *  Shows a full-screen modal with all booking/tournament details
   *  after owner scans a QR code. Replaces the tiny inline resultDiv.
   * ══════════════════════════════════════════════════════════════════*/

  /* ── Inject verification modal styles once ──────────────────────── */
  (function _injectVerifStyles() {
    if (document.getElementById('bmg-verif-styles')) return;
    const s = document.createElement('style');
    s.id = 'bmg-verif-styles';
    s.textContent = `
/* ── Scanner modal: centred on screen ── */
#professional-qr-modal {
  align-items: center !important;
  justify-content: center !important;
}
.qr-scanner-container {
  border-radius: 24px !important;
  max-width: 440px !important;
  width: calc(100% - 32px) !important;
  margin: 0 auto !important;
}
/* ── Verification result overlay ── */
#bmg-verif-overlay {
  position: fixed;
  inset: 0;
  z-index: 99999;
  background: rgba(0,0,0,0.72);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
  animation: bmgVerifFadeIn .25s ease;
}
@keyframes bmgVerifFadeIn { from{opacity:0} to{opacity:1} }
#bmg-verif-card {
  background: #fff;
  border-radius: 24px;
  overflow: hidden;
  max-width: 400px;
  width: 100%;
  box-shadow: 0 32px 80px rgba(0,0,0,0.45);
  max-height: 90vh;
  overflow-y: auto;
  animation: bmgVerifSlideUp .32s cubic-bezier(.34,1.56,.64,1);
}
@keyframes bmgVerifSlideUp { from{transform:translateY(32px) scale(.96);opacity:0} to{transform:translateY(0) scale(1);opacity:1} }
.bmg-vr-header {
  padding: 28px 24px 20px;
  text-align: center;
  position: relative;
}
.bmg-vr-header.success { background: linear-gradient(135deg, #065f46, #10b981); }
.bmg-vr-header.error   { background: linear-gradient(135deg, #7f1d1d, #ef4444); }
.bmg-vr-header.warning { background: linear-gradient(135deg, #78350f, #f59e0b); }
.bmg-vr-status-ring {
  width: 80px; height: 80px;
  border-radius: 50%;
  background: rgba(255,255,255,0.18);
  border: 3px solid rgba(255,255,255,0.35);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 14px;
  font-size: 36px;
}
.bmg-vr-header h2 {
  margin: 0 0 4px;
  font-size: 20px;
  font-weight: 800;
  color: #fff;
  letter-spacing: -0.3px;
}
.bmg-vr-header p {
  margin: 0;
  font-size: 13px;
  color: rgba(255,255,255,0.78);
}
.bmg-vr-timestamp {
  position: absolute;
  top: 14px; right: 14px;
  font-size: 10px;
  color: rgba(255,255,255,0.6);
  font-weight: 600;
  background: rgba(255,255,255,0.12);
  padding: 3px 8px;
  border-radius: 20px;
}
.bmg-vr-body {
  padding: 20px;
  background: #f8fafc;
}
.bmg-vr-section {
  background: #fff;
  border-radius: 16px;
  overflow: hidden;
  margin-bottom: 12px;
  border: 1.5px solid #e8edf8;
}
.bmg-vr-section-title {
  font-size: 10px;
  font-weight: 800;
  letter-spacing: 0.8px;
  text-transform: uppercase;
  color: #6b7280;
  padding: 10px 16px 6px;
  border-bottom: 1px solid #f0f4ff;
  background: #fafbff;
}
.bmg-vr-row {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 11px 16px;
  border-bottom: 1px solid #f0f4ff;
}
.bmg-vr-row:last-child { border-bottom: none; }
.bmg-vr-row-icon {
  width: 32px; height: 32px;
  border-radius: 10px;
  background: #eff6ff;
  display: flex; align-items: center; justify-content: center;
  color: #2563eb;
  font-size: 14px;
  flex-shrink: 0;
}
.bmg-vr-row-label {
  font-size: 10px;
  font-weight: 700;
  color: #9ca3af;
  text-transform: uppercase;
  letter-spacing: 0.4px;
  display: block;
  margin-bottom: 2px;
}
.bmg-vr-row-value {
  font-size: 14px;
  font-weight: 700;
  color: #111827;
  display: block;
  word-break: break-all;
}
.bmg-vr-row-value.mono {
  font-family: 'Courier New', monospace;
  font-size: 12px;
  color: #374151;
}
.bmg-vr-status-chip {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 4px 12px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 700;
}
.bmg-vr-status-chip.confirmed { background:#dcfce7; color:#15803d; }
.bmg-vr-status-chip.cancelled { background:#fee2e2; color:#dc2626; }
.bmg-vr-status-chip.pending   { background:#fef3c7; color:#92400e; }
.bmg-vr-amount-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  background: linear-gradient(135deg,#eff6ff,#dbeafe);
  color: #1d4ed8;
  padding: 5px 14px;
  border-radius: 20px;
  font-size: 16px;
  font-weight: 800;
  border: 1px solid #bfdbfe;
}
.bmg-vr-footer {
  padding: 16px 20px calc(16px + env(safe-area-inset-bottom, 0px));
  background: #fff;
  display: flex;
  gap: 10px;
  border-top: 1px solid #f0f4ff;
}
.bmg-vr-btn {
  flex: 1;
  padding: 13px;
  border: none;
  border-radius: 14px;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
  transition: all .2s;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
}
.bmg-vr-btn.primary {
  background: linear-gradient(135deg, #1b2e6c, #2563eb);
  color: #fff;
  box-shadow: 0 4px 14px rgba(37,99,235,0.3);
}
.bmg-vr-btn.secondary {
  background: #f3f4f6;
  color: #374151;
}
.bmg-vr-btn:hover { filter: brightness(1.05); transform: translateY(-1px); }
/* Hide old inline result div */
#professional-qr-result { display: none !important; }
    `;
    document.head.appendChild(s);
  })();

  /* ── Show the full verification result modal ─────────────────────── */
  function _bmgShowVerifModal(opts) {
    /* opts: { success, title, subtitle, sections[], scannerType } */
    const existing = document.getElementById('bmg-verif-overlay');
    if (existing) existing.remove();

    const now = new Date().toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true });
    const headerCls = opts.success ? 'success' : (opts.warning ? 'warning' : 'error');
    const emoji     = opts.success ? '✅' : (opts.warning ? '⚠️' : '❌');

    let sectionsHTML = '';
    (opts.sections || []).forEach(sec => {
      const rowsHTML = (sec.rows || []).map(row => {
        const iconBg = row.iconBg || '#eff6ff';
        const iconColor = row.iconColor || '#2563eb';
        let valueHTML = '';
        if (row.chip) {
          valueHTML = `<span class="bmg-vr-status-chip ${row.chipCls||''}">${row.chipIcon||''} ${window._esc(row.value)}</span>`;
        } else if (row.amount) {
          valueHTML = `<span class="bmg-vr-amount-badge"><i class="fas fa-rupee-sign" style="font-size:12px;"></i>${window._esc(row.value)}</span>`;
        } else {
          valueHTML = `<span class="bmg-vr-row-value ${row.mono?'mono':''}">${window._esc(String(row.value||'—'))}</span>`;
        }
        return `<div class="bmg-vr-row">
          <div class="bmg-vr-row-icon" style="background:${iconBg};color:${iconColor}"><i class="fas ${row.icon||'fa-info'}"></i></div>
          <div style="flex:1;min-width:0;">
            <span class="bmg-vr-row-label">${window._esc(row.label)}</span>
            ${valueHTML}
          </div>
        </div>`;
      }).join('');
      sectionsHTML += `<div class="bmg-vr-section">
        ${sec.title ? `<div class="bmg-vr-section-title">${window._esc(sec.title)}</div>` : ''}
        ${rowsHTML}
      </div>`;
    });

    const overlay = document.createElement('div');
    overlay.id = 'bmg-verif-overlay';
    overlay.innerHTML = `
      <div id="bmg-verif-card">
        <div class="bmg-vr-header ${headerCls}">
          <div class="bmg-vr-timestamp">🕐 ${now}</div>
          <div class="bmg-vr-status-ring">${emoji}</div>
          <h2>${window._esc(opts.title)}</h2>
          <p>${window._esc(opts.subtitle||'')}</p>
        </div>
        <div class="bmg-vr-body">${sectionsHTML}</div>
        <div class="bmg-vr-footer">
          <button class="bmg-vr-btn secondary" id="bmg-vr-close">
            <i class="fas fa-times"></i> Close
          </button>
          <button class="bmg-vr-btn primary" id="bmg-vr-scan-again">
            <i class="fas fa-qrcode"></i> Scan Next
          </button>
        </div>
      </div>`;
    document.body.appendChild(overlay);

    overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
    document.getElementById('bmg-vr-close').addEventListener('click', () => overlay.remove());
    document.getElementById('bmg-vr-scan-again').addEventListener('click', () => {
      overlay.remove();
      /* Resume scanner */
      const scannerModal = document.getElementById('professional-qr-modal');
      if (scannerModal && scannerModal.style.display !== 'none') return; /* already open */
      if (typeof window.showProfessionalQRScanner === 'function') window.showProfessionalQRScanner();
    });
  }

  /* Install as global for paymentService.js to call too */
  window.showVerificationResult = function(success, booking, errorMsg) {
    if (success && booking) {
      const statusChipCls = (booking.bookingStatus||'confirmed').toLowerCase() === 'confirmed' ? 'confirmed' : 'pending';
      _bmgShowVerifModal({
        success: true,
        title: '✅ Booking Verified!',
        subtitle: 'Entry granted — booking is confirmed & valid',
        sections: [
          {
            title: 'Booking Status',
            rows: [
              {
                label: 'Status',
                icon: 'fa-check-circle',
                iconBg: '#dcfce7', iconColor: '#15803d',
                chip: true, chipCls: 'confirmed',
                chipIcon: '✅',
                value: 'Confirmed & Paid',
              },
              {
                label: 'Booking ID',
                icon: 'fa-hashtag',
                iconBg: '#eff6ff', iconColor: '#2563eb',
                mono: true,
                value: (booking.bookingId || booking.id || 'N/A').slice(-12),
              },
            ],
          },
          {
            title: 'Player Details',
            rows: [
              { label:'Player Name', icon:'fa-user', value: booking.userName || booking.userPhone || 'N/A' },
              { label:'Phone', icon:'fa-phone', value: booking.userPhone || booking.phone || '—' },
              { label:'Email', icon:'fa-envelope', value: booking.userEmail || booking.email || '—' },
            ],
          },
          {
            title: 'Booking Details',
            rows: [
              { label:'Ground', icon:'fa-map-marker-alt', iconBg:'#fff7ed', iconColor:'#c2410c', value: booking.groundName || '—' },
              { label:'Venue', icon:'fa-building', value: booking.venueName || '—' },
              { label:'Date', icon:'fa-calendar-alt', iconBg:'#f0fdf4', iconColor:'#15803d', value: booking.date || '—' },
              { label:'Time Slot', icon:'fa-clock', iconBg:'#f0fdf4', iconColor:'#15803d', value: booking.slotTime || '—' },
              { label:'Sport', icon:'fa-running', value: booking.sportType || booking.sport || '—' },
              { label:'Amount Paid', icon:'fa-rupee-sign', iconBg:'#eff6ff', iconColor:'#1d4ed8', amount:true, value: String(booking.amount || 0) },
            ],
          },
        ],
      });
    } else {
      _bmgShowVerifModal({
        success: false,
        title: 'Verification Failed',
        subtitle: errorMsg || 'This QR code could not be verified',
        sections: [
          {
            title: 'Error Details',
            rows: [
              {
                label: 'Reason',
                icon: 'fa-exclamation-circle',
                iconBg: '#fee2e2', iconColor: '#dc2626',
                value: errorMsg || 'Unknown error',
              },
            ],
          },
        ],
      });
    }
  };

  /* ── Tournament QR verification (owner scanner) ──────────────────────── */
  async function verifyTournamentQR(qrObject) {
    const db = window.db, cu = window.currentUser;
    try {
      if (qrObject.appId !== 'BookMyGame') throw new Error('Not a BookMyGame QR code');
      const now = new Date();
      if (new Date(qrObject.validTo) < now) throw new Error('QR code has expired');
      const entryDoc = await db.collection('tournament_entries').doc(qrObject.entryId).get();
      if (!entryDoc.exists) throw new Error('Tournament entry not found');
      const entry = entryDoc.data();
      if (entry.status === 'cancelled') throw new Error('Registration was cancelled');
      if (entry.tournamentEntryStatus === 'used') throw new Error('Entry already scanned');
      await entryDoc.ref.update({
        tournamentEntryStatus:'used', scannedAt:firebase.firestore.FieldValue.serverTimestamp(),
        scannedBy:cu?.uid||'unknown', scannedByName:cu?.name||cu?.ownerName||'Owner',
      });
      _bmgShowVerifModal({
        success: true,
        title: 'Tournament Entry Verified!',
        subtitle: window._esc(entry.tournamentName || 'Tournament'),
        sections: [
          {
            title: 'Entry Status',
            rows: [
              { label:'Status', icon:'fa-check-circle', iconBg:'#dcfce7', iconColor:'#15803d', chip:true, chipCls:'confirmed', chipIcon:'✅', value:'Entry Granted' },
            ],
          },
          {
            title: 'Participant Details',
            rows: [
              { label:'Player Name', icon:'fa-user', value: entry.userName || '—' },
              ...(entry.teamName ? [{ label:'Team', icon:'fa-users', value: entry.teamName }] : []),
              { label:'Sport', icon:'fa-running', value: entry.sport || '—' },
              { label:'Tournament', icon:'fa-trophy', iconBg:'#fef3c7', iconColor:'#92400e', value: entry.tournamentName || '—' },
              ...(entry.date ? [{ label:'Event Date', icon:'fa-calendar-alt', value: entry.date }] : []),
              ...(entry.venue ? [{ label:'Venue', icon:'fa-map-marker-alt', value: entry.venue }] : []),
              { label:'Entry ID', icon:'fa-hashtag', mono:true, value: (qrObject.entryId||'').slice(-12) },
            ],
          },
        ],
      });
      window._bmgToast('✅ Tournament entry verified!','success');
    } catch (err) {
      _bmgShowVerifModal({
        success: false,
        title: 'Verification Failed',
        subtitle: 'Tournament entry could not be verified',
        sections: [{
          title: 'Error Details',
          rows: [{ label:'Reason', icon:'fa-exclamation-circle', iconBg:'#fee2e2', iconColor:'#dc2626', value: err.message }],
        }],
      });
      window._bmgToast('❌ ' + err.message, 'error');
    }
  }
  window.verifyTournamentQR = verifyTournamentQR;

  /* ── Patch processVerifiedQRCode to handle tournament + compact format ── */
  window._bmgWaitFor('processVerifiedQRCode', () => {
    const _orig = window.processVerifiedQRCode;
    window.processVerifiedQRCode = async function (qrData) {
      if (!qrData) return;
      qrData = qrData.trim();
      if (qrData.startsWith('BMG|')) { await _verifyBookingQRCompact(qrData.slice(4)); return; }
      let parsed = null;
      try { parsed = JSON.parse(qrData); } catch (_) { return _orig(qrData); }
      if (parsed?.type === 'tournament') { return verifyTournamentQR(parsed); }
      if (parsed?.bid || parsed?.bookingId) { await _verifyBookingQRCompact(parsed.bid || parsed.bookingId); return; }
      return _orig(qrData);
    };
  });

  async function _verifyBookingQRCompact(bookingId) {
    const db = window.db, cu = window.currentUser;
    if (!db || !cu) { window._bmgToast('Please log in to verify','error'); return; }
    try {
      const directDoc = await db.collection('bookings').doc(bookingId).get().catch(() => null);
      let booking = null;
      if (directDoc?.exists) { booking = { id:directDoc.id, ...directDoc.data() }; }
      else {
        const snap = await db.collection('bookings').where('bookingId','==',bookingId).limit(1).get();
        if (!snap.empty) booking = { id:snap.docs[0].id, ...snap.docs[0].data() };
      }
      if (!booking) {
        _bmgShowVerifModal({
          success: false,
          title: 'Booking Not Found',
          subtitle: 'No booking matched this QR code',
          sections: [{ title:'Error Details', rows:[{ label:'Booking ID Scanned', icon:'fa-hashtag', mono:true, value: bookingId.slice(-16) }] }],
        });
        window._bmgToast('Booking not found','error');
        return;
      }
      const confirmed = booking.bookingStatus==='confirmed'||booking.status==='confirmed'||booking.paymentStatus==='PAID';
      if (confirmed) {
        window.showVerificationResult(true, booking);
        window._bmgToast('✅ Valid booking confirmed','success');
      } else {
        const statusLabel = booking.bookingStatus || booking.status || 'unknown';
        const chipCls = statusLabel === 'cancelled' ? 'cancelled' : 'pending';
        _bmgShowVerifModal({
          success: false,
          title: 'Booking Not Confirmed',
          subtitle: 'This booking has not been paid or confirmed',
          sections: [
            {
              title: 'Booking Status',
              rows: [
                { label:'Current Status', icon:'fa-exclamation-circle', iconBg:'#fee2e2', iconColor:'#dc2626', chip:true, chipCls, chipIcon:'⚠️', value: statusLabel },
                { label:'Booking ID', icon:'fa-hashtag', mono:true, value: (booking.bookingId||booking.id||'').slice(-12) },
                { label:'Player', icon:'fa-user', value: booking.userName || '—' },
                { label:'Ground', icon:'fa-map-marker-alt', value: booking.groundName || '—' },
                { label:'Date', icon:'fa-calendar-alt', value: booking.date || '—' },
                { label:'Slot', icon:'fa-clock', value: booking.slotTime || '—' },
              ],
            },
          ],
        });
        window._bmgToast('❌ Booking not confirmed','error');
      }
    } catch (err) {
      _bmgShowVerifModal({
        success: false,
        title: 'Verification Error',
        subtitle: 'An error occurred while verifying',
        sections: [{ title:'Error Details', rows:[{ label:'Details', icon:'fa-exclamation-triangle', iconBg:'#fee2e2', iconColor:'#dc2626', value: err.message }] }],
      });
      window._bmgToast('Verify error: '+err.message,'error');
    }
  }

  /* ── _showTournamentJoinedSuccess with QR ────────────────────────────── */
  window._showTournamentJoinedSuccess = function (data) {
    // Generate QR and show success modal
    _genQR({
      appId:'BookMyGame', type:'tournament_entry',
      tournamentId:data.tournamentId||'', registrationId:data.registrationId||data.orderId||'',
      userId:data.userId||window.currentUser?.uid||'', teamName:data.teamName||'',
      tournamentName:data.tournamentName||'', sport:data.sport||'',
    }, 200).then(qrDataUrl => {
      const modal = document.createElement('div');
      modal.style.cssText='position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.75);display:flex;align-items:center;justify-content:center;padding:20px;';
      modal.innerHTML=`
        <div style="background:#fff;border-radius:20px;max-width:380px;width:100%;padding:28px;text-align:center;box-shadow:0 24px 64px rgba(0,0,0,.35);max-height:90vh;overflow-y:auto;">
          <div style="width:72px;height:72px;background:linear-gradient(135deg,#10b981,#059669);border-radius:50%;display:inline-flex;align-items:center;justify-content:center;margin-bottom:16px;">
            <i class="fas fa-trophy" style="color:#fff;font-size:30px;"></i>
          </div>
          <h2 style="margin:0 0 6px;font-size:22px;font-weight:800;color:#111;">Registration Confirmed! 🎉</h2>
          <p style="color:#6b7280;font-size:14px;margin:0 0 20px;">${window._esc(data.tournamentName||'Tournament')}</p>
          ${qrDataUrl?`<div style="background:#f9fafb;border-radius:16px;padding:16px;margin-bottom:16px;"><img src="${qrDataUrl}" style="width:180px;height:180px;"><p style="font-size:12px;color:#6b7280;margin:8px 0 0;">Show to organiser at the event</p></div>`:''}
          <button onclick="this.closest('[style*=fixed]').remove();if(typeof window.loadMyTournaments==='function')window.loadMyTournaments();"
            style="width:100%;padding:14px;background:linear-gradient(135deg,#10b981,#059669);color:#fff;border:none;border-radius:14px;font-size:15px;font-weight:700;cursor:pointer;">
            View My Tournaments
          </button>
        </div>`;
      document.body.appendChild(modal);
      modal.addEventListener('click', e => { if (e.target===modal) modal.remove(); });
    });
  };

  /* ── loadUserBookings: add pool bookings section + tournament entries ──── */
  window._bmgWaitFor('loadUserBookings', () => {
    const _orig = window.loadUserBookings;
    window.loadUserBookings = async function (status) {
      // Run original (ground bookings only — pool section removed from app.js)
      await _orig(status);
      const cu = window.currentUser;
      const db = window.db;
      if (!cu || !db) return;
      const container = document.getElementById('user-bookings-list');
      if (!container) return;
      const today = new Date().toISOString().split('T')[0];

      // ── SECTION 1: Swimming Pool Bookings ────────────────────────────────
      // Only add if bmg_swimming_pool_fix.js hasn't already added them
      // (it sets _poolPatched on loadUserBookings — but since we're the last
      //  patcher, we handle pool cards here and skip in swimming pool fix)
      try {
        let poolSnap = await db.collection('pool_bookings')
          .where('userId','==',cu.uid)
          .orderBy('createdAt','desc')
          .get()
          .catch(() => db.collection('pool_bookings').where('userId','==',cu.uid).get());

        if (!poolSnap.empty) {
          let poolDocs = poolSnap.docs.map(d => ({ _docId: d.id, ...d.data() }));

          // Filter by tab
          poolDocs = poolDocs.filter(b => {
            const bDate = b.date || '';
            const bStat = b.bookingStatus || b.status || '';
            if (status === 'upcoming') return bDate >= today && bStat === 'confirmed';
            if (status === 'past')     return bDate < today || bStat === 'completed' || bStat === 'cancelled';
            return false;
          });

          if (poolDocs.length > 0) {
            const empty = container.querySelector('.empty-state');
            if (empty) empty.remove();

            // Section header
            const poolSection = document.createElement('div');
            poolSection.id = 'bmg-pool-bookings-section';
            poolSection.style.cssText = 'margin-top:20px;';
            poolSection.innerHTML =
              '<div style="display:flex;align-items:center;gap:10px;padding:10px 0 12px;border-top:2px solid #e0f2fe;">' +
                '<div style="width:34px;height:34px;background:linear-gradient(135deg,#0369a1,#0ea5e9);border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:18px;">🏊</div>' +
                '<h4 style="margin:0;font-size:15px;font-weight:800;color:#0c4a6e;letter-spacing:-.2px;">Swimming Pool Bookings</h4>' +
                '<span style="margin-left:auto;background:#e0f2fe;color:#0369a1;font-size:11px;font-weight:700;padding:3px 9px;border-radius:20px;">' + poolDocs.length + '</span>' +
              '</div>';

            poolDocs.forEach(b => {
              const bStatus     = b.bookingStatus || b.status || 'pending';
              const isConfirmed = bStatus === 'confirmed';
              const isCancelled = bStatus === 'cancelled';
              const isCompleted = bStatus === 'completed';
              const memberCount = b.memberCount || b.currentMembers || 1;
              const perPer      = b.pricePerMember || (b.amount && memberCount > 1 ? Math.round(b.amount / memberCount) : b.amount) || 0;
              const total       = b.amount || (perPer * memberCount);
              const bookingId   = b.bookingId || b.orderId || b._docId;
              const isPassed    = b.date < today && !isCompleted;

              let dateLabel = b.date || 'Date TBD';
              try { dateLabel = new Date(b.date).toLocaleDateString('en-IN',{weekday:'long',day:'numeric',month:'long',year:'numeric'}); } catch(_){}

              const scMap = {
                confirmed: { icon:'fa-check-circle', label:'Confirmed', cls:'confirmed' },
                cancelled:  { icon:'fa-times-circle', label:'Cancelled', cls:'cancelled' },
                completed:  { icon:'fa-flag-checkered', label:'Completed', cls:'completed' },
              };
              const sc = scMap[bStatus] || { icon:'fa-hourglass-half', label:'Pending', cls:'pending' };

              const card = document.createElement('div');
              card.className = 'bk-card bk-card--' + sc.cls;
              card.style.cssText = 'border-top:3px solid #0ea5e9;margin-bottom:12px;';
              card.innerHTML =
                '<div class="bk-card__header">' +
                  '<div class="bk-card__sport-badge">🏊</div>' +
                  '<div class="bk-card__title-block">' +
                    '<div class="bk-card__ground-name">' + window._esc(b.poolName || 'Swimming Pool') + '</div>' +
                    '<div class="bk-card__venue-name" style="color:#0ea5e9;font-weight:700;">' +
                      '<i class="fas fa-users" style="font-size:9px"></i> ' + memberCount + ' member' + (memberCount > 1 ? 's' : '') +
                    '</div>' +
                  '</div>' +
                  '<div class="bk-card__status-pill bk-card__status-pill--' + sc.cls + '">' +
                    '<i class="fas ' + sc.icon + '"></i> ' + sc.label +
                  '</div>' +
                '</div>' +
                '<div class="bk-card__divider"></div>' +
                '<div class="bk-card__details">' +
                  '<div class="bk-card__detail-row"><span class="bk-card__detail-icon"><i class="fas fa-calendar-alt"></i></span><span class="bk-card__detail-text">' + window._esc(dateLabel) + '</span></div>' +
                  '<div class="bk-card__detail-row"><span class="bk-card__detail-icon"><i class="fas fa-clock"></i></span><span class="bk-card__detail-text">' + window._esc(b.slotTime || 'Time TBD') + '</span></div>' +
                  '<div class="bk-card__detail-row"><span class="bk-card__detail-icon"><i class="fas fa-map-marker-alt"></i></span><span class="bk-card__detail-text">' + window._esc(b.poolAddress || 'Address not available') + '</span></div>' +
                  '<div class="bk-card__detail-row"><span class="bk-card__detail-icon"><i class="fas fa-rupee-sign"></i></span><span class="bk-card__detail-text bk-card__amount">₹' + total + (memberCount > 1 ? ' <span style="font-size:11px;color:#64748b">(₹' + perPer + '/person)</span>' : '') + '</span></div>' +
                '</div>' +
                (isPassed ? '<div class="bk-card__alert"><i class="fas fa-exclamation-circle"></i> Booking date has passed</div>' : '') +
                '<div class="bk-card__footer">' +
                  '<span class="bk-card__booking-id"><i class="fas fa-hashtag"></i> ' + window._esc(bookingId.slice(-10)) + '</span>' +
                  (isConfirmed
                    ? '<button class="bk-card__pass-btn bmg-pool-btn" data-bid="' + window._esc(bookingId) + '" style="background:linear-gradient(135deg,#0369a1,#0ea5e9);border:none;"><i class="fas fa-swimmer"></i> Pool Pass</button>'
                    : '') +
                  (isCompleted ? '<span class="bk-card__done-chip"><i class="fas fa-check-double"></i> Completed</span>' : '') +
                  (isCancelled ? '<span class="bk-card__cancel-chip"><i class="fas fa-ban"></i> Cancelled</span>' : '') +
                '</div>';

              poolSection.appendChild(card);
            });

            container.appendChild(poolSection);

            // Wire pool pass buttons
            // bmg_pool_entry_fix.js (loads last) defines showPoolEntryPass(docId, bookingData)
            // bmg_swimming_pool_fix.js defines showPoolEntryPass(bookingId) — 1 arg
            // We fetch the doc first so both signatures are satisfied.
            container.querySelectorAll('.bmg-pool-btn').forEach(btn => {
              btn.addEventListener('click', async () => {
                const bid = btn.getAttribute('data-bid');
                if (typeof window.showPoolEntryPass !== 'function') {
                  window.showEntryPass(bid); return;
                }
                // Fetch the pool booking doc so we can pass data to the 2-arg version
                try {
                  const db = window.db;
                  let docId = bid, bookingData = null;
                  // Try by doc ID first
                  const byId = await db.collection('pool_bookings').doc(bid).get().catch(() => null);
                  if (byId && byId.exists) {
                    docId = byId.id; bookingData = byId.data();
                  } else {
                    // Try by bookingId field
                    const snap = await db.collection('pool_bookings').where('bookingId','==',bid).limit(1).get().catch(() => null);
                    if (snap && !snap.empty) { docId = snap.docs[0].id; bookingData = snap.docs[0].data(); }
                  }
                  if (bookingData) {
                    window.showPoolEntryPass(docId, bookingData);
                  } else {
                    // No data found — try single-arg call (bmg_swimming_pool_fix version)
                    window.showPoolEntryPass(bid);
                  }
                } catch(e) {
                  window.showPoolEntryPass(bid); // fallback to 1-arg
                }
              });
            });
          }
        }
      } catch (_) {}

      // ── SECTION 2: Tournament Registrations ─────────────────────────────
      try {
        const snap = await db.collection('tournament_entries').where('userId','==',cu.uid).orderBy('createdAt','desc').get();
        if (snap.empty) return;
        let entries = snap.docs.map(d => ({ id:d.id, ...d.data() }));
        if (status === 'upcoming') entries = entries.filter(e => (!e.date||e.date>=today) && e.status!=='cancelled');
        else if (status === 'past') entries = entries.filter(e => (e.date&&e.date<today) || e.status==='cancelled');
        if (!entries.length) return;

        const empty = container.querySelector('.empty-state');
        if (empty) empty.remove();

        const tournSection = document.createElement('div');
        tournSection.style.cssText = 'margin-top:20px;';
        tournSection.innerHTML =
          '<div style="display:flex;align-items:center;gap:10px;padding:10px 0 12px;border-top:2px solid #d1fae5;">' +
            '<div style="width:34px;height:34px;background:linear-gradient(135deg,#059669,#10b981);border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:18px;">🏆</div>' +
            '<h4 style="margin:0;font-size:15px;font-weight:800;color:#064e3b;letter-spacing:-.2px;">Tournament Registrations</h4>' +
            '<span style="margin-left:auto;background:#d1fae5;color:#059669;font-size:11px;font-weight:700;padding:3px 9px;border-radius:20px;">' + entries.length + '</span>' +
          '</div>';

        const html = entries.map(e => `
          <div class="booking-card status-${e.status||'confirmed'}" style="border-left:4px solid #10b981;margin-bottom:14px;">
            <div class="booking-status">🏆 Tournament — ${e.status==='confirmed'?'Confirmed':e.status==='cancelled'?'Cancelled':'Registered'}</div>
            <h4 style="margin:10px 0 6px;font-weight:700;">${window._esc(e.tournamentName||'Tournament')}</h4>
            ${e.sport?`<p><i class="fas fa-futbol"></i> ${window._esc(e.sport)}</p>`:''}
            ${e.teamName?`<p><i class="fas fa-users"></i> Team: ${window._esc(e.teamName)}</p>`:''}
            ${e.date?`<p><i class="fas fa-calendar"></i> ${e.date}</p>`:''}
            ${e.venue?`<p><i class="fas fa-map-pin"></i> ${window._esc(e.venue)}</p>`:''}
            <p><i class="fas fa-rupee-sign"></i> Entry Fee: ₹${e.amount||e.entryFee||0}</p>
            ${e.status!=='cancelled'?`<button class="auth-btn" onclick="showTournamentEntryPass('${e.id}')" style="margin-top:10px;background:linear-gradient(135deg,#10b981,#059669);"><i class="fas fa-qrcode"></i> View Tournament Pass</button>`:''}
          </div>`).join('');

        tournSection.innerHTML += html;
        container.appendChild(tournSection);
      } catch (_) {}
    };
  });

  /* ── Tournament spots real-time counter ──────────────────────────────── */
  let _tournamentListener = null;
  function _startTournamentListener(tournamentId) {
    if (_tournamentListener) { _tournamentListener(); _tournamentListener = null; }
    const db = window.db;
    if (!db || !tournamentId) return;
    _tournamentListener = db.collection('tournaments').doc(tournamentId).onSnapshot(doc => {
      if (!doc.exists) return;
      const t = doc.data();
      const spots = Math.max(0, (t.maxTeams||0) - (t.registeredTeams||t.currentTeams||0));
      document.querySelectorAll('[data-tournament-spots],.tournament-spots-value,.spots-left-value').forEach(el => { el.textContent = spots; });
      document.querySelectorAll('.info-value').forEach(el => {
        if (/\d+\s*\/\s*\d+/.test(el.textContent.trim())) el.textContent = `${spots}/${t.maxTeams||0}`;
      });
      const btn = document.getElementById('tournament-register-btn') || document.querySelector('.tournament-register-btn');
      if (btn && spots <= 0) { btn.disabled=true; btn.textContent='Tournament Full'; }
    });
  }

  ['showTournamentDetail','loadTournamentDetail','openTournamentDetail'].forEach(fn => {
    window._bmgWaitFor(fn, () => {
      const _orig = window[fn];
      window[fn] = function (tournament, ...args) {
        const id = typeof tournament==='string' ? tournament : (tournament?.id||tournament?.tournamentId);
        if (id) {
          window._currentTournamentId = id;
          const page = document.getElementById('tournament-detail-page');
          if (page) page.dataset.tournamentId = id;
          _startTournamentListener(id);
        }
        return _orig(tournament, ...args);
      };
    });
  });

  window.addEventListener('bmg:paymentConfirmed', e => {
    const { paymentType } = e.detail||{};
    if (paymentType==='tournament') {
      const id = window._currentTournamentId;
      if (id) _startTournamentListener(id);
    }
  });
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §6  ENTRY PASS (booking QR)
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  function _buildQRPayload(booking) {
    return 'BMG|' + (booking.bookingId || booking.id || '');
  }

  window._bmgWaitFor('showEntryPass', () => {
    const _orig = window.showEntryPass;

    window.showEntryPass = async function (bookingId) {
      if (!bookingId) { window._bmgToast('Booking ID missing','error'); return; }
      window._bmgShowLoading('Generating pass…');
      try {
        const db = window.db;

        // ── STEP 1: Check pool_bookings first (3 strategies) ──────────────
        let poolBooking = null;
        // 1a. By document ID
        try { const d = await db.collection('pool_bookings').doc(bookingId).get(); if (d.exists) poolBooking = { _docId: d.id, ...d.data() }; } catch(_){}
        // 1b. By bookingId field
        if (!poolBooking) { try { const s = await db.collection('pool_bookings').where('bookingId','==',bookingId).limit(1).get(); if (!s.empty) poolBooking = { _docId: s.docs[0].id, ...s.docs[0].data() }; } catch(_){} }
        // 1c. By orderId field
        if (!poolBooking) { try { const s = await db.collection('pool_bookings').where('orderId','==',bookingId).limit(1).get(); if (!s.empty) poolBooking = { _docId: s.docs[0].id, ...s.docs[0].data() }; } catch(_){} }

        // ── STEP 2: If pool booking found → delegate to showPoolEntryPass ──
        if (poolBooking) {
          window._bmgHideLoading();
          if (typeof window.showPoolEntryPass === 'function') {
            // bmg_pool_entry_fix.js (loads last) needs (docId, bookingData) — 2 args
            // bmg_swimming_pool_fix.js needs (bookingId) — 1 arg
            // Pass both: if 2-arg version, it uses docId+data; if 1-arg, extra arg is ignored
            window.showPoolEntryPass(poolBooking._docId || bookingId, poolBooking);
          } else {
            window._bmgToast('Pool pass generator not loaded yet — please try again','warning');
          }
          return;
        }

        // ── STEP 3: Ground booking lookup ─────────────────────────────────
        let booking = null;
        const dd = await db.collection('bookings').doc(bookingId).get().catch(() => null);
        if (dd?.exists) { booking = { id:dd.id, ...dd.data() }; }
        else {
          const snap = await db.collection('bookings').where('bookingId','==',bookingId).limit(1).get();
          if (!snap.empty) booking = { id:snap.docs[0].id, ...snap.docs[0].data() };
        }
        if (!booking) { window._bmgToast('Booking not found','error'); window._bmgHideLoading(); return; }

        const isConfirmed = booking.bookingStatus==='confirmed'||booking.status==='confirmed'||booking.paymentStatus==='PAID';
        if (!isConfirmed) { window._bmgToast('Entry pass available only for confirmed bookings','warning'); window._bmgHideLoading(); return; }

        const qrPayload = _buildQRPayload(booking);
        let qrDataUrl = '';
        if (typeof QRCode !== 'undefined' && typeof QRCode.toDataURL === 'function') {
          try { qrDataUrl = await QRCode.toDataURL(qrPayload, { width:220, margin:2, errorCorrectionLevel:'M' }); } catch (_) {}
        }
        if (!qrDataUrl && typeof window.QRCode === 'function') {
          qrDataUrl = await new Promise(resolve => {
            const tmp = document.createElement('div'); tmp.style.cssText='position:absolute;left:-9999px;';
            document.body.appendChild(tmp);
            try { new window.QRCode(tmp, { text:qrPayload, width:220, height:220 }); } catch (_) {}
            setTimeout(() => { const img=tmp.querySelector('img'); const url=img?.src||''; try{document.body.removeChild(tmp);}catch(_){} resolve(url); }, 400);
          });
        }

        const passHtml = `
          <div style="background:linear-gradient(135deg,#1a1a2e,#16213e,#0f3460);color:#fff;border-radius:24px;padding:28px 22px;max-width:360px;margin:16px auto;box-shadow:0 20px 60px rgba(0,0,0,.4);">
            <div style="text-align:center;margin-bottom:18px;">
              <div style="font-size:2rem;margin-bottom:4px;">🏟️</div>
              <h2 style="margin:0;font-size:1.3rem;font-weight:800;letter-spacing:1px;">ENTRY PASS</h2>
              <p style="margin:4px 0 0;font-size:.75rem;opacity:.7;letter-spacing:2px;">BookMyGame · SpörtoBook</p>
            </div>
            <div style="background:rgba(255,255,255,.08);border-radius:16px;padding:16px;margin-bottom:18px;">
              <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;font-size:.82rem;">
                <div><span style="opacity:.6;">Booking ID</span><br><strong style="font-size:.78rem;">${window._esc(booking.bookingId||booking.id)}</strong></div>
                <div><span style="opacity:.6;">Name</span><br><strong>${window._esc(booking.userName||'')}</strong></div>
                <div><span style="opacity:.6;">Ground</span><br><strong>${window._esc(booking.groundName||'')}</strong></div>
                <div><span style="opacity:.6;">Date</span><br><strong>${booking.date||''}</strong></div>
                <div><span style="opacity:.6;">Time</span><br><strong>${booking.slotTime||''}</strong></div>
                <div><span style="opacity:.6;">Amount</span><br><strong>₹${booking.amount||0}</strong></div>
              </div>
              ${booking.groundAddress||booking.venueAddress?`<div style="margin-top:10px;font-size:.78rem;opacity:.8;">📍 ${window._esc(booking.groundAddress||booking.venueAddress)}</div>`:''}
            </div>
            <div style="background:#fff;border-radius:16px;padding:14px;text-align:center;margin-bottom:14px;">
              ${qrDataUrl?`<img src="${qrDataUrl}" alt="QR" style="width:200px;height:200px;">`:`<p style="color:#999;font-size:12px;">QR: ${window._esc(booking.bookingId||booking.id)}</p>`}
              <p style="color:#374151;font-size:.7rem;margin:8px 0 0;">Scan to verify at venue</p>
            </div>
            <div style="background:rgba(34,197,94,.15);border:1px solid rgba(34,197,94,.3);border-radius:10px;padding:10px 14px;font-size:.75rem;text-align:center;color:#86efac;">
              <i class="fas fa-check-circle"></i> CONFIRMED &nbsp;|&nbsp; <i class="fas fa-clock"></i> Valid: 15 min before to 1 hr after slot
            </div>
          </div>
          <button id="entry-pass-home" style="display:block;width:calc(100% - 32px);margin:12px auto 24px;padding:14px;background:linear-gradient(135deg,#6366f1,#4f46e5);color:#fff;border:none;border-radius:14px;font-size:1rem;font-weight:700;cursor:pointer;">
            <i class="fas fa-home"></i> Back to Home
          </button>`;

        const container = document.getElementById('entry-pass-content');
        if (container) {
          container.innerHTML = passHtml;
          container.querySelector('#entry-pass-home')?.addEventListener('click', () => {
            if (typeof window.goHome==='function') window.goHome();
            else if (typeof window.showPage==='function') window.showPage('home-page');
          });
        }

        window._bmgHideLoading();
        if (typeof window.showPage==='function') window.showPage('entry-pass-page');

      } catch (err) {
        console.error('[BMG] showEntryPass error:', err);
        window._bmgHideLoading();
        window._bmgToast(err.message||'Error generating pass','error');
      }
    };
  });

  window.showEntryPassFromConfirmation = function () {
    const bid = window._lastConfirmedBookingId
      || document.querySelector('[data-booking-id]')?.dataset?.bookingId
      || document.querySelector('#booking-id-display,.booking-id')?.textContent?.trim()
      || sessionStorage.getItem('lastBookingId');
    if (!bid || bid.length < 3) { window._bmgToast('Booking ID not found. Please check My Bookings.','warning'); return; }
    window.showEntryPass(bid);
  };
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §7  OWNER — canAddGround fix + registrationVerified auto-write
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  function _patchCanAddGround() {
    window.canAddGround = async function () {
      const cu = window.currentUser;
      if (!cu || cu.role !== 'owner') { window._bmgToast('Please login as owner','error'); return false; }
      try {
        const db = window.db;
        const snap = await db.collection('owners').doc(cu.uid).get();
        if (!snap.exists) { window._bmgToast('Owner data not found. Please contact support.','error'); return false; }
        const owner = snap.data();

        if (owner.status && owner.status !== 'active') { window._bmgToast('Your account is blocked. Please contact support.','error'); return false; }
        if (owner.documentVerified === false) { window._bmgToast('Address verification pending. Please upload your electricity bill.','warning'); return false; }

        const isPaid = owner.registrationPaid===true || owner.isActive===true || owner.paymentDone===true;

        if (!isPaid) {
          let isRequired = true, payAmt = 5;
          try {
            const cfg = await db.collection('system_config').doc('owner_registration').get();
            if (cfg.exists) { isRequired=cfg.data().paymentRequired===true; payAmt=cfg.data().paymentAmount||5; }
          } catch (_) {}
          if (isRequired) {
            window._bmgToast(`Please complete registration (₹${payAmt}) to add grounds.`, 'warning');
            return false;
          } else {
            await db.collection('owners').doc(cu.uid).update({
              registrationPaid:true, registrationVerified:true, isActive:true, paymentDone:true,
              updatedAt:firebase.firestore.FieldValue.serverTimestamp(),
            });
          }
        } else {
          if (!owner.registrationVerified) {
            try {
              await db.collection('owners').doc(cu.uid).update({
                registrationVerified:true, isActive:true, paymentDone:true,
                updatedAt:firebase.firestore.FieldValue.serverTimestamp(),
              });
            } catch (_) {}
            cu.registrationVerified = true; cu.isActive = true; cu.paymentDone = true;
          }
        }

        const validTypes = ['venue_owner','plot_owner','VENUE_OWNER','PLOT_OWNER'];
        if (!validTypes.includes(owner.ownerType)) { window._bmgToast('Your account type does not allow adding grounds.','error'); return false; }

        console.log('✅ [BMG] canAddGround: all checks passed');
        return true;
      } catch (err) {
        console.error('[BMG] canAddGround error:', err);
        window._bmgToast('Error checking permissions. Please try again.','error');
        return false;
      }
    };
    console.log('✅ [BMG] canAddGround patched — registrationVerified auto-fix active');
  }

  // Patch after app.js defines it
  window._bmgWaitFor('canAddGround', _patchCanAddGround);
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §8  OWNER & CEO EARNINGS
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  const _db = () => window.db;
  const _cu = () => window.currentUser;
  const _fmt = v => window._bmgFmt(v);

  /* ── Full admin/CEO owner earnings loader ────────────────────────────── */
  async function loadAdminOwnerEarningsFull(container) {
    if (!container) return;
    const db = _db(), cu = _cu();
    if (!db || !cu) { container.innerHTML='<p style="text-align:center;padding:32px;color:#9ca3af;">Please log in.</p>'; return; }

    container.innerHTML=`<div style="text-align:center;padding:40px;"><div class="loader-spinner" style="margin:0 auto 12px;"></div><p style="color:#6b7280;font-size:14px;">Loading owner earnings…</p></div>`;

    try {
      let bookSnap, tournSnap;
      try { bookSnap=await db.collection('bookings').where('bookingStatus','==','confirmed').orderBy('createdAt','desc').get(); }
      catch (_) { bookSnap=await db.collection('bookings').where('bookingStatus','==','confirmed').get(); }
      try { tournSnap=await db.collection('tournament_entries').where('status','==','confirmed').get(); }
      catch (_) { tournSnap={docs:[]}; }
      const [opSnap,prSnap]=await Promise.all([
        db.collection('owner_payments').where('status','==','paid').get().catch(()=>({docs:[]})),
        db.collection('payout_requests').where('status','==','paid').get().catch(()=>({docs:[]})),
      ]);

      const ownerData={};
      const ensure=(oid,name='')=>{ if(!ownerData[oid]) ownerData[oid]={ownerId:oid,ownerName:name,bookingEarnings:0,tournamentEarnings:0,transfersPaid:0,bookingCount:0,tournCount:0,transferCount:0}; if(name&&!ownerData[oid].ownerName) ownerData[oid].ownerName=name; };

      bookSnap.docs.forEach(doc=>{ const b=doc.data(); const oid=b.ownerId||''; if(!oid)return; ensure(oid,b.ownerName||''); const full=Number(b.amount||b.totalAmount||0); const plat=Number(b.commission||b.platformFee||Math.round(full*0.10)); const share=Number(b.ownerAmount||(full-plat)); if(share<=0)return; ownerData[oid].bookingEarnings+=share; ownerData[oid].bookingCount++; });
      tournSnap.docs.forEach(doc=>{ const e=doc.data(); const oid=e.ownerId||e.tournamentOwnerId||''; if(!oid)return; ensure(oid,''); const fee=Number(e.amount||e.entryFee||0); const share=Number(e.ownerAmount||(fee-Math.round(fee*0.20))); if(share<=0)return; ownerData[oid].tournamentEarnings+=share; ownerData[oid].tournCount++; });

      const seen=new Set();
      opSnap.docs.forEach(doc=>{ seen.add(doc.id); const t=doc.data(); const oid=t.ownerId||''; if(!oid)return; ensure(oid,t.ownerName||''); ownerData[oid].transfersPaid+=Number(t.amount||0); ownerData[oid].transferCount++; });
      prSnap.docs.forEach(doc=>{ if(seen.has(doc.id))return; const t=doc.data(); const oid=t.ownerId||''; if(!oid)return; ensure(oid,t.ownerName||''); ownerData[oid].transfersPaid+=Number(t.amount||0); ownerData[oid].transferCount++; });

      const unknownIds=Object.keys(ownerData).filter(id=>!ownerData[id].ownerName);
      for(let i=0;i<unknownIds.length;i+=10){
        try{
          const snap=await db.collection('owners').where(firebase.firestore.FieldPath.documentId(),'in',unknownIds.slice(i,i+10)).get();
          snap.docs.forEach(d=>{ if(ownerData[d.id]) ownerData[d.id].ownerName=d.data().name||d.data().ownerName||'Unknown'; });
        }catch(_){}
      }

      const owners=Object.values(ownerData).sort((a,b)=>(b.bookingEarnings+b.tournamentEarnings)-(a.bookingEarnings+a.tournamentEarnings));
      const totalPlat=owners.reduce((s,o)=>s+(o.bookingCount>0?(o.bookingEarnings/0.9)*0.1:0)+(o.tournCount>0?(o.tournamentEarnings/0.8)*0.2:0),0);
      const totalOwed=owners.reduce((s,o)=>s+Math.max(0,(o.bookingEarnings+o.tournamentEarnings)-o.transfersPaid),0);

      container.innerHTML=`
        <style>.bae-banner{background:linear-gradient(135deg,#1e3a5f,#1e40af);color:#fff;border-radius:16px;padding:18px 20px;margin-bottom:20px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px;}.bae-banner-stat{text-align:center;}.bae-banner-val{font-size:26px;font-weight:800;}.bae-banner-lbl{font-size:11px;opacity:.75;text-transform:uppercase;letter-spacing:.5px;}.bae-card{background:#fff;border-radius:16px;padding:18px;margin-bottom:14px;box-shadow:0 2px 12px rgba(0,0,0,.07);border-left:4px solid #10b981;}.bae-card-owed{border-left-color:#f59e0b;}.bae-row{display:flex;justify-content:space-between;align-items:center;padding:7px 0;border-bottom:1px solid #f3f4f6;font-size:13px;color:#374151;}.bae-owed-box{background:#fef3c7;border-radius:10px;padding:10px 12px;margin-top:10px;display:flex;justify-content:space-between;align-items:center;}.bae-transfer-btn{background:linear-gradient(135deg,#10b981,#059669);color:#fff;border:none;padding:10px 18px;border-radius:12px;font-size:13px;font-weight:700;cursor:pointer;margin-top:12px;display:flex;align-items:center;gap:6px;}.bae-paid-badge{background:#d1fae5;color:#065f46;font-size:12px;font-weight:700;padding:4px 12px;border-radius:20px;}</style>
        <div class="bae-banner">
          <div class="bae-banner-stat"><div class="bae-banner-val">${_fmt(totalPlat)}</div><div class="bae-banner-lbl">Platform Revenue</div></div>
          <div class="bae-banner-stat"><div class="bae-banner-val">${owners.length}</div><div class="bae-banner-lbl">Active Owners</div></div>
          <div class="bae-banner-stat" style="background:rgba(255,255,255,.1);border-radius:12px;padding:10px 16px;"><div class="bae-banner-val" style="color:#fbbf24;">${_fmt(totalOwed)}</div><div class="bae-banner-lbl">Total Still Owed</div></div>
          <button class="bae-refresh-btn" onclick="window._bmgRefreshAdminEarnings()" style="background:#f3f4f6;border:none;padding:8px 16px;border-radius:10px;font-size:13px;cursor:pointer;font-weight:600;"><i class="fas fa-sync-alt"></i> Refresh</button>
        </div>
        <div id="bae-owners-list">
          ${owners.length===0?'<p style="text-align:center;color:#9ca3af;padding:32px;">No earnings data yet.</p>':owners.map(o=>{
            const total=o.bookingEarnings+o.tournamentEarnings,netOwed=Math.max(0,total-o.transfersPaid),isOwed=netOwed>0;
            return `<div class="bae-card ${isOwed?'bae-card-owed':''}" id="bae-card-${o.ownerId}">
              <h4 style="font-size:15px;font-weight:700;color:#111;margin:0 0 12px;display:flex;justify-content:space-between;align-items:center;">
                <span>${window._esc(o.ownerName||'Unknown')} <span style="font-size:10px;color:#9ca3af;">${o.ownerId.slice(0,8)}…</span></span>
                ${!isOwed?'<span class="bae-paid-badge"><i class="fas fa-check-circle"></i> Fully Paid</span>':''}
              </h4>
              <div class="bae-row"><span>Ground Bookings (90% share)</span><span style="color:#3b82f6;font-weight:700;">${_fmt(o.bookingEarnings)}</span></div>
              <div class="bae-row"><span>Tournament Earnings (80% share)</span><span style="color:#8b5cf6;font-weight:700;">${_fmt(o.tournamentEarnings)}</span></div>
              <div class="bae-row"><span>Total Earned</span><span style="font-weight:800;">${_fmt(total)}</span></div>
              <div class="bae-row"><span>Already Transferred (${o.transferCount})</span><span style="color:#10b981;font-weight:700;">-${_fmt(o.transfersPaid)}</span></div>
              <div class="bae-owed-box"><strong>Amount Still Owed</strong><span style="font-size:18px;font-weight:800;color:${isOwed?'#d97706':'#10b981'};">${_fmt(netOwed)}</span></div>
              ${isOwed?`<button class="bae-transfer-btn" onclick="window.bmgAdminTransferPaymentV3('${o.ownerId}','${window._esc(o.ownerName||'').replace(/'/g,"\\'")}',${Math.round(netOwed)})"><i class="fas fa-paper-plane"></i> Mark Payment Done (${_fmt(netOwed)})</button>`:''}
            </div>`;
          }).join('')}
        </div>`;
    } catch (err) {
      console.error('[BMG] loadAdminOwnerEarningsFull error:', err);
      container.innerHTML=`<p style="text-align:center;color:#ef4444;padding:32px;">${err.code==='permission-denied'?'Check Firestore rules for admin role.':window._esc(err.message)}</p>`;
    }
  }

  window.loadAdminOwnerEarnings = loadAdminOwnerEarningsFull;
  window._bmgRefreshAdminEarnings = function () {
    ['admin-dashboard-content','ceo-dashboard-content'].forEach(id => {
      const el = document.getElementById(id);
      if (el) { el.innerHTML='<div class="loading-spinner"><div class="loader-spinner"></div></div>'; loadAdminOwnerEarningsFull(el); }
    });
  };

  /* ── bmgAdminTransferPaymentV3 ───────────────────────────────────────── */
  window.bmgAdminTransferPaymentV3 = async function (ownerId, ownerName, suggestedAmount) {
    const db = _db(), cu = _cu();
    if (!db || !cu) { window._bmgToast('Not logged in','error'); return; }
    document.getElementById('bmg-transfer-modal-v3')?.remove();
    const modal = document.createElement('div');
    modal.id = 'bmg-transfer-modal-v3';
    modal.style.cssText='position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.6);display:flex;align-items:center;justify-content:center;padding:16px;';
    modal.innerHTML=`
      <div style="background:#fff;border-radius:20px;max-width:380px;width:100%;padding:28px 24px;box-shadow:0 24px 64px rgba(0,0,0,.25);">
        <h3 style="margin:0 0 4px;font-size:18px;font-weight:800;"><i class="fas fa-paper-plane" style="color:#10b981;margin-right:8px;"></i>Mark Payment Done</h3>
        <p style="font-size:13px;color:#6b7280;margin:0 0 20px;">to <strong>${window._esc(ownerName||ownerId)}</strong></p>
        <label style="font-size:12px;font-weight:600;color:#374151;display:block;margin-bottom:6px;">Amount Transferred (₹)</label>
        <input id="bmg-tv3-amount" type="number" value="${suggestedAmount||0}" min="1" style="width:100%;padding:12px;border:2px solid #e5e7eb;border-radius:12px;font-size:18px;font-weight:700;margin-bottom:14px;box-sizing:border-box;">
        <label style="font-size:12px;font-weight:600;color:#374151;display:block;margin-bottom:6px;">Payment Method</label>
        <select id="bmg-tv3-method" style="width:100%;padding:10px;border:2px solid #e5e7eb;border-radius:12px;font-size:14px;margin-bottom:14px;box-sizing:border-box;">
          <option>UPI</option><option>NEFT</option><option>IMPS</option><option>Cash</option><option>Other</option>
        </select>
        <label style="font-size:12px;font-weight:600;color:#374151;display:block;margin-bottom:6px;">Transaction ID / Note (optional)</label>
        <input id="bmg-tv3-note" type="text" placeholder="e.g. UTR1234567890" style="width:100%;padding:10px;border:2px solid #e5e7eb;border-radius:12px;font-size:13px;margin-bottom:20px;box-sizing:border-box;">
        <div style="display:flex;gap:10px;">
          <button id="bmg-tv3-cancel" style="flex:1;padding:12px;background:#f3f4f6;color:#374151;border:none;border-radius:12px;font-size:14px;font-weight:600;cursor:pointer;">Cancel</button>
          <button id="bmg-tv3-confirm" style="flex:2;padding:12px;background:linear-gradient(135deg,#10b981,#059669);color:#fff;border:none;border-radius:12px;font-size:14px;font-weight:700;cursor:pointer;"><i class="fas fa-check"></i> Confirm Payment Done</button>
        </div>
        <p id="bmg-tv3-error" style="color:#ef4444;font-size:12px;text-align:center;margin-top:10px;display:none;"></p>
      </div>`;
    document.body.appendChild(modal);
    modal.addEventListener('click', e => { if (e.target===modal) modal.remove(); });
    document.getElementById('bmg-tv3-cancel').addEventListener('click', () => modal.remove());
    document.getElementById('bmg-tv3-confirm').addEventListener('click', async () => {
      const amt=Number(document.getElementById('bmg-tv3-amount')?.value||0);
      const method=document.getElementById('bmg-tv3-method')?.value||'UPI';
      const note=document.getElementById('bmg-tv3-note')?.value||'';
      const errEl=document.getElementById('bmg-tv3-error');
      const btn=document.getElementById('bmg-tv3-confirm');
      if (!amt||amt<=0) { errEl.textContent='Please enter a valid amount.'; errEl.style.display='block'; return; }
      btn.disabled=true; btn.innerHTML='<i class="fas fa-spinner fa-spin"></i> Processing…'; errEl.style.display='none';
      try {
        const now=firebase.firestore.FieldValue.serverTimestamp();
        const transferDoc={ ownerId, ownerName:ownerName||'', amount:amt, method, note, description:note||`Payment via ${method}`, status:'paid', paidAt:now, paidBy:cu.uid, paidByName:cu.name||cu.email||'Admin', paidByEmail:cu.email||'', createdAt:now, updatedAt:now };
        const opRef=await db.collection('owner_payments').add(transferDoc);
        await db.collection('payout_requests').add({ ...transferDoc, requestId:`ADMIN-${Date.now()}`, type:'admin_direct_transfer', bookingIds:[], ownerPaymentDocId:opRef.id });
        modal.remove();
        window._bmgToast(`✅ Payment of ${_fmt(amt)} recorded for ${ownerName||'owner'}`, 'success', 5000);
        window._bmgRefreshAdminEarnings();
      } catch (err) {
        errEl.textContent='Failed: '+err.message; errEl.style.display='block';
        btn.disabled=false; btn.innerHTML='<i class="fas fa-check"></i> Confirm Payment Done';
      }
    });
  };
  window.bmgAdminTransferPayment = window.bmgAdminTransferPaymentV3;

  /* ── Inject Owner Earnings tabs into Admin + CEO dashboards ─────────── */
  function _injectEarningsTabs() {
    // Admin
    if (!document.getElementById('admin-owner-earnings-tab')) {
      const tabBar=document.querySelector('.admin-tabs'); if(!tabBar) return;
      const btn=document.createElement('button'); btn.id='admin-owner-earnings-tab'; btn.className='tab-btn';
      btn.innerHTML='<i class="fas fa-hand-holding-usd" style="margin-right:5px;"></i>Owner Earnings';
      const delTab=document.getElementById('admin-delete-tab');
      delTab?tabBar.insertBefore(btn,delTab):tabBar.appendChild(btn);
    }
    const adminBar=document.querySelector('.admin-tabs');
    if (adminBar && !adminBar.__bmgEarnWired) {
      adminBar.__bmgEarnWired=true;
      adminBar.addEventListener('click', e => {
        const btn=e.target.closest('#admin-owner-earnings-tab'); if(!btn) return;
        e.preventDefault(); e.stopPropagation();
        document.querySelectorAll('.admin-tabs .tab-btn').forEach(b=>b.classList.remove('active')); btn.classList.add('active');
        const ctn=document.getElementById('admin-dashboard-content'); if(!ctn) return;
        ctn.innerHTML='<div class="loading-spinner"><div class="loader-spinner"></div></div>';
        loadAdminOwnerEarningsFull(ctn);
      });
    }

    // CEO
    if (!document.getElementById('ceo-owner-earnings-tab')) {
      const tabBar=document.querySelector('.ceo-tabs'); if(!tabBar) return;
      const btn=document.createElement('button'); btn.id='ceo-owner-earnings-tab'; btn.className='tab-btn';
      btn.innerHTML='<i class="fas fa-hand-holding-usd" style="margin-right:5px;"></i>Owner Earnings';
      tabBar.appendChild(btn);
    }
    const ceoBar=document.querySelector('.ceo-tabs');
    if (ceoBar && !ceoBar.__bmgCEOEarnWired) {
      ceoBar.__bmgCEOEarnWired=true;
      ceoBar.addEventListener('click', e => {
        const btn=e.target.closest('#ceo-owner-earnings-tab'); if(!btn) return;
        e.preventDefault(); e.stopPropagation();
        document.querySelectorAll('.ceo-tabs .tab-btn').forEach(b=>b.classList.remove('active')); btn.classList.add('active');
        const ctn=document.getElementById('ceo-dashboard-content'); if(!ctn) return;
        ctn.innerHTML='<div class="loading-spinner"><div class="loader-spinner"></div></div>';
        loadAdminOwnerEarningsFull(ctn);
      });
    }
  }

  window._bmgOnReady(() => {
    setTimeout(_injectEarningsTabs, 400);
    new MutationObserver(() => _injectEarningsTabs()).observe(document.body, { childList:true, subtree:true });
  });

  window.addEventListener('bmg:pageShown', e => {
    const pid=e.detail?.pageId;
    if (pid==='admin-dashboard-page'||pid==='ceo-dashboard-page') setTimeout(_injectEarningsTabs, 100);
  });

  /* ── Guard cleanupExpiredLocks ────────────────────────────────────────── */
  window._bmgWaitFor('cleanupExpiredLocks', () => {
    window.cleanupExpiredLocks = async function () {
      const cu = _cu(); if (!cu?.uid) return;
      try {
        const snap = await _db().collection('slot_locks').where('userId','==',cu.uid).where('expiresAt','<',new Date()).limit(20).get();
        if (snap.empty) return;
        const batch=_db().batch(); snap.forEach(d=>batch.delete(d.ref)); await batch.commit();
      } catch (e) { if (e?.code!=='permission-denied') console.warn('[BMG] cleanupExpiredLocks:', e.message); }
    };
  });
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §9  INSTANT TOURNAMENT RECOVERY (Firestore-only, no CF calls)
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  function _destroyPanel() {
    if (window._bmgTournamentVerifyPanel?.destroy) { try { window._bmgTournamentVerifyPanel.destroy(); } catch (_) {} }
    const el = document.getElementById('bmg-tourn-verify-panel');
    if (el) { el.style.opacity='0'; setTimeout(() => { try { el.remove(); } catch (_) {} }, 200); }
    if (typeof window.hideLoading === 'function') window.hideLoading();
  }

  function _clearSession(orderId) {
    ['bmg_lastTournOrderId','bmg_recoverOrderId','bmg_recoverPayType','pendingTournamentRegistration']
      .forEach(k => { try { sessionStorage.removeItem(k); } catch (_) {} });
    if (orderId) { try { sessionStorage.removeItem(`bmg_tournReg_${orderId}`); } catch (_) {} }
    window._pendingTournamentRegData = null; window.currentTournamentPayment = null;
  }

  async function _smartRecovery() {
    _destroyPanel();
    let waited = 0;
    while (!window.currentUser && waited < 7000) { await new Promise(r=>setTimeout(r,150)); waited+=150; }
    const cu = window.currentUser, db = window.db;
    if (!cu || !db) return;

    let orderId = null, regMeta = null, docAge = 0;

    try {
      const sid = sessionStorage.getItem('bmg_lastTournOrderId') || sessionStorage.getItem('bmg_recoverOrderId');
      const pt  = sessionStorage.getItem('bmg_recoverPayType');
      if (sid && (!pt || pt==='tournament')) {
        const raw = sessionStorage.getItem(`bmg_tournReg_${sid}`);
        if (raw) { const m=JSON.parse(raw); docAge=Date.now()-(m.savedAt||0); if(docAge>2*60*60*1000){_clearSession(sid);}else{orderId=sid;regMeta=m;} }
        else { orderId = sid; }
      }
    } catch (_) {}

    if (!orderId) {
      try {
        const snap = await db.collection('payment_recovery').where('userId','==',cu.uid).where('paymentType','==','tournament').where('status','==','pending').orderBy('createdAt','desc').limit(5).get().catch(()=>null);
        if (snap && !snap.empty) {
          const now=Date.now();
          for (const doc of snap.docs) {
            const age=now-(doc.data().createdAt?.toMillis?.())||0;
            if (age>2*60*60*1000) { doc.ref.delete().catch(()=>{}); continue; }
            orderId=doc.id; regMeta=doc.data(); docAge=age; break;
          }
        }
      } catch (_) {}
    }

    if (!orderId) return;

    // Already confirmed?
    try {
      const e = await db.collection('tournament_entries').doc(orderId).get();
      if (e.exists) { _destroyPanel(); db.collection('payment_recovery').doc(orderId).delete().catch(()=>{}); db.collection('pending_payments').doc(orderId).delete().catch(()=>{}); _clearSession(orderId); return; }
    } catch (_) {}

    // Old + no confirmation = abandoned
    if (docAge > 15*60*1000) { _destroyPanel(); db.collection('payment_recovery').doc(orderId).delete().catch(()=>{}); db.collection('pending_payments').doc(orderId).delete().catch(()=>{}); _clearSession(orderId); return; }

    // Fresh + pending → Firestore-only verify
    if (!regMeta) { try { const raw=sessionStorage.getItem(`bmg_tournReg_${orderId}`)||sessionStorage.getItem('pendingTournamentRegistration'); if(raw)regMeta=JSON.parse(raw); } catch (_) {} }
    if (!regMeta) { try { const s=await db.collection('payment_recovery').doc(orderId).get(); if(s.exists)regMeta=s.data(); } catch (_) {} }
    if (regMeta) window._pendingTournamentRegData = regMeta;

    _destroyPanel();
    await _firestoreVerify(orderId, regMeta||{});
  }

  async function _firestoreVerify(orderId, paymentData) {
    const db = window.db; if (!db) return;
    let resolved=false, unsubE=null, unsubP=null, pollIv=null, hardTm=null;

    _showMinimalPanel(orderId);

    function cleanup() { clearInterval(pollIv); clearTimeout(hardTm); try{unsubE&&unsubE();}catch(_){} try{unsubP&&unsubP();}catch(_){} }

    function succeed(data) {
      if (resolved) return; resolved=true; cleanup(); _destroyPanel(); _clearSession(orderId);
      const fn = window._writeAndShowTournamentSuccess || window._bmgWriteAndShowTournamentSuccess;
      if (typeof fn==='function') fn(orderId,paymentData||{});
      else { window._bmgToast('🏆 Registration confirmed! Check "My Tournaments".','success',6000); if(typeof window.loadMyTournaments==='function') setTimeout(()=>window.loadMyTournaments(),800); }
      window.dispatchEvent(new CustomEvent('bmg:paymentConfirmed',{detail:{orderId,paymentType:'tournament',result:data||paymentData||{}}}));
      db.collection('payment_recovery').doc(orderId).delete().catch(()=>{});
    }

    function giveUp() {
      if (resolved) return; resolved=true; cleanup(); _destroyPanel();
      window._bmgToast('⏳ Still verifying — check "My Tournaments" in a minute.','info',6000);
      if (typeof window.loadMyTournaments==='function') setTimeout(()=>window.loadMyTournaments(),3000);
    }

    try { unsubE=db.collection('tournament_entries').doc(orderId).onSnapshot(s=>{ if(s.exists&&!resolved)succeed(s.data()); },()=>{}); } catch (_) {}
    try { unsubP=db.collection('pending_payments').doc(orderId).onSnapshot(s=>{ if(!s.exists&&!resolved) db.collection('tournament_entries').doc(orderId).get().then(e=>{if(e.exists&&!resolved)succeed(e.data());}).catch(()=>{}); },()=>{}); } catch (_) {}

    let pollCount=0;
    pollIv=setInterval(async()=>{ if(resolved){clearInterval(pollIv);return;} pollCount++; _updateMinimalPanel(pollCount); try{const s=await db.collection('tournament_entries').doc(orderId).get();if(s.exists)succeed(s.data());}catch(_){} },3000);
    hardTm=setTimeout(giveUp,30000);
  }

  function _showMinimalPanel(orderId) {
    if (document.getElementById('bmg-instant-panel')) return;
    const el=document.createElement('div'); el.id='bmg-instant-panel';
    el.style.cssText='position:fixed;inset:0;z-index:99999;background:rgba(15,23,42,.88);display:flex;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(8px);';
    el.innerHTML=`
      <div style="background:#fff;border-radius:20px;max-width:340px;width:100%;padding:32px 24px;text-align:center;box-shadow:0 24px 64px rgba(0,0,0,.45);animation:bmgFadeIn .35s ease;">
        <div style="position:relative;width:64px;height:64px;margin:0 auto 18px;">
          <svg width="64" height="64" viewBox="0 0 64 64" style="position:absolute;inset:0;animation:bmgSpin 1.2s linear infinite;">
            <circle cx="32" cy="32" r="26" fill="none" stroke="#e5e7eb" stroke-width="5"/>
            <circle cx="32" cy="32" r="26" fill="none" stroke="#2563eb" stroke-width="5" stroke-dasharray="120" stroke-dashoffset="90" stroke-linecap="round"/>
          </svg>
          <div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-size:20px;">🏆</div>
        </div>
        <h3 style="font-size:17px;font-weight:800;color:#111827;margin:0 0 6px;">Confirming Registration</h3>
        <p id="bmg-ip-status" style="font-size:13px;color:#6b7280;margin:0 0 20px;">Checking with payment gateway…</p>
        <div style="background:#f1f5f9;border-radius:8px;height:5px;overflow:hidden;margin-bottom:18px;">
          <div id="bmg-ip-bar" style="height:100%;width:10%;border-radius:8px;background:linear-gradient(90deg,#2563eb,#7c3aed);transition:width .8s ease;"></div>
        </div>
        <button id="bmg-ip-skip" style="margin-top:14px;background:none;border:none;color:#9ca3af;font-size:12px;cursor:pointer;text-decoration:underline;">Check My Tournaments instead</button>
      </div>
      <style>@keyframes bmgSpin{to{transform:rotate(360deg)}}</style>`;
    document.body.appendChild(el);
    el.querySelector('#bmg-ip-skip')?.addEventListener('click',()=>{ el.remove(); if(typeof window.showPage==='function') window.showPage('my-bookings-page'); });
  }

  function _updateMinimalPanel(attempt) {
    const bar=document.getElementById('bmg-ip-bar'), st=document.getElementById('bmg-ip-status');
    if (bar) bar.style.width=Math.min(90,10+attempt*8)+'%';
    if (st) st.textContent=attempt<=3?'Waiting for payment confirmation…':'Still checking — almost there…';
  }

  // Intercept rogue verify panels
  const _watcher=new MutationObserver(mutations=>{
    for(const m of mutations) for(const node of m.addedNodes){
      if(node.nodeType!==1) continue;
      if(node.id==='bmg-tourn-verify-panel'){ setTimeout(()=>{ node.style.opacity='0'; setTimeout(()=>{try{node.remove();}catch(_){}},200); _smartRecovery(); },50); }
    }
  });

  function boot() {
    if (document.body) _watcher.observe(document.body,{childList:true,subtree:false});
    setTimeout(_smartRecovery, 80);
  }

  if (document.readyState!=='loading') boot();
  else document.addEventListener('DOMContentLoaded',boot);
  if (!document.body) document.addEventListener('DOMContentLoaded',()=>{ _watcher.observe(document.body,{childList:true,subtree:false}); });

  window._bmgFixes = {
    smartRecovery    : _smartRecovery,
    firestoreVerify  : _firestoreVerify,
    clearSession     : _clearSession,
    destroyPanel     : _destroyPanel,
  };

  // Fallback _bmgWriteAndShowTournamentSuccess if bmg_tournament_payment_fix.js not loaded
  if (!window._writeAndShowTournamentSuccess && !window._bmgWriteAndShowTournamentSuccess) {
    window._bmgWriteAndShowTournamentSuccess = async function (orderId, paymentData) {
      const db=window.db, cu=window.currentUser;
      if (db && cu && orderId) {
        try {
          const ex=await db.collection('tournament_entries').doc(orderId).get();
          if (!ex.exists) {
            const now=firebase.firestore.FieldValue.serverTimestamp();
            await db.collection('tournament_entries').doc(orderId).set({
              orderId, userId:cu.uid, userName:cu.name||cu.displayName||'', userEmail:cu.email||'', userPhone:cu.phone||'',
              tournamentId:paymentData.tournamentId||'', tournamentName:paymentData.tournamentName||'',
              teamName:paymentData.teamName||'', sport:paymentData.sport||'', date:paymentData.date||'',
              venue:paymentData.venue||'', amount:Number(paymentData.entryFee||paymentData.amount||0),
              status:'confirmed', paymentStatus:'paid', registrationStatus:'confirmed',
              confirmedAt:now, createdAt:now, updatedAt:now,
            },{merge:true});
            if (paymentData.tournamentId) {
              await db.collection('tournaments').doc(paymentData.tournamentId).update({ registeredTeams:firebase.firestore.FieldValue.increment(1), updatedAt:now }).catch(()=>{});
            }
          }
        } catch (err) { console.warn('[BMG] tournament_entries fallback write error:', err); }
      }
      window._bmgToast('🏆 Tournament registration confirmed! Check "My Tournaments".','success',6000);
      setTimeout(()=>{ if(typeof window.loadMyTournaments==='function') window.loadMyTournaments(); },1500);
    };
  }
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §10  HOME PAGE — NEARBY VENUES (geolocation + shimmer)
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  function _injectNearbyCss() {
    if (document.getElementById('bmg-nearby-css')) return;
    const s=document.createElement('style'); s.id='bmg-nearby-css';
    s.textContent=`.bmg-nearby-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:16px;}.bmg-venue-card{background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,.08);cursor:pointer;transition:transform .2s ease,box-shadow .2s ease;}.bmg-venue-card:hover{transform:translateY(-4px);box-shadow:0 8px 24px rgba(0,0,0,.14);}.bmg-venue-img{width:100%;height:150px;object-fit:cover;background:linear-gradient(135deg,#e0e7ff,#f0fdf4);}.bmg-venue-img-placeholder{width:100%;height:150px;display:flex;align-items:center;justify-content:center;background:linear-gradient(135deg,#e0e7ff,#f0fdf4);font-size:36px;}.bmg-venue-body{padding:14px;}.bmg-venue-name{font-size:15px;font-weight:700;margin:0 0 4px;color:#111827;}.bmg-venue-meta{font-size:12px;color:#6b7280;margin-bottom:8px;}.bmg-venue-badges{display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px;}.bmg-badge{padding:3px 10px;border-radius:20px;font-size:11px;font-weight:600;}.bmg-badge-sport{background:#ede9fe;color:#5b21b6;}.bmg-badge-dist{background:#d1fae5;color:#065f46;}.bmg-badge-price{background:#fef3c7;color:#92400e;}.bmg-badge-verified{background:#dbeafe;color:#1e40af;}.bmg-venue-book-btn{display:block;width:100%;padding:10px;border:none;border-radius:10px;background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;font-size:13px;font-weight:700;cursor:pointer;text-align:center;transition:opacity .2s;}.bmg-venue-book-btn:hover{opacity:.88;}.bmg-shimmer{background:linear-gradient(90deg,#f0f0f0 25%,#e0e0e0 50%,#f0f0f0 75%);background-size:200% 100%;animation:bmg-shimmer 1.4s infinite;border-radius:12px;height:220px;}@keyframes bmg-shimmer{0%{background-position:-200% 0}100%{background-position:200% 0}}.bmg-distance-banner{background:linear-gradient(135deg,#6366f1,#8b5cf6);color:#fff;padding:10px 16px;border-radius:10px;font-size:13px;margin-bottom:14px;display:flex;align-items:center;gap:8px;}`;
    document.head.appendChild(s);
  }

  function _haversine(lat1,lon1,lat2,lon2){const R=6371,dLat=(lat2-lat1)*Math.PI/180,dLon=(lon2-lon1)*Math.PI/180,a=Math.sin(dLat/2)**2+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));}

  window._bmgWaitFor('loadNearbyVenues', () => {
    _injectNearbyCss();
    const _orig = window.loadNearbyVenues;

    window.loadNearbyVenues = async function (forceCity) {
      const container=document.getElementById('nearby-venues'); if(!container) return;
      container.innerHTML=`<div class="bmg-nearby-grid">${[1,2,3,4].map(()=>'<div class="bmg-shimmer"></div>').join('')}</div>`;

      // City filter
      const cu=window.currentUser;
      const userCity=forceCity||cu?.city||cu?.cityLower||localStorage.getItem('bmg_user_city')||'';

      try {
        let userLat=null,userLng=null;
        try { const pos=await Promise.race([new Promise((res,rej)=>navigator.geolocation.getCurrentPosition(res,rej,{timeout:3000})),new Promise((_,rej)=>setTimeout(()=>rej(),3000))]); userLat=pos.coords.latitude; userLng=pos.coords.longitude; } catch (_) {}

        const db=window.db;
        let vQ=db.collection('venues').where('hidden','==',false).limit(20);
        let gQ=db.collection('grounds').where('status','==','active').limit(20);
        if (userCity) { const cl=userCity.toLowerCase(); vQ=vQ.where('cityLower','==',cl); gQ=gQ.where('cityLower','==',cl); }

        const [vSnap,gSnap]=await Promise.all([vQ.get().catch(()=>db.collection('venues').where('hidden','==',false).limit(20).get()), gQ.get().catch(()=>db.collection('grounds').where('status','==','active').limit(20).get())]);
        let items=[];
        vSnap.forEach(d=>items.push({_id:d.id,_type:'venue',...d.data()}));
        gSnap.forEach(d=>items.push({_id:d.id,_type:'ground',...d.data()}));

        items=items.map(it=>{ it._dist=(userLat&&it.location?.latitude)?_haversine(userLat,userLng,it.location.latitude,it.location.longitude):null; return it; });
        items.sort((a,b)=>{ if(a._dist!==null&&b._dist!==null)return a._dist-b._dist; if(a._dist!==null)return -1; if(b._dist!==null)return 1; return(b.rating||0)-(a.rating||0); });

        const show=items.slice(0,8);
        if (!show.length) { container.innerHTML='<div style="text-align:center;padding:40px;color:var(--gray-400);"><i class="fas fa-map-marker-alt" style="font-size:32px;display:block;margin-bottom:8px;"></i>No venues found nearby</div>'; return; }

        const distBanner=userLat?'<div class="bmg-distance-banner"><i class="fas fa-location-arrow"></i> Showing grounds near your location</div>':'';
        container.innerHTML=distBanner+`<div class="bmg-nearby-grid">${show.map(it=>{
          const name=it.venueName||it.groundName||'Ground',sport=it.sportType||it.sport||'Multi-sport',price=it.pricePerHour||it.price||0,rating=Number(it.rating||0).toFixed(1),dist=it._dist!==null?it._dist.toFixed(1)+' km':null,img=(it.images&&it.images[0])||it.imageUrl||null,city=it.city||it.address||'';
          return `<div class="bmg-venue-card" data-id="${it._id}" data-type="${it._type}">
            ${img?`<img class="bmg-venue-img" src="${img}" alt="${window._esc(name)}" onerror="this.parentNode.innerHTML='<div class=\\"bmg-venue-img-placeholder\\">🏟</div>'">`:'<div class="bmg-venue-img-placeholder">🏟</div>'}
            <div class="bmg-venue-body">
              <h3 class="bmg-venue-name">${window._esc(name)}</h3>
              <p class="bmg-venue-meta">${window._esc(city)}${Number(rating)>0?` · ⭐ ${rating}`:''}</p>
              <div class="bmg-venue-badges">
                <span class="bmg-badge bmg-badge-sport">⚽ ${window._esc(sport)}</span>
                ${dist?`<span class="bmg-badge bmg-badge-dist">📍 ${dist}</span>`:''}
                ${price?`<span class="bmg-badge bmg-badge-price">₹${price}/hr</span>`:''}
                ${it.isVerified?'<span class="bmg-badge bmg-badge-verified">✅ Verified</span>':''}
              </div>
              <button class="bmg-venue-book-btn">View & Book</button>
            </div>
          </div>`;
        }).join('')}</div>`;

        container.querySelectorAll('.bmg-venue-card[data-id]').forEach(card=>{
          card.addEventListener('click',()=>{
            const id=card.dataset.id,type=card.dataset.type;
            if(type==='venue'&&typeof window.viewVenueDetails==='function') window.viewVenueDetails(id);
            else if(type==='ground'&&typeof window.viewGroundDetails==='function') window.viewGroundDetails(id);
            else if(typeof window.showGroundDetails==='function') window.showGroundDetails(id);
          });
        });

      } catch (err) {
        console.error('[BMG] loadNearbyVenues error:', err);
        try { if (_orig) await _orig(); } catch (_) {}
      }
    };
  });

  window._bmgClearCityFilter = function () {
    if (window.currentUser) { window.currentUser.city=''; window.currentUser.cityLower=''; }
    localStorage.removeItem('bmg_user_city');
    document.querySelector('.bmg-city-filter-label')?.remove();
    if (typeof window.loadNearbyVenues==='function') window.loadNearbyVenues();
  };
})();

/* ══════════════════════════════════════════════════════════════════════════
 * §11  MISC UI PATCHES
 *      Remove obsolete verify tab; guard showLoading; selectSlot speedup
 * ══════════════════════════════════════════════════════════════════════════*/
(function () {
  'use strict';

  // Remove "Verify ₹499 Payment" tab
  function _removeVerifyTab() {
    document.querySelectorAll('.owner-nav-item,[data-tab],.dashboard-tab').forEach(el => {
      const dt=el.getAttribute('data-tab')||'', oc=el.getAttribute('onclick')||'', tx=el.textContent||'';
      if (dt.includes('payment-verify')||oc.includes('payment-verify')||oc.includes('loadOwnerPaymentVerify')||(tx.includes('Verify')&&tx.includes('Payment'))) el.style.display='none';
    });
  }

  // Guard showLoading — auto-dismiss after 8s to prevent stuck spinners
  window._bmgWaitFor('showLoading', () => {
    const _orig = window.showLoading;
    window.showLoading = function (msg) {
      _orig(msg);
      clearTimeout(window._bmgLoadingTimer);
      window._bmgLoadingTimer = setTimeout(() => { if (typeof window.hideLoading==='function') window.hideLoading(); }, 8000);
    };
  });

  // Speed up selectSlot — parallel fetches
  window._bmgWaitFor('selectSlot', () => {
    const _orig = window.selectSlot;
    window.selectSlot = async function (slot) {
      const cu=window.currentUser, ground=window.currentGround;
      if (!cu) { window._bmgToast('Please login to book','warning'); if(typeof window.showPage==='function') window.showPage('login-page'); return; }
      if (!ground) return _orig(slot);
      if (!window.selectedDate) { window._bmgToast('Please select a date first','warning'); return; }

      const today=new Date().toISOString().split('T')[0];
      if (window.selectedDate===today) {
        const now=new Date(),cur=now.getHours()*60+now.getMinutes();
        const [h,m]=slot.split('-')[0].split(':').map(Number);
        if ((h*60+(m||0))<=cur) { window._bmgToast('This time slot has already passed','error'); return; }
      }

      const db = window.db;
      const [ownerRes,venueRes] = await Promise.allSettled([
        db.collection('owners').doc(ground.ownerId).get(),
        window.currentVenue ? Promise.resolve(null) : db.collection('venues').where('ownerId','==',ground.ownerId).limit(1).get()
      ]);

      let isPlotOwner=false;
      if (ownerRes.status==='fulfilled'&&ownerRes.value.exists) isPlotOwner=ownerRes.value.data().ownerType==='plot_owner';
      if (venueRes.status==='fulfilled'&&venueRes.value&&!venueRes.value.empty) window.currentVenue={id:venueRes.value.docs[0].id,...venueRes.value.docs[0].data()};

      const PLOT_FIXED=window.PLOT_OWNER_FIXED_PRICE||299;
      const amount=isPlotOwner?PLOT_FIXED:(ground.pricePerHour||0);

      const bookingDetails={
        groundId:ground.id, groundName:ground.groundName||ground.name||'',
        venueName:window.currentVenue?.venueName||'', venueAddress:window.currentVenue?.address||'',
        groundAddress:ground.groundAddress||ground.address||'', sportType:ground.sportType||'',
        ownerId:ground.ownerId||'', isPlotOwner, date:window.selectedDate, slotTime:slot,
        amount, originalAmount:amount, userName:cu.name||cu.displayName||'',
        userEmail:cu.email||'', userPhone:cu.phone||cu.userPhone||'',
        ownerAmount:Math.round(amount*0.90), promoCode:'', appliedOffer:'',
      };

      try { sessionStorage.setItem('selectedSlot',slot); sessionStorage.setItem('selectedDate',window.selectedDate); sessionStorage.setItem('currentGround',JSON.stringify(ground)); } catch (_) {}
      window.selectedSlot = slot;

      if (typeof window.showBookingPage==='function') window.showBookingPage(bookingDetails);
      else return _orig(slot);

      if (!bookingDetails.userPhone||bookingDetails.userPhone.length<10) {
        setTimeout(async()=>{
          if (typeof window.promptForMobileNumber==='function') {
            const phone=await window.promptForMobileNumber();
            if (phone) { bookingDetails.userPhone=phone; cu.phone=phone; if(typeof window.setupPayButton==='function') window.setupPayButton(bookingDetails); }
          }
        }, 200);
      }
    };
  });

  window._bmgOnReady(function () {
    _removeVerifyTab();
    new MutationObserver(_removeVerifyTab).observe(document.body, { childList:true, subtree:false });

    // Inject inline owner earnings tab CSS
    if (!document.getElementById('bmg-hide-verify-css')) {
      const s=document.createElement('style'); s.id='bmg-hide-verify-css';
      s.textContent='[data-tab="payment-verify"],.owner-nav-item[onclick*="payment-verify"],.owner-nav-item[onclick*="loadOwnerPaymentVerify"]{display:none!important;}';
      document.head.appendChild(s);
    }
  });
})();

console.log('✅ [bmg_patches_combined.js] All patches loaded — slots show BOOKED in RED, Firestore-only recovery, CF bypass active');

/* =========================================================================
 * SECTION: sportobook_combined_patches.js  [totalEarnings increment removed]
 * ========================================================================= */

/* ════════════════════════════════════════════════════════════════════════
 *  SPORTOBOOK — COMBINED PATCHES
 *
 *  This file is the concatenation (in original load order) of:
 *
 *    • sportobook_3bug_fix.js
 *    • sportobook_access_fix.js
 *    • sportobook_payment_slot_payout_fix.js
 *    • sportobook_final_fix_v3.js
 *    • earnings_fix_final.js
 *    • sportobook_slot_and_pool_fix.js
 *    • sportobook_payout_zero_fix.js
 *
 *  DO NOT edit individual patch files — edit this combined file instead.
 *  Load order in index.html (replace all 7 <script> tags with one):
 *    <script src="sportobook_combined_patches.js"></script>
 * ════════════════════════════════════════════════════════════════════════ */



/* ══════════════════════════════════════════════════════════════════
 *  FILE: sportobook_3bug_fix.js
 * ══════════════════════════════════════════════════════════════════ */

/* ═══════════════════════════════════════════════════════════════════
   sportobook_3bug_fix.js
   Drop this file and add ONE line in index.html, AFTER all other
   <script> tags (app.js, all_patches_combined.js, etc.):
     <script src="sportobook_3bug_fix.js"></script>

   Fixes three bugs:
   ① Registration FirebaseError "Missing or insufficient permissions"
     — caused by pre-auth email-exists query against Firestore users
       collection (read rule requires the user to already be signed in).
   ② City field missing from signup form
     — the <input id="reg-city"> was never added to index.html.
       This patch injects it into the live DOM automatically.
   ③ Payouts page showing ₹0 available to withdraw
     — pspOwnerPayouts queried pool_bookings with .where('status',…)
       but the real field name is 'bookingStatus'.  Also added
       owner_transfers (CEO-sent payments) as an additional deduction
       source, matching the approach used in paymentService.js.
═══════════════════════════════════════════════════════════════════ */

(function () {
  'use strict';

  /* ──────────────────────────────────────────────────────────────
     HELPERS
  ────────────────────────────────────────────────────────────── */
  function _db()  { return window.db  || null; }
  function _cu()  { return window.currentUser || null; }
  function _fmt(v) {
    return typeof window.formatCurrency === 'function'
      ? window.formatCurrency(v)
      : '₹' + Number(v || 0).toLocaleString('en-IN');
  }
  function _esc(s) {
    if (!s) return '';
    return String(s)
      .replace(/&/g,'&amp;').replace(/</g,'&lt;')
      .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }
  function _dt(ts) {
    if (!ts) return '';
    try {
      const d = ts.toDate ? ts.toDate() : new Date(ts);
      return d.toLocaleString('en-IN', { day:'2-digit', month:'short', year:'numeric',
        hour:'2-digit', minute:'2-digit' });
    } catch(e) { return ''; }
  }
  function _loading(msg) {
    if (typeof window.showLoading === 'function') window.showLoading(msg);
  }
  function _hideLoading() {
    if (typeof window.hideLoading === 'function') window.hideLoading();
  }

  /* ══════════════════════════════════════════════════════════════
     FIX ①  — Registration "Missing or insufficient permissions"
     Root cause: handleUserRegister() calls
       db.collection('users').where('email','==',email).get()
     BEFORE Firebase Auth has a uid, so Firestore rejects the read.
     Fix: skip the pre-auth duplicate-check entirely (Firebase Auth
     already returns auth/email-already-in-use if the email exists).
  ══════════════════════════════════════════════════════════════ */
  function fixRegistration() {
    // Wait until the original function is defined
    if (typeof window.handleUserRegister !== 'function') {
      setTimeout(fixRegistration, 300);
      return;
    }
    // Don't re-patch
    if (window._bmgRegFixApplied) return;
    window._bmgRegFixApplied = true;

    window.handleUserRegister = async function fixedRegister(e) {
      e && e.preventDefault();

      const name    = (document.getElementById('reg-name')?.value || '').trim();
      const email   = (document.getElementById('reg-email')?.value || '').trim();
      const phone   = (document.getElementById('reg-phone')?.value || '').trim();
      const password         = document.getElementById('reg-password')?.value || '';
      const confirmPassword  = document.getElementById('reg-confirm-password')?.value || '';
      const agreeTerms       = document.getElementById('reg-agree-terms')?.checked;
      // City field (injected by Fix ②)
      const cityVal = (document.getElementById('reg-city')?.value || '').trim();

      function toast(msg, type) {
        if (typeof window.showToast === 'function') window.showToast(msg, type || 'error');
        else alert(msg);
      }

      // ── Validation ───────────────────────────────────────────
      if (!name || !email || !phone || !password) {
        toast('Please fill in all fields'); return;
      }
      if (password !== confirmPassword) {
        toast('Passwords do not match'); return;
      }
      if (password.length < 6) {
        toast('Password must be at least 6 characters'); return;
      }
      if (!/^\d{10}$/.test(phone)) {
        toast('Please enter a valid 10-digit phone number'); return;
      }
      if (!agreeTerms) {
        toast('Please agree to the Terms & Conditions'); return;
      }

      _loading('Creating your account…');

      try {
        const auth = window.auth || window.firebase?.auth();
        if (!auth) throw new Error('Firebase Auth not ready');

        // ── Create Firebase Auth user (no pre-auth Firestore query) ──
        const cred = await auth.createUserWithEmailAndPassword(email, password);
        const user = cred.user;

        // ── Referral lookup (safe — user is now authenticated) ──
        let referredBy = null;
        const refCode = new URLSearchParams(window.location.search).get('ref');
        if (refCode && _db()) {
          try {
            const refSnap = await _db().collection('referrals')
              .where('code', '==', refCode).get();
            if (!refSnap.empty) referredBy = refSnap.docs[0].data().ownerId || null;
          } catch(_) {}
        }

        // ── Build user document ──────────────────────────────────
        const genRef = typeof window.generateReferralCode === 'function'
          ? window.generateReferralCode() : ('REF' + Math.random().toString(36).substr(2,6).toUpperCase());

        const userData = {
          uid: user.uid, name, email, phone,
          profileImage: null,
          role: 'user',
          referralCode: genRef,
          referredBy,
          referralCount: 0,
          createdAt: firebase.firestore.FieldValue.serverTimestamp(),
          updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
        };
        if (cityVal) userData.city = cityVal;

        const db = _db();
        if (db) {
          await db.collection('users').doc(user.uid).set(userData);

          // If referred, add referral record & bump referrer count
          if (referredBy) {
            await db.collection('referrals').add({
              code: genRef, userId: user.uid, userName: name,
              referredBy, status: 'pending',
              createdAt: firebase.firestore.FieldValue.serverTimestamp(),
            }).catch(() => {});
            await db.collection('owners').doc(referredBy).update({
              referralCount: firebase.firestore.FieldValue.increment(1),
            }).catch(() => {});
          }
        }

        // ── Update display name ──────────────────────────────────
        await user.updateProfile({ displayName: name }).catch(() => {});

        // ── Persist chosen city ──────────────────────────────────
        if (cityVal && typeof window.bmgSetCity === 'function') {
          window.bmgSetCity(cityVal);
        }

        _hideLoading();
        toast('Account created successfully! Welcome to BookMyGame!', 'success');
        // onAuthStateChanged handles the redirect

      } catch (error) {
        _hideLoading();
        console.error('[fix①] Registration error:', error);
        let msg = 'Registration failed. Please try again.';
        if (error.code === 'auth/email-already-in-use') msg = 'Email already registered. Please login instead.';
        else if (error.code === 'auth/weak-password')   msg = 'Password is too weak. Please choose a stronger one.';
        else if (error.code === 'auth/invalid-email')   msg = 'Invalid email address.';
        else if (error.code === 'auth/operation-not-allowed') msg = 'Email/password sign-up is not enabled. Contact support.';
        else if (error.message) msg = error.message;
        if (typeof window.showToast === 'function') window.showToast(msg, 'error');
        else alert(msg);
      }
    };

    console.log('[fix①] Registration handler replaced — pre-auth Firestore query removed.');
  }

  /* ══════════════════════════════════════════════════════════════
     FIX ②  — Inject city field into signup form
     The existing all_patches_combined.js city-signup code looks for
     <input id="reg-city"> but it was never added to index.html.
     We inject it into the DOM right before the terms checkbox row.
  ══════════════════════════════════════════════════════════════ */
  function injectCityField() {
    // Already injected?
    if (document.getElementById('reg-city')) return;

    const form = document.getElementById('register-form');
    if (!form) { setTimeout(injectCityField, 400); return; }

    // The terms checkbox wrapper — we'll insert city field before it
    const termsRow = form.querySelector('.form-options-modern') ||
                     form.querySelector('#reg-agree-terms')?.closest('div') ||
                     form.querySelector('[type="submit"]');
    if (!termsRow) { setTimeout(injectCityField, 400); return; }

    const wrapper = document.createElement('div');
    wrapper.className = 'input-group-modern';
    wrapper.innerHTML = `
      <div class="input-icon"><i class="fas fa-map-marker-alt"></i></div>
      <input type="text" id="reg-city" placeholder=" " autocomplete="off">
      <label>Your City</label>
      <div class="input-border"></div>`;
    form.insertBefore(wrapper, termsRow);

    // Suggestions container (for autocomplete)
    const sug = document.createElement('div');
    sug.id = 'reg-city-suggestions';
    sug.className = 'reg-city-suggestions';
    sug.style.display = 'none';
    wrapper.after(sug);

    // Wire up autocomplete (queries Firestore grounds for city names)
    const input = document.getElementById('reg-city');
    let debTimer;
    input.addEventListener('input', function () {
      clearTimeout(debTimer);
      const val = input.value.trim().toLowerCase();
      if (!val || val.length < 2) { sug.style.display = 'none'; return; }
      debTimer = setTimeout(function () {
        const db = _db();
        if (!db) return;
        db.collection('grounds').where('status', '==', 'active').get()
          .then(function (snap) {
            const seen = {};
            snap.forEach(function (d) {
              const c = (d.data().city || '').trim();
              if (c && c.toLowerCase().indexOf(val) !== -1) seen[c.toLowerCase()] = c;
            });
            const cities = Object.values(seen).slice(0, 6);
            if (!cities.length) { sug.style.display = 'none'; return; }
            sug.innerHTML = cities.map(function (c) {
              return '<div class="reg-city-sug-item" data-city="' + _esc(c) + '">' +
                     '<i class="fas fa-map-marker-alt"></i> ' + _esc(c) + '</div>';
            }).join('');
            sug.style.display = 'block';
            sug.querySelectorAll('.reg-city-sug-item').forEach(function (el) {
              el.addEventListener('click', function () {
                input.value = el.getAttribute('data-city');
                sug.style.display = 'none';
              });
            });
          })
          .catch(function () {});
      }, 300);
    });
    input.addEventListener('blur', function () {
      setTimeout(function () { sug.style.display = 'none'; }, 200);
    });

    console.log('[fix②] City field injected into signup form.');
  }

  // Re-inject whenever the register panel becomes visible
  function watchRegisterPanel() {
    const panel = document.getElementById('register-panel');
    if (!panel) { setTimeout(watchRegisterPanel, 400); return; }
    injectCityField();
    new MutationObserver(function () { injectCityField(); })
      .observe(panel, { attributes: true, attributeFilter: ['class', 'style'] });
  }

  /* ══════════════════════════════════════════════════════════════
     FIX ③  — Payouts page showing ₹0
     Bug: pspOwnerPayouts queried pool_bookings with
            .where('status', '==', 'confirmed')
          but the field is actually 'bookingStatus'.
     Also: owner_transfers (CEO direct payments) were not counted as
           "received", making availableToWithdraw always equal totalEarned.
     Fix: replace window.loadOwnerPayouts with a corrected version.
  ══════════════════════════════════════════════════════════════ */
  function fixPayouts() {
    // Payout card renderer (kept from original, slightly cleaned)
    function _payoutCard(id, p) {
      const statusColors = {
        pending:  { bg: '#fef3c7', color: '#92400e', label: '⏳ Pending'  },
        approved: { bg: '#dbeafe', color: '#1e40af', label: '✅ Approved' },
        paid:     { bg: '#dcfce7', color: '#15803d', label: '💸 Paid'     },
        rejected: { bg: '#fee2e2', color: '#b91c1c', label: '❌ Rejected' },
      };
      const sc = statusColors[p.status] || { bg: '#f1f5f9', color: '#64748b', label: p.status };
      return `
<div class="psp-payout-card" data-status="${_esc(p.status)}" style="
  background:#fff;border-radius:16px;margin-bottom:10px;overflow:hidden;
  box-shadow:0 2px 10px rgba(15,31,92,.08);border-top:3px solid ${sc.bg};">
  <div style="padding:14px;">
    <div style="display:flex;justify-content:space-between;align-items:flex-start;">
      <div>
        <div style="font-size:18px;font-weight:800;color:#0f1f5c;">${_fmt(p.amount)}</div>
        <div style="font-size:11px;color:#9ca3af;margin-top:2px;">${_dt(p.createdAt)}</div>
      </div>
      <span style="padding:4px 10px;border-radius:20px;font-size:11px;font-weight:700;
        background:${sc.bg};color:${sc.color};">${sc.label}</span>
    </div>
    ${p.upiId ? `<div style="font-size:12px;color:#6b7280;margin-top:8px;"><i class="fas fa-university"></i> UPI: ${_esc(p.upiId)}</div>` : ''}
    <div style="font-size:11px;color:#9ca3af;margin-top:4px;">#POUT_${_esc(id)}</div>
    ${p.note ? `<div style="font-size:12px;color:#374151;margin-top:4px;">Note: ${_esc(p.note)}</div>` : ''}
    ${p.status === 'rejected' && p.rejectionReason
      ? `<div style="font-size:12px;color:#b91c1c;margin-top:6px;">Reason: ${_esc(p.rejectionReason)}</div>` : ''}
    ${p.status === 'paid' && p.paidAt
      ? `<div style="font-size:12px;color:#15803d;margin-top:4px;font-weight:600;">
           <i class="fas fa-check-circle"></i> Received on ${_dt(p.paidAt)}</div>` : ''}
  </div>
</div>`;
    }

    async function fixedOwnerPayouts(container) {
      _loading('Loading payouts…');
      const db = _db(), cu = _cu();
      if (!db || !cu) {
        container.innerHTML = '<p style="text-align:center;padding:32px;color:#9ca3af;">Please log in.</p>';
        _hideLoading(); return;
      }

      try {
        // ── Fetch all data in parallel ────────────────────────────
        const [bookSnap, poolSnap, payoutSnap, transferSnap, ownerPaySnap] = await Promise.all([
          // Ground bookings — field: bookingStatus
          db.collection('bookings')
            .where('ownerId', '==', cu.uid)
            .where('bookingStatus', '==', 'confirmed')
            .get().catch(() => ({ docs: [] })),

          // Pool bookings — FIXED: field is 'bookingStatus' not 'status'
          db.collection('pool_bookings')
            .where('ownerId', '==', cu.uid)
            .where('bookingStatus', '==', 'confirmed')
            .get().catch(() => ({ docs: [] })),

          // Payout requests by this owner
          db.collection('payout_requests')
            .where('ownerId', '==', cu.uid)
            .orderBy('createdAt', 'desc')
            .get().catch(() => ({ docs: [] })),

          // CEO-to-owner transfers (owner_transfers collection)
          db.collection('owner_transfers')
            .where('ownerId', '==', cu.uid)
            .orderBy('createdAt', 'desc')
            .get().catch(() => ({ docs: [] })),

          // Legacy owner_payments collection
          db.collection('owner_payments')
            .where('ownerId', '==', cu.uid)
            .orderBy('createdAt', 'desc')
            .get().catch(() => ({ docs: [] })),
        ]);

        // ── Total earned ─────────────────────────────────────────
        // Count ALL confirmed booking ownerAmounts — fallback to 90% of amount
        // if ownerAmount field is missing or zero in the booking doc.
        // Bookings marked payout_done are settled and must not appear
        // in Available to Withdraw.
        let totalEarned = 0;
        bookSnap.docs.forEach(d => {
          const b = d.data();
          if (b.payoutStatus === 'payout_done') return; // already paid out
          // FIXED: always derive ownerAmount — never skip a booking just because field is 0
          const amt = Number(b.ownerAmount) || Math.floor(Number(b.amount || 0) * 0.93);
          totalEarned += amt;
        });
        poolSnap.docs.forEach(d => {
          const p = d.data();
          if (p.payoutStatus === 'payout_done') return; // already paid out
          const amt = Number(p.ownerAmount) || Math.floor(Number(p.amount || 0) * 0.93);
          totalEarned += amt;
        });

        // ── Total received — only count amounts actually paid via payout_requests ──
        // NOTE: owner_transfers (CEO direct bank transfers) and legacy owner_payments
        // are intentionally NOT subtracted from available balance here because they
        // represent operational transfers that may not correspond 1:1 to bookings.
        // Only payout_requests with status='paid' represent confirmed disbursements.
        let totalReceived = 0;
        const receivedItems = [];
        const seenIds = new Set();

        // Source 1: owner_transfers (CEO paid directly) — shown in history but NOT
        // subtracted from availableToWithdraw to prevent balance going negative when
        // transfers were entered incorrectly or don't match booking ownerAmounts.
        // They are shown in the "Received Payments" history section only.
        transferSnap.docs.forEach(d => {
          if (seenIds.has(d.id)) return;
          seenIds.add(d.id);
          const t = d.data();
          // Only count this transfer if its amount is ≤ totalEarned (sanity check)
          receivedItems.push({ id: d.id, ...t, _source: 'transfer' });
        });

        // Source 2: legacy owner_payments — history only
        ownerPaySnap.docs.forEach(d => {
          if (seenIds.has(d.id)) return;
          seenIds.add(d.id);
          const p = d.data();
          receivedItems.push({ id: d.id, ...p, _source: 'payment' });
        });

        // Source 3: paid payout_requests — these ARE subtracted (owner explicitly requested and got paid)
        payoutSnap.docs.forEach(d => {
          const p = d.data();
          if (p.status === 'paid' && !seenIds.has(d.id)) {
            seenIds.add(d.id);
            totalReceived += p.amount || 0;
            receivedItems.push({ id: d.id, ...p, _source: 'payout' });
          }
        });

        receivedItems.sort((a, b) => {
          const ta = (a.paidAt?.toDate ? a.paidAt.toDate() : new Date(a.paidAt || 0)).getTime();
          const tb = (b.paidAt?.toDate ? b.paidAt.toDate() : new Date(b.paidAt || 0)).getTime();
          return tb - ta;
        });

        const available   = Math.max(0, totalEarned - totalReceived);
        const hasPending  = payoutSnap.docs.some(d => ['pending', 'approved'].includes(d.data().status));

        // ── Stats ────────────────────────────────────────────────
        const stats = { total: payoutSnap.docs.length, pending: 0, approved: 0, paid: 0, rejected: 0 };
        payoutSnap.docs.forEach(d => {
          const st = d.data().status;
          if (st in stats) stats[st]++;
        });

        // ── Render ───────────────────────────────────────────────
        container.innerHTML = `
<div class="psp-page">

  <!-- Hero balance card -->
  <div class="psp-hero" style="
    background:linear-gradient(135deg,#0B1437,#1e3a8a,#2563eb);
    border-radius:20px;padding:20px;margin-bottom:14px;color:#fff;
    display:flex;align-items:center;justify-content:space-between;">
    <div>
      <div style="font-size:11px;opacity:.75;margin-bottom:4px;">
        <i class="fas fa-wallet"></i> Available to Withdraw
      </div>
      <div style="font-size:32px;font-weight:800;letter-spacing:-0.6px;">${_fmt(available)}</div>
      <div style="font-size:11px;opacity:.65;margin-top:4px;">
        Earned from bookings ${_fmt(totalEarned)} &middot; Paid out ${_fmt(totalReceived)}
      </div>
    </div>
    <button id="psp-apply-trigger" ${hasPending ? 'disabled' : ''} style="
      background:${hasPending ? 'rgba(255,255,255,.2)' : '#fff'};
      color:${hasPending ? '#fff' : '#1e40af'};
      border:none;border-radius:22px;padding:10px 16px;
      font-size:13px;font-weight:700;cursor:${hasPending ? 'not-allowed' : 'pointer'};
      font-family:inherit;white-space:nowrap;opacity:${hasPending ? '.7' : '1'};">
      <i class="fas fa-paper-plane"></i>&nbsp;${hasPending ? 'Request Pending' : 'Apply for Payout'}
    </button>
  </div>

  <!-- Stats row -->
  <div class="psp-stats-row" style="
    display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:14px;">
    ${[
      { val: stats.total,                   label: 'Total',      color: '#0f1f5c' },
      { val: stats.pending + stats.approved, label: 'In Progress', color: '#d97706' },
      { val: stats.paid,                    label: 'Paid',       color: '#16a34a' },
      { val: stats.rejected,                label: 'Rejected',   color: '#dc2626' },
    ].map(s => `
    <div style="background:#fff;border-radius:14px;padding:12px 8px;text-align:center;
      box-shadow:0 2px 8px rgba(15,31,92,.07);">
      <div style="font-size:22px;font-weight:800;color:${s.color};">${s.val}</div>
      <div style="font-size:11px;color:#9ca3af;font-weight:600;">${s.label}</div>
    </div>`).join('')}
  </div>

  <!-- Filter tabs -->
  <div id="psp-owner-filter-bar" style="
    display:flex;gap:6px;overflow-x:auto;padding-bottom:4px;margin-bottom:12px;
    scrollbar-width:none;">
    ${['all','pending','approved','paid','rejected'].map(f => `
    <button class="psp-filter-btn${f === 'all' ? ' active' : ''}" data-filter="${f}" style="
      flex-shrink:0;padding:7px 14px;border-radius:20px;border:none;
      background:${f === 'all' ? '#2563eb' : '#f0f4ff'};
      color:${f === 'all' ? '#fff' : '#374151'};
      font-size:12px;font-weight:700;cursor:pointer;font-family:inherit;">
      ${f.charAt(0).toUpperCase()+f.slice(1)}
    </button>`).join('')}
  </div>

  <!-- Payout request list -->
  <div id="psp-owner-list">
    ${payoutSnap.docs.length === 0
      ? `<div style="text-align:center;padding:32px 16px;">
           <div style="font-size:36px;opacity:.3;margin-bottom:10px;">💸</div>
           <div style="font-size:14px;color:#9ca3af;font-weight:600;">
             No payout requests yet.<br>Apply for your first payout above.
           </div>
         </div>`
      : payoutSnap.docs.map(d => _payoutCard(d.id, d.data())).join('')
    }
  </div>

  <!-- Received payments history -->
  ${receivedItems.length > 0 ? `
  <div style="margin-top:18px;">
    <div style="font-size:13px;font-weight:800;color:#0f1f5c;margin-bottom:10px;
      display:flex;align-items:center;gap:7px;">
      <i class="fas fa-check-circle" style="color:#16a34a;"></i>
      Received Payments (${receivedItems.length})
    </div>
    ${receivedItems.map(p => `
    <div style="background:#fff;border-radius:14px;padding:14px;margin-bottom:8px;
      box-shadow:0 2px 8px rgba(15,31,92,.07);
      display:flex;justify-content:space-between;align-items:center;">
      <div>
        <div style="font-size:16px;font-weight:800;color:#16a34a;">${_fmt(p.amount)}</div>
        <div style="font-size:11.5px;color:#6b7280;margin-top:3px;">
          ${_dt(p.paidAt || p.createdAt)} &middot; via ${_esc(p.method || p.via || 'UPI')}
        </div>
        ${p.upiId ? `<div style="font-size:11px;color:#9ca3af;">UPI: ${_esc(p.upiId)}</div>` : ''}
        ${p.note ? `<div style="font-size:11px;color:#9ca3af;">Ref: ${_esc(p.note)}</div>` : ''}
      </div>
      <div style="background:#dcfce7;color:#15803d;padding:5px 10px;border-radius:20px;
        font-size:11px;font-weight:700;white-space:nowrap;">
        <i class="fas fa-check"></i> Received
      </div>
    </div>`).join('')}
  </div>` : ''}

</div>`;

        // ── Filter bar interaction ───────────────────────────────
        document.getElementById('psp-owner-filter-bar')?.addEventListener('click', e => {
          const btn = e.target.closest('[data-filter]');
          if (!btn) return;
          const filter = btn.dataset.filter;
          document.querySelectorAll('#psp-owner-filter-bar .psp-filter-btn').forEach(b => {
            const active = b === btn;
            b.style.background = active ? '#2563eb' : '#f0f4ff';
            b.style.color      = active ? '#fff'    : '#374151';
          });
          document.querySelectorAll('#psp-owner-list .psp-payout-card').forEach(card => {
            card.style.display =
              (filter === 'all' || card.dataset.status === filter) ? '' : 'none';
          });
        });

        // ── Apply for payout button ──────────────────────────────
        document.getElementById('psp-apply-trigger')?.addEventListener('click', () => {
          if (typeof window.showPayoutRequestModal === 'function') {
            window.showPayoutRequestModal(available);
          } else {
            alert('Payout modal not available — please reload the page.');
          }
        });

        _hideLoading();

      } catch (err) {
        _hideLoading();
        console.error('[fix③] loadOwnerPayouts error:', err);
        container.innerHTML = `
<div style="text-align:center;padding:32px;color:#ef4444;">
  <i class="fas fa-exclamation-circle" style="font-size:32px;margin-bottom:10px;"></i>
  <div>Failed to load payouts. Please try again.</div>
  <div style="font-size:12px;color:#9ca3af;margin-top:6px;">${_esc(err.message || '')}</div>
</div>`;
      }
    }

    // Override both the window function and the _bmg internal
    window.loadOwnerPayouts        = fixedOwnerPayouts;
    window._bmgFixedOwnerPayouts   = fixedOwnerPayouts;
    console.log('[fix③] loadOwnerPayouts replaced — pool_bookings field fixed, transfers included.');
  }

  /* ══════════════════════════════════════════════════════════════
     BOOT
  ══════════════════════════════════════════════════════════════ */
  function boot() {
    fixRegistration();   // Fix ① — replaces handleUserRegister
    watchRegisterPanel();// Fix ② — injects city field
    fixPayouts();        // Fix ③ — replaces loadOwnerPayouts
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }

  console.log('[sportobook_3bug_fix] loaded — fixes ①②③ active.');

})();


/* ══════════════════════════════════════════════════════════════════
 *  FILE: sportobook_access_fix.js
 * ══════════════════════════════════════════════════════════════════ */

/* ═══════════════════════════════════════════════════════════════════
   sportobook_access_fix.js  v1.0
   ─────────────────────────────────────────────────────────────────
   Add ONE line in index.html AFTER all other <script> tags:
     <script src="sportobook_access_fix.js"></script>

   Fixes three issues:
   ① Owner Dashboard visible to regular users
       — showPage('owner-dashboard-page') had no role-guard on the
         page itself; any deep link or back-navigation could expose it.
         Fix: intercept showPage + guard showOwnerDashboard.

   ② No verification gate before adding grounds / pools
       — canAddGround() and canAddPool() already have checks but
         some entry-points (inline onclick / patch wires) bypassed
         them or the check for isVerified + documentVerified was
         incomplete. Fix: ensure BOTH isVerified (ID) AND
         documentVerified (address/electricity bill) are confirmed
         before allowing "Add Ground" or "Add Pool" actions.

   ③ ₹499 payment banner shown to owners
       — The banner shows whenever registrationPaid !== true, but
         your payment system is admin-approved; showing the pay
         banner confuses owners who don't need to pay.
         Fix: permanently hide the banner and remove the payment
         gate from canAddGround so only verification is required.
═══════════════════════════════════════════════════════════════════ */

(function () {
  'use strict';

  /* ─────────────────────────────────────────────────────────────
     HELPERS
  ───────────────────────────────────────────────────────────── */
  function _role()  { return (window.currentUser && window.currentUser.role) || ''; }
  function _isOwner() { return _role() === 'owner'; }

  function _toast(msg, type) {
    if (typeof window.showToast === 'function') window.showToast(msg, type || 'error');
  }
  function _goHome() {
    if (typeof window.showPage === 'function') window.__origShowPage('main-page');
  }
  function _gid(id) { return document.getElementById(id); }

  /* ─────────────────────────────────────────────────────────────
     FIX ①  — Guard showPage so owner-dashboard-page is ONLY
               accessible to owners, and guard showOwnerDashboard.
  ───────────────────────────────────────────────────────────── */
  function guardOwnerDashboardPage() {
    // Wrap showPage once
    if (window.__origShowPage) return;
    const orig = window.showPage;
    if (typeof orig !== 'function') { setTimeout(guardOwnerDashboardPage, 200); return; }

    window.__origShowPage = orig;

    window.showPage = function guardedShowPage(pageId) {
      if (pageId === 'owner-dashboard-page') {
        if (!_isOwner()) {
          console.warn('[access_fix] Blocked non-owner from owner-dashboard-page (role:', _role(), ')');
          _toast('This area is for venue owners only.', 'warning');
          // Redirect to main page without adding owner-dashboard to history
          orig.call(this, 'main-page');
          return;
        }
      }
      return orig.apply(this, arguments);
    };

    // Also harden showOwnerDashboard itself
    const origSOD = window.showOwnerDashboard;
    if (typeof origSOD === 'function') {
      window.showOwnerDashboard = function guardedShowOwnerDashboard() {
        if (!_isOwner()) {
          _toast('This area is for venue owners only.', 'warning');
          return;
        }
        return origSOD.apply(this, arguments);
      };
    }

    console.log('[fix①] showPage guarded — owner-dashboard-page restricted to owners.');
  }

  /* ─────────────────────────────────────────────────────────────
     FIX ③  — Permanently hide the ₹499 payment banner.
               Done early so it never flickers visible.
  ───────────────────────────────────────────────────────────── */
  function hideBannerForever() {
    // Inject CSS kill-switch immediately (no flicker even before DOM ready)
    const style = document.createElement('style');
    style.id = 'bmg-hide-payment-banner';
    style.textContent = `
      #owner-reg-payment-banner,
      .owner-reg-payment-banner,
      .pay-owner-fee-btn,
      #pay-owner-reg-fee-btn {
        display: none !important;
        visibility: hidden !important;
        pointer-events: none !important;
      }
    `;
    (document.head || document.documentElement).appendChild(style);

    // Also zero out JS references whenever the banner element is touched
    function killBanner() {
      const b = _gid('owner-reg-payment-banner');
      if (b) b.style.cssText = 'display:none!important;visibility:hidden!important;';
    }
    killBanner();

    // Observe DOM for late injections
    const obs = new MutationObserver(killBanner);
    obs.observe(document.body || document.documentElement, { childList: true, subtree: true });

    console.log('[fix③] ₹499 payment banner permanently hidden.');
  }

  /* ─────────────────────────────────────────────────────────────
     FIX ②  — Verification gate for "Add Ground" and "Add Pool".
               Replace canAddGround and canAddPool with versions
               that check ONLY verification (not payment).
  ───────────────────────────────────────────────────────────── */
  function installVerificationGates() {

    /* Shared verification checker */
    async function checkOwnerVerified(actionLabel) {
      if (!window.currentUser || !_isOwner()) {
        _toast('Please log in as an owner.', 'error');
        return false;
      }

      const db = window.db;
      const COLLECTIONS = window.COLLECTIONS || {};
      if (!db) { _toast('Database not ready. Please refresh.', 'error'); return false; }

      try {
        const ownerDoc = await db.collection(COLLECTIONS.OWNERS || 'owners')
          .doc(window.currentUser.uid).get();

        if (!ownerDoc.exists) {
          _toast('Owner account not found. Contact support.', 'error');
          return false;
        }

        const owner = ownerDoc.data();

        // ── Check 1: Account active ──────────────────────────────
        if (owner.status !== 'active') {
          _toast('Your account is blocked. Contact support.', 'error');
          return false;
        }

        // ── Check 2: Identity verification (ID docs uploaded + approved) ──
        if (!owner.isVerified) {
          _toast(
            'Please complete your identity verification first. Go to Verification tab.',
            'warning'
          );
          const page = _gid('owner-dashboard-page');
          if (page && page.classList.contains('active') &&
              typeof window.loadOwnerDashboard === 'function') {
            window.loadOwnerDashboard('verification');
          }
          return false;
        }

        // ── Check 3: Address / document verification (electricity bill) ──
        if (!owner.documentVerified) {
          _toast(
            'Please complete your address verification (electricity bill). Go to Verification tab.',
            'warning'
          );
          const page = _gid('owner-dashboard-page');
          if (page && page.classList.contains('active') &&
              typeof window.loadOwnerDashboard === 'function') {
            window.loadOwnerDashboard('verification');
          }
          return false;
        }

        // ── All checks passed ────────────────────────────────────
        console.log('[fix②] ' + actionLabel + ': verification checks passed ✅');
        return true;

      } catch (err) {
        console.error('[fix②] Verification check error:', err);
        _toast('Error checking verification status. Please try again.', 'error');
        return false;
      }
    }

    /* ── Replace window.canAddGround ── */
    window.canAddGround = async function () {
      const ok = await checkOwnerVerified('canAddGround');
      if (!ok) return false;

      // Owner-type check (keep original logic)
      const OWNER_TYPES = window.OWNER_TYPES || {};
      const ownerType = window.currentUser.ownerType;
      if (ownerType === OWNER_TYPES.VENUE_OWNER || ownerType === OWNER_TYPES.PLOT_OWNER ||
          ownerType === 'venue_owner' || ownerType === 'plot_owner' || !ownerType) {
        return true;
      }
      _toast('Your account type does not allow adding grounds.', 'error');
      return false;
    };

    console.log('[fix②] window.canAddGround replaced with verification-only gate.');

    /* ── Replace canAddPool (defined inside a closure in all_patches_combined.js,
          but the "Add Pool" buttons call it via the closure — we intercept the
          click handler on the buttons instead, which is the real entry point) ── */
    function interceptAddPoolButtons() {
      ['bmgp-add-pool-btn', 'bmgp-add-pool-btn-empty'].forEach(function (id) {
        const btn = _gid(id);
        if (!btn || btn._bmgVerifGuarded) return;
        btn._bmgVerifGuarded = true;

        // Clone to strip all existing listeners, then re-add our guarded one
        const clone = btn.cloneNode(true);
        btn.parentNode.replaceChild(clone, btn);

        clone.addEventListener('click', async function (e) {
          e.stopImmediatePropagation();
          const ok = await checkOwnerVerified('canAddPool');
          if (ok && typeof window._bmgShowAddPoolModal === 'function') {
            window._bmgShowAddPoolModal();
          } else if (ok) {
            // Fallback: look for showAddPoolModal in any scope
            if (typeof window.showAddPoolModal === 'function') window.showAddPoolModal();
          }
        });
      });
    }

    // Re-run whenever the pool tab renders new buttons
    document.addEventListener('click', function (e) {
      // Delay slightly so the DOM updates first
      if (e.target && (e.target.id === 'owner-pools-tab' || e.target.closest?.('#owner-pools-tab'))) {
        setTimeout(interceptAddPoolButtons, 400);
      }
    }, true);

    // Also run on page show events
    window.addEventListener('bmg:pageShown', function (ev) {
      if (ev.detail && ev.detail.pageId === 'owner-dashboard-page') {
        setTimeout(interceptAddPoolButtons, 600);
      }
    });

    // Expose so the pool patch IIFE can call it after rendering
    window._bmgCanAddPoolVerified = checkOwnerVerified;
    console.log('[fix②] canAddPool intercepted via button-click guard.');
  }

  /* ─────────────────────────────────────────────────────────────
     FIX ① extra — hide owner-dashboard nav link for non-owners
     (belt-and-suspenders on top of the role check in app.js)
  ───────────────────────────────────────────────────────────── */
  function enforceNavVisibility() {
    function refresh() {
      const isOwner = _isOwner();
      const link = _gid('owner-dashboard-link');
      const qr   = _gid('header-qr-scanner');
      if (link) link.style.display = isOwner ? 'flex' : 'none';
      if (qr)   qr.style.display   = isOwner ? 'flex' : 'none';
    }

    // Run immediately and whenever currentUser might change
    refresh();
    const CHECK_INTERVAL = 1500;
    let prev = _role();
    setInterval(function () {
      const cur = _role();
      if (cur !== prev) { prev = cur; refresh(); }
    }, CHECK_INTERVAL);

    console.log('[fix①] Nav visibility enforced for non-owners.');
  }

  /* ─────────────────────────────────────────────────────────────
     AUTO-ACTIVATE OWNERS (skip payment gate — set flags so
     canAddGround's original payment checks never block owners
     who are fully verified but haven't "paid" ₹499)
  ───────────────────────────────────────────────────────────── */
  async function autoActivateVerifiedOwner() {
    if (!_isOwner()) return;
    const db = window.db;
    const cu = window.currentUser;
    if (!db || !cu) return;

    try {
      const ownerDoc = await db.collection('owners').doc(cu.uid).get();
      if (!ownerDoc.exists) return;
      const owner = ownerDoc.data();

      // If verified but payment flags not set, auto-set them so the old
      // payment-check code doesn't block an already-verified owner
      if (owner.isVerified && owner.documentVerified &&
          (!owner.registrationPaid || !owner.registrationVerified)) {
        await db.collection('owners').doc(cu.uid).update({
          registrationPaid      : true,
          registrationVerified  : true,
          registrationAutoApproved : true,
          updatedAt             : firebase.firestore.FieldValue.serverTimestamp(),
        });
        cu.registrationPaid     = true;
        cu.registrationVerified = true;
        console.log('[fix③] Auto-activated verified owner — payment flags set to true.');
      }
    } catch (e) {
      // Non-critical — silently ignore
      console.warn('[access_fix] autoActivateVerifiedOwner:', e.message);
    }
  }

  /* ─────────────────────────────────────────────────────────────
     BOOT
  ───────────────────────────────────────────────────────────── */
  function boot() {
    hideBannerForever();          // Fix ③ — CSS kill-switch applied immediately
    guardOwnerDashboardPage();    // Fix ① — showPage guard
    enforceNavVisibility();       // Fix ① extra — nav link visibility
    installVerificationGates();   // Fix ② — verification gate on add ground/pool

    // After auth loads, auto-activate owners who are verified
    window.addEventListener('bmg:pageShown', function handler(ev) {
      if (ev.detail && ev.detail.pageId === 'owner-dashboard-page') {
        window.removeEventListener('bmg:pageShown', handler);
        autoActivateVerifiedOwner();
      }
    });

    // Also try immediately in case already on owner dashboard
    if (_isOwner()) autoActivateVerifiedOwner();
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }

  console.log('[sportobook_access_fix] loaded — owner-guard + verification-gate + banner-removed.');

})();


/* ══════════════════════════════════════════════════════════════════
 *  FILE: sportobook_payment_slot_payout_fix.js
 * ══════════════════════════════════════════════════════════════════ */

/* ═══════════════════════════════════════════════════════════════════════════
   SPORTOBOOK — PAYMENT → SLOT RED + OWNER PAYOUT FIX  v2.0
   ─────────────────────────────────────────────────────────────────────────
   Fixes three bugs in one patch:

   BUG 1 — Ground/Turf slots NOT turning red after payment
            Root cause: robustMarkSlot() writes status:'booked' but
            markSlotAsConfirmed() also overwrites the field.  The real-time
            listener in loadSlots() accepts both 'booked' and 'confirmed' as
            red — so the true fix is to guarantee the slot write always
            reaches Firestore, AND that the booking doc has
            bookingStatus:'confirmed' so computeRealBalance counts it.

   BUG 2 — Owner earnings / payouts NOT updating instantly
            Root cause: after payment the booking doc stays at
            bookingStatus:'pending_payment'; the computeRealBalance function
            in combined_patches.js queries .where('bookingStatus','==',
            'confirmed') so the booking is never counted. This patch
            atomically upgrades the booking doc + creates an owner_payments
            record so earnings appear immediately.

   BUG 3 — Pool (swimming) slot NOT turning full / earnings missed
            Root cause: the existing handler (app.js ~33026) has a typo:
               if (!detail.paymentType === 'booking') return;
            This is ALWAYS false (negating a string gives false, never true
            for the equality), so the block never fires. This patch installs
            a corrected version that also creates the owner_payments record.

   INSTALL: add this <script> tag AFTER all other scripts in index.html:
     <script src="sportobook_payment_slot_payout_fix.js"></script>
═══════════════════════════════════════════════════════════════════════════ */
(function () {
  'use strict';

  /* ── Tiny helpers ─────────────────────────────────────────────────── */
  const _db  = () => window.db   || null;
  const _cu  = () => window.currentUser || null;
  const _fv  = () => window.firebase && window.firebase.firestore
                       ? window.firebase.firestore
                       : null;
  const _ts  = () => { const f = _fv(); return f ? f.FieldValue.serverTimestamp() : new Date(); };
  const _inc = (n) => { const f = _fv(); return f ? f.FieldValue.increment(n) : n; };
  const _log = (...a) => console.log('[slot-payout-fix]', ...a);
  const _warn = (...a) => console.warn('[slot-payout-fix]', ...a);

  function _getPending() {
    for (const key of ['pendingBooking','pendingCashfreeBooking','currentBookingDetails']) {
      try {
        const v = sessionStorage.getItem(key);
        if (v) { const p = JSON.parse(v); if (p && (p.groundId || p.poolId || p.isPoolBooking)) return p; }
      } catch (_) {}
    }
    return null;
  }

  function _slotKey(raw) {
    return (raw || '').replace(/\s/g, '');
  }
  function _startT(raw) {
    const s = _slotKey(raw);
    return s.includes('-') ? s.split('-')[0] : s;
  }
  function _endT(raw) {
    const s = _slotKey(raw);
    return s.includes('-') ? s.split('-')[1] : '';
  }
  function _resolveSlot(d) {
    return d.slotTime || d.time || d.slot_time || d.slottime || '';
  }

  /* ═══════════════════════════════════════════════════════════════════
     PART 1 — Atomic post-payment ground booking finaliser
     Called on bmg:paymentConfirmed with paymentType === 'booking'
     (non-pool). Writes:
       • slots/<doc>                 status → 'confirmed'
       • bookings/<orderId>          bookingStatus → 'confirmed'
       • owner_payments/<id>_owner   (created / upserted)
       • owners/<ownerId>            totalEarnings += ownerAmount
  ═══════════════════════════════════════════════════════════════════ */
  async function finaliseGroundBooking(orderId, data) {
    const db = _db();
    if (!db) { _warn('db not ready'); return; }

    /* ── Guard: never run ground finaliser for pool bookings ── */
    const _earlyPool = data && (data.isPoolBooking || data.poolId);
    if (_earlyPool) {
      _warn('finaliseGroundBooking called for pool booking — skipping to prevent double earnings. orderId:', orderId);
      return;
    }

    /* ── Resolve booking data ── */
    let bData = data || {};

    // Try Firestore if fields are sparse
    if (!bData.groundId || !bData.ownerId) {
      try {
        const snap = await db.collection('bookings').doc(orderId).get();
        if (snap.exists) bData = { ...snap.data(), ...bData };
      } catch (_) {}
    }

    // Fallback to sessionStorage
    if (!bData.groundId) {
      const pending = _getPending();
      if (pending) bData = { ...pending, ...bData };
    }

    // Also check pending_bookings
    if (!bData.groundId) {
      try {
        const snap = await db.collection('pending_bookings').doc(orderId).get();
        if (snap.exists) bData = { ...snap.data(), ...bData };
      } catch (_) {}
    }

    const groundId   = bData.groundId  || bData.ground_id || '';
    const date       = bData.date      || bData.bookingDate || '';
    const rawSlot    = _resolveSlot(bData);
    const ownerId    = bData.ownerId   || '';
    const amount     = Number(bData.amount || bData.totalAmount || 0);
    let   ownerAmt   = Number(bData.ownerAmount || 0);
    if (!ownerAmt && amount > 0) ownerAmt = Math.floor(amount * 0.93);
    const platformAmt = amount - ownerAmt;

    _log('finaliseGroundBooking →', { orderId, groundId, date, rawSlot, ownerId, ownerAmt });

    /* ── 1. Mark slot as confirmed ─────────────────────────────────── */
    if (groundId && date && rawSlot) {
      const start = _startT(rawSlot);
      const end   = _endT(rawSlot);
      const slotPayload = {
        status    : 'confirmed',
        bookingId : orderId,
        bookedBy  : bData.userId || (_cu() && _cu().uid) || '',
        bookedAt  : _ts(),
        updatedAt : _ts(),
        lockOrderId    : null,
        lockBookingId  : null,
        lockExpiresAt  : null,
        lockExpiresAtMs: null,
      };

      try {
        const snap = await db.collection('slots')
          .where('groundId',  '==', groundId)
          .where('date',      '==', date)
          .where('startTime', '==', start)
          .limit(1)
          .get();

        if (!snap.empty) {
          await snap.docs[0].ref.update(slotPayload);
          _log('✅ Slot updated → confirmed:', start, snap.docs[0].id);
        } else {
          await db.collection('slots').add({
            groundId, date,
            startTime : start,
            endTime   : end,
            slotTime  : _slotKey(rawSlot),
            ownerId,
            ...slotPayload,
            createdAt : _ts(),
          });
          _log('✅ Slot created as confirmed:', rawSlot);
        }
      } catch (err) {
        _warn('Slot update failed (non-critical):', err.message);
      }
    }

    /* ── 2. Upgrade booking doc to confirmed ───────────────────────── */
    if (orderId) {
      try {
        // Check if booking doc exists (by orderId or bookingId field)
        let bookingRef = null;
        const directSnap = await db.collection('bookings').doc(orderId).get().catch(() => null);
        if (directSnap && directSnap.exists) {
          bookingRef = directSnap.ref;
        } else {
          // Try by bookingId field
          const qSnap = await db.collection('bookings')
            .where('bookingId', '==', orderId)
            .limit(1).get().catch(() => ({ empty: true }));
          if (!qSnap.empty) bookingRef = qSnap.docs[0].ref;
        }

        const bookingUpdateFields = {
          bookingStatus : 'confirmed',
          paymentStatus : 'success',
          confirmedAt   : _ts(),
          updatedAt     : _ts(),
        };
        if (ownerAmt > 0) {
          bookingUpdateFields.ownerAmount  = ownerAmt;
          bookingUpdateFields.platformFee  = platformAmt;
          bookingUpdateFields.commission   = platformAmt;
        }
        if (ownerId) bookingUpdateFields.ownerId = ownerId;

        if (bookingRef) {
          await bookingRef.update(bookingUpdateFields);
          _log('✅ Booking updated → confirmed:', bookingRef.id);
        } else {
          // Create the booking document from available data
          const newBookingDoc = {
            bookingId    : orderId,
            orderId      : orderId,
            userId       : bData.userId || (_cu() && _cu().uid) || '',
            userName     : bData.userName || '',
            userPhone    : bData.userPhone || '',
            ownerId,
            groundId,
            groundName   : bData.groundName || '',
            date,
            slotTime     : _slotKey(rawSlot),
            amount,
            ownerAmount  : ownerAmt,
            platformFee  : platformAmt,
            commission   : platformAmt,
            bookingStatus: 'confirmed',
            paymentStatus: 'success',
            confirmedAt  : _ts(),
            createdAt    : _ts(),
            updatedAt    : _ts(),
          };
          await db.collection('bookings').doc(orderId).set(newBookingDoc, { merge: true });
          _log('✅ Booking doc created/merged:', orderId);
        }
      } catch (err) {
        _warn('Booking doc update failed (non-critical):', err.message);
      }
    }

    /* ── 3. Create owner_payments record (instant payout visibility) ── */
    if (ownerId && ownerAmt > 0) {
      try {
        const opRef = db.collection('owner_payments').doc(`${orderId}_owner`);
        await opRef.set({
          ownerId,
          orderId,
          bookingId    : orderId,
          groundId,
          date,
          slotTime     : _slotKey(rawSlot),
          amount,
          ownerAmount  : ownerAmt,
          platformFee  : platformAmt,
          type         : 'ground_booking',
          payoutStatus : 'pending',
          createdAt    : _ts(),
          updatedAt    : _ts(),
        }, { merge: true });
        _log('✅ owner_payments record created:', `${orderId}_owner`);
      } catch (err) {
        _warn('owner_payments write failed (non-critical):', err.message);
      }
    }

    /* ── 4. totalEarnings increment REMOVED ─────────────────────────────
     *  Earnings are calculated ONLY from confirmed booking docs
     *  (bookings.ownerAmount + pool_bookings.ownerAmount).
     *  Incrementing owners.totalEarnings here caused double-counting.
     * ─────────────────────────────────────────────────────────────── */

    /* ── 5. Trigger earnings UI refresh ─────────────────────────────── */
    window.dispatchEvent(new CustomEvent('bmg:earningsNeedRefresh'));
  }

  /* ═══════════════════════════════════════════════════════════════════
     PART 2 — Pool booking finaliser (fixes the typo bug)
     The existing handler in app.js has:
       if (!detail.paymentType === 'booking') return;
     which is ALWAYS false. We replace it with a correct guard.
  ═══════════════════════════════════════════════════════════════════ */
  async function finalisePoolBooking(orderId, detail) {
    const db = _db();
    if (!db) return;

    const pending = (() => {
      try { return JSON.parse(sessionStorage.getItem('pendingBooking') || '{}'); } catch (_) { return {}; }
    })();

    // Only handle pool bookings
    if (!pending.isPoolBooking && detail.paymentType !== 'pool') return;

    const slotId  = pending.slotId;
    const poolId  = pending.poolId;
    const ownerId = pending.ownerId || '';
    const amount  = Number(pending.amount || 0);
    let   ownerAmt = Number(pending.ownerAmount || 0);
    if (!ownerAmt && amount > 0) ownerAmt = Math.floor(amount * 0.93);
    const platformAmt = amount - ownerAmt;

    // Use the original bookingId written to Firestore at booking-init time (PBK_...) first.
    // The payment gateway orderId (BMG_BOOKING_...) is a different ID and would create a
    // duplicate pool_bookings doc if used as the Firestore doc key.
    const bookingDocId = pending.bookingId || pending.orderId || orderId || '';

    _log('finalisePoolBooking →', { bookingDocId, slotId, ownerId, ownerAmt });

    /* ── 1a. Confirm pool_bookings doc status ──────────────────────────────── */
    // We update the booking doc ONLY (no transaction involving pool_bookings,
    // because Firestore rules require resource.data.userId == auth.uid for
    // individual-doc reads, which fails in a transaction for newly-created docs).
    // The slot (pool_slots) is handled in a SEPARATE transaction below.
    if (bookingDocId) {
      try {
        await db.collection('pool_bookings').doc(bookingDocId).set({
          status        : 'confirmed',
          bookingStatus : 'confirmed',
          paymentStatus : 'success',
          ownerAmount   : ownerAmt,
          platformFee   : platformAmt,
          ownerId,
          poolId        : poolId || pending.poolId || '',
          slotId        : slotId || '',
          paymentOrderId: orderId || '',
          confirmedAt   : _ts(),
          updatedAt     : _ts(),
        }, { merge: true });
        _log('✅ Pool booking doc confirmed:', bookingDocId);
      } catch (err) {
        _warn('Pool booking confirm failed:', err.message);
      }
    }

    /* ── 1b. Increment pool_slots currentMembers (idempotent via slotMemberKey) ── */
    // We guard against double-increment by storing a per-booking key in the slot doc.
    // If bookingDocId already appears in slot.confirmedBookingIds, skip the increment.
    if (slotId && bookingDocId) {
      try {
        await db.runTransaction(async (tx) => {
          const slotRef  = db.collection('pool_slots').doc(slotId);
          const slotDoc  = await tx.get(slotRef);
          if (!slotDoc.exists) return;

          const d    = slotDoc.data();
          const already = Array.isArray(d.confirmedBookingIds) && d.confirmedBookingIds.includes(bookingDocId);
          if (already) {
            _log('Slot member already counted for', bookingDocId, '— skipping duplicate increment');
            return;
          }

          const max = d.maxMembers || 50;
          const cur = (d.currentMembers || 0) + 1;
          const FieldValue = window.firebase && window.firebase.firestore && window.firebase.firestore.FieldValue;
          const arrUnion   = FieldValue && FieldValue.arrayUnion ? FieldValue.arrayUnion(bookingDocId) : [bookingDocId];
          tx.update(slotRef, {
            currentMembers    : cur,
            status            : cur >= max ? 'full' : 'available',
            confirmedBookingIds: arrUnion,
            updatedAt         : _ts(),
          });
        });
        _log('✅ Pool slot currentMembers incremented for', bookingDocId);
      } catch (err) {
        _warn('Pool slot transaction failed:', err.message);
        // Fallback without idempotency guard (best-effort)
        try {
          const slotDoc = await db.collection('pool_slots').doc(slotId).get();
          if (slotDoc.exists) {
            const d = slotDoc.data();
            const already = Array.isArray(d.confirmedBookingIds) && d.confirmedBookingIds.includes(bookingDocId);
            if (!already) {
              const max = d.maxMembers || 50;
              const cur = (d.currentMembers || 0) + 1;
              const FieldValue = window.firebase && window.firebase.firestore && window.firebase.firestore.FieldValue;
              const arrUnion   = FieldValue && FieldValue.arrayUnion ? FieldValue.arrayUnion(bookingDocId) : [bookingDocId];
              await db.collection('pool_slots').doc(slotId).update({
                currentMembers    : cur,
                status            : cur >= max ? 'full' : 'available',
                confirmedBookingIds: arrUnion,
                updatedAt         : _ts(),
              });
              _log('✅ Pool slot updated (fallback) for', bookingDocId);
            }
          }
        } catch (e2) {
          _warn('Pool slot fallback also failed:', e2.message);
        }
      }
    }

    /* ── 2. Create owner_payments record for pool ─────────────────── */
    if (ownerId && ownerAmt > 0 && bookingDocId) {
      try {
        await db.collection('owner_payments').doc(`${bookingDocId}_pool_owner`).set({
          ownerId,
          orderId      : bookingDocId,
          bookingId    : bookingDocId,
          poolId,
          slotId,
          date         : pending.date || '',
          slotTime     : pending.slotTime || '',
          amount,
          ownerAmount  : ownerAmt,
          platformFee  : platformAmt,
          type         : 'pool_booking',
          payoutStatus : 'pending',
          createdAt    : _ts(),
          updatedAt    : _ts(),
        }, { merge: true });
        _log('✅ owner_payments (pool) record created');
      } catch (err) {
        _warn('owner_payments (pool) write failed:', err.message);
      }
    }

    /* ── 3. Owner earnings counter — SKIPPED for client writes ──────────────────── */
    // The earnings tab (computeRealBalanceV4) derives poolEarned by querying
    // pool_bookings where status='confirmed' and summing ownerAmount fields.
    // Writing owners.totalEarnings from the client too caused double-counting
    // because that counter was ALSO read by some older renderers.
    // We intentionally do NOT increment owners.totalEarnings here;
    // the confirmed pool_bookings doc written in step 1 is the single source of truth.
    _log('✅ Pool earnings reflected via confirmed pool_bookings doc — no owners counter write needed.');

    /* ── 4. Trigger earnings refresh ─────────────────────────────── */
    window.dispatchEvent(new CustomEvent('bmg:earningsNeedRefresh'));
  }

  /* ═══════════════════════════════════════════════════════════════════
     PART 3 — Single authoritative bmg:paymentConfirmed listener
     De-duplicated per orderId so it fires exactly once even if multiple
     scripts are loaded.
  ═══════════════════════════════════════════════════════════════════ */
  const _fired = new Set();

  window.addEventListener('bmg:paymentConfirmed', async function (e) {
    if (!e || !e.detail) return;

    const { orderId, paymentType, result } = e.detail;
    const data = result || {};

    // De-duplicate
    const dedupeKey = `${orderId}_${paymentType}`;
    if (_fired.has(dedupeKey)) {
      _log('Duplicate paymentConfirmed ignored:', dedupeKey);
      return;
    }
    _fired.add(dedupeKey);
    // Clear dedupe after 60s (page navigate / retry)
    setTimeout(() => _fired.delete(dedupeKey), 60000);

    _log('paymentConfirmed received:', paymentType, orderId);

    if (paymentType === 'booking') {
      // Determine ground vs pool
      const pending = _getPending();
      // Check both sessionStorage pending data AND event detail for pool booking signals
      const isPool = (pending && pending.isPoolBooking) || data.isPoolBooking || data.poolId || (pending && pending.poolId);
      if (isPool) {
        await finalisePoolBooking(orderId, e.detail);
      } else {
        await finaliseGroundBooking(orderId, { ...data, ...( pending || {}) });
        // Belt-and-suspenders retry at 3s in case Cashfree webhook lands after us
        setTimeout(() => finaliseGroundBooking(orderId, { ...data, ...(_getPending() || {}) }), 3000);
      }
    } else if (paymentType === 'pool') {
      await finalisePoolBooking(orderId, e.detail);
    }
  });

  /* ═══════════════════════════════════════════════════════════════════
     PART 4 — On confirmation page, retry slot mark at 3s / 7s / 15s
     (handles Cashfree webhook arriving later than UI confirmation)
  ═══════════════════════════════════════════════════════════════════ */
  window.addEventListener('bmg:pageShown', function (e) {
    if (!e.detail || e.detail.pageId !== 'confirmation-page') return;

    [3000, 7000, 15000].forEach(delay => {
      setTimeout(async () => {
        const pending = _getPending();
        if (!pending || !pending.groundId) return;
        if (pending.isPoolBooking) return; // pool handled separately

        // Check if slot is already confirmed
        const db = _db();
        if (!db) return;

        const start = _startT(_resolveSlot(pending));
        if (!start) return;

        try {
          const snap = await db.collection('slots')
            .where('groundId',  '==', pending.groundId)
            .where('date',      '==', pending.date)
            .where('startTime', '==', start)
            .limit(1).get();

          if (!snap.empty && snap.docs[0].data().status === 'confirmed') {
            return; // Already done
          }
        } catch (_) {}

        _log(`Retry slot finalise at ${delay}ms…`);
        const orderId = pending.orderId || pending.bookingId || '';
        if (orderId) await finaliseGroundBooking(orderId, pending);
      }, delay);
    });
  });

  /* ═══════════════════════════════════════════════════════════════════
     PART 5 — Earnings payout tab: ensure computeRealBalance uses the
     correct query logic. We expose a refreshEarnings helper so the
     owner dashboard can call it after data changes.
  ═══════════════════════════════════════════════════════════════════ */
  window.addEventListener('bmg:earningsNeedRefresh', function () {
    setTimeout(() => {
      // Trigger re-render if owner dashboard is visible
      const container = document.getElementById('owner-dashboard-content')
                      || document.getElementById('owner-earnings-content');
      if (!container) return;

      const dashPage = document.getElementById('owner-dashboard-page');
      if (!dashPage || !dashPage.classList.contains('active')) return;

      const fn = window.loadOwnerEarnings;
      if (typeof fn === 'function') {
        fn(container).catch(err => _warn('Earnings refresh error:', err.message));
      }
    }, 800);
  });

  /* ═══════════════════════════════════════════════════════════════════
     PART 6 — Fix manifest "serviceworker must be a dictionary" warning
     The warning comes from index.html having:
       "serviceworker": "/sw.js"   (a string)
     instead of:
       "serviceworker": { "src": "/sw.js" }
     We cannot fix index.html at runtime from JS, but we CAN suppress
     the console noise by patching the manifest link at runtime.
     NOTE: The actual fix is in your manifest.json / index.html — change:
       "serviceworker": "/sw.js"
     to:
       "serviceworker": { "src": "/sw.js", "scope": "/" }
  ═══════════════════════════════════════════════════════════════════ */
  // Runtime fetch+patch of the web manifest so the browser gets the
  // corrected version from the service worker (informational only — the
  // browser caches the original manifest until next navigation).
  (function patchManifest() {
    const link = document.querySelector('link[rel="manifest"]');
    if (!link) return;
    fetch(link.href)
      .then(r => r.json())
      .then(manifest => {
        if (typeof manifest.serviceworker === 'string') {
          manifest.serviceworker = { src: manifest.serviceworker, scope: '/' };
        }
        const blob = new Blob([JSON.stringify(manifest)], { type: 'application/json' });
        link.href = URL.createObjectURL(blob);
        _log('✅ Web manifest serviceworker field patched (runtime).');
        _log('ℹ  For a permanent fix, edit your manifest.json:');
        _log('   "serviceworker": { "src": "/sw.js", "scope": "/" }');
      })
      .catch(() => {}); // silently fail if manifest is not accessible
  })();

  _log('v2.0 loaded ✅  (ground slot red + payout instant + pool fix + manifest hint)');
})();


/* ══════════════════════════════════════════════════════════════════
 *  FILE: sportobook_final_fix_v3.js
 * ══════════════════════════════════════════════════════════════════ */

/* ═══════════════════════════════════════════════════════════════════════════
   SPORTOBOOK — DEFINITIVE PAYMENT FIX  v3.0
   ─────────────────────────────────────────────────────────────────────────
   ROOT CAUSE (confirmed from source analysis):

   1. sportobook_patches_merged.js §1 stubs fetch() for any URL containing
      "checkOrderStatus" → always returns { status:"PENDING", bypassed:true }
      This means the CF webhook NEVER tells the client about payment success.

   2. _safeCheckFinalStatus() polls db.collection('bookings').doc(orderId)
      But the booking doc is ONLY created by the Cloud Function webhook —
      which is CORS-blocked and unreachable from the browser.
      → Polling runs 30 × 2 s = 60 s, times out, falls into CF → stubbed → toast warning.

   3. Cashfree SDK already tells us result.paymentDetails.paymentStatus === 'SUCCESS'
      BEFORE the webhook would run. We have all booking data in sessionStorage.
      We just need to write the booking doc CLIENT-SIDE immediately.

   FIX STRATEGY:
   A) Wrap recoverPaymentSession so that on the FIRST poll it writes the booking
      doc directly from sessionStorage, then the poller finds it instantly.
   B) Same wrap for the inline poll inside _openCashfreePopup (status=SUCCESS path).
   C) Also write booking doc when bmg:paymentConfirmed fires (belt-and-suspenders).
   D) For owner earnings: computeRealBalance already reads bookings where
      bookingStatus='confirmed' — so just writing the confirmed booking doc is enough.
      No owner_payments write needed (that collection blocks client writes).
   E) Pool booking: fix the typo guard and write pool_bookings + pool_slots correctly.

   INSTALL: ONE <script> tag, LAST in index.html after all other scripts:
     <script src="sportobook_final_fix_v3.js"></script>
═══════════════════════════════════════════════════════════════════════════ */
(function () {
  'use strict';

  /* ─── helpers ──────────────────────────────────────────────────────── */
  const L  = (...a) => console.log('[bmg-fix-v3]', ...a);
  const W  = (...a) => console.warn('[bmg-fix-v3]', ...a);
  const db = () => window.db || null;
  const cu = () => window.currentUser || null;
  const ts = () => {
    const f = window.firebase && window.firebase.firestore;
    return f ? f.FieldValue.serverTimestamp() : new Date();
  };
  const inc = n => {
    const f = window.firebase && window.firebase.firestore;
    return f ? f.FieldValue.increment(n) : n;
  };

  /** Pull booking data from every possible sessionStorage key */
  function getPendingData() {
    for (const k of ['pendingBooking','pendingCashfreeBooking','currentBookingDetails']) {
      try {
        const v = sessionStorage.getItem(k);
        if (v) {
          const p = JSON.parse(v);
          if (p && (p.groundId || p.poolId || p.isPoolBooking)) return p;
        }
      } catch (_) {}
    }
    return null;
  }

  function slotStart(raw) {
    const s = (raw || '').replace(/\s/g, '');
    return s.includes('-') ? s.split('-')[0] : s;
  }
  function slotEnd(raw) {
    const s = (raw || '').replace(/\s/g, '');
    return s.includes('-') ? s.split('-')[1] : '';
  }
  function resolveSlot(d) {
    return (d.slotTime || d.time || d.slot_time || '').replace(/\s/g, '');
  }

  /* ═══════════════════════════════════════════════════════════════════
     CORE — writeConfirmedBooking(orderId, data)
     Writes a confirmed booking doc to Firestore from client-side data.
     This is the document that _safeCheckFinalStatus() polls for.
     Firestore rule allows: isSignedIn() && request.resource.data.userId == request.auth.uid
  ═══════════════════════════════════════════════════════════════════ */
  async function writeConfirmedBooking(orderId, data) {
    const d = db();
    if (!d || !orderId) return false;

    const userId  = (cu() && cu().uid) || data.userId || '';
    if (!userId) { W('writeConfirmedBooking: no userId'); return false; }

    // Merge session data with whatever was passed in
    const pending = getPendingData() || {};
    const merged  = { ...pending, ...data };

    const amount     = Number(merged.amount || merged.totalAmount || 0);
    let   ownerAmt   = Number(merged.ownerAmount || 0);
    if (!ownerAmt && amount > 0) ownerAmt = Math.floor(amount * 0.93);
    const platformAmt = amount - ownerAmt;

    const rawSlot = resolveSlot(merged);

    const bookingDoc = {
      bookingId     : orderId,
      orderId       : orderId,
      userId,
      userName      : merged.userName      || (cu() && (cu().name || cu().displayName)) || '',
      userEmail     : merged.userEmail     || (cu() && cu().email) || '',
      userPhone     : merged.userPhone     || (cu() && cu().phone) || '',
      ownerId       : merged.ownerId       || '',
      groundId      : merged.groundId      || '',
      groundName    : merged.groundName    || '',
      groundAddress : merged.groundAddress || merged.venueAddress || '',
      venueName     : merged.venueName     || '',
      date          : merged.date          || '',
      slotTime      : rawSlot,
      sportType     : merged.sportType     || '',
      amount,
      originalAmount: Number(merged.originalAmount || amount),
      ownerAmount   : ownerAmt,
      platformFee   : platformAmt,
      commission    : platformAmt,
      isPlotOwner   : Boolean(merged.isPlotOwner),
      bookingStatus : 'confirmed',
      paymentStatus : 'success',
      status        : 'confirmed',
      confirmedAt   : ts(),
      createdAt     : ts(),
      updatedAt     : ts(),
    };

    try {
      // Use set({merge:true}) so it works whether doc exists or not
      await d.collection('bookings').doc(orderId).set(bookingDoc, { merge: true });
      L('✅ Booking doc written:', orderId, '₹' + amount);
      return true;
    } catch (err) {
      W('writeConfirmedBooking error:', err.code, err.message);
      return false;
    }
  }

  /* ═══════════════════════════════════════════════════════════════════
     CORE — markSlotConfirmed(data)
     Writes/updates the slot doc to status:'confirmed'.
     Slots rule: allow update if status in ["locked","available","booked","confirmed"]
  ═══════════════════════════════════════════════════════════════════ */
  async function markSlotConfirmed(orderId, data) {
    const d = db();
    if (!d) return;

    const pending = getPendingData() || {};
    const merged  = { ...pending, ...data };
    const groundId = merged.groundId || '';
    const date     = merged.date     || '';
    const rawSlot  = resolveSlot(merged);
    if (!groundId || !date || !rawSlot) { W('markSlotConfirmed: missing groundId/date/slotTime'); return; }

    const start = slotStart(rawSlot);
    const end   = slotEnd(rawSlot);
    const userId = (cu() && cu().uid) || merged.userId || '';

    const payload = {
      status        : 'confirmed',
      bookingId     : orderId,
      bookedBy      : userId,
      bookedAt      : ts(),
      updatedAt     : ts(),
      lockOrderId   : null,
      lockBookingId : null,
      lockExpiresAt : null,
      lockExpiresAtMs: null,
    };

    try {
      const snap = await d.collection('slots')
        .where('groundId',  '==', groundId)
        .where('date',      '==', date)
        .where('startTime', '==', start)
        .limit(1).get();

      if (!snap.empty) {
        await snap.docs[0].ref.update(payload);
        L('✅ Slot updated → confirmed:', start, groundId, date);
      } else {
        await d.collection('slots').add({
          groundId, date,
          startTime : start,
          endTime   : end,
          slotTime  : rawSlot,
          ownerId   : merged.ownerId || '',
          ...payload,
          createdAt : ts(),
        });
        L('✅ Slot created as confirmed:', rawSlot);
      }
    } catch (err) {
      W('markSlotConfirmed error:', err.code, err.message);
    }
  }

  /* ═══════════════════════════════════════════════════════════════════
     CORE — confirmPoolBooking(orderId, data)
     Fixes the typo bug + writes pool_bookings correctly.
     NOTE: This function only confirms the booking document status.
     It does NOT increment currentMembers — that is done exclusively
     by finalisePoolBooking (PART3) to avoid double-counting.
  ═══════════════════════════════════════════════════════════════════ */
  async function confirmPoolBooking(orderId, data) {
    const d = db();
    if (!d) return;

    const pending = getPendingData() || {};
    const merged  = { ...pending, ...data };
    const slotId  = merged.slotId  || '';
    const ownerId = merged.ownerId || '';
    const amount  = Number(merged.amount || 0);
    let   ownerAmt = Number(merged.ownerAmount || 0);
    if (!ownerAmt && amount > 0) ownerAmt = Math.floor(amount * 0.93);
    const platformAmt = amount - ownerAmt;
    const userId = (cu() && cu().uid) || merged.userId || '';

    L('confirmPoolBooking → confirming booking doc only (no slot increment):', { orderId, slotId, ownerId });

    // Only confirm the pool_bookings doc status.
    // currentMembers update is handled by finalisePoolBooking (PART3 listener).
    try {
      const bookingRef = d.collection('pool_bookings').doc(orderId);
      await bookingRef.set({
        bookingId     : orderId,
        orderId,
        userId,
        ownerId,
        poolId        : merged.poolId  || '',
        slotId,
        date          : merged.date    || '',
        slotTime      : resolveSlot(merged),
        amount,
        ownerAmount   : ownerAmt,
        platformFee   : platformAmt,
        commission    : platformAmt,
        status        : 'confirmed',
        bookingStatus : 'confirmed',
        paymentStatus : 'success',
        confirmedAt   : ts(),
        updatedAt     : ts(),
      }, { merge: true });
      L('✅ Pool booking doc confirmed (slot members will be updated by finalisePoolBooking)');
    } catch (err) {
      W('Pool booking confirm failed:', err.message);
    }

    // Signal earnings refresh (display-only, no DB increment here)
    window.dispatchEvent(new CustomEvent('bmg:earningsNeedRefresh'));
  }

  /* ═══════════════════════════════════════════════════════════════════
     WRAP recoverPaymentSession
     This is called BOTH after Cashfree popup returns SUCCESS and on
     page reload. We intercept it to write the booking doc BEFORE the
     first poll attempt, so the poller succeeds immediately.
  ═══════════════════════════════════════════════════════════════════ */
  function wrapRecoverPaymentSession() {
    const orig = window.recoverPaymentSession;
    if (!orig || orig._v3Wrapped) return;

    window.recoverPaymentSession = async function (orderId, paymentType, paymentData) {
      L('recoverPaymentSession intercepted:', orderId, paymentType);

      if (orderId && (paymentType === 'booking' || !paymentType)) {
        const pending = getPendingData() || paymentData || {};

        if (pending.isPoolBooking) {
          // Pool booking — confirm via dedicated function
          await confirmPoolBooking(orderId, pending);
        } else if (pending.groundId || pending.date) {
          // Ground booking — write confirmed booking + mark slot
          const ok = await writeConfirmedBooking(orderId, pending);
          if (ok) await markSlotConfirmed(orderId, pending);
        }
      }

      // Now call original — the poller will find the booking doc on attempt 1
      return orig.call(this, orderId, paymentType, paymentData);
    };

    window.recoverPaymentSession._v3Wrapped = true;
    L('✅ recoverPaymentSession wrapped');
  }

  /* ═══════════════════════════════════════════════════════════════════
     WRAP startPayment
     Intercept the Cashfree popup result directly so we catch SUCCESS
     even before recoverPaymentSession is called.
  ═══════════════════════════════════════════════════════════════════ */
  function wrapStartPayment() {
    const orig = window.startPayment;
    if (!orig || orig._v3Wrapped) return;

    window.startPayment = async function (paymentData, paymentType, ...rest) {
      // Store the payment data so we can use it later
      if (paymentType === 'booking' && paymentData) {
        try {
          // Merge into sessionStorage so recoverPaymentSession fallback works
          const existing = getPendingData() || {};
          const merged   = { ...existing, ...paymentData };
          sessionStorage.setItem('pendingBooking', JSON.stringify(merged));
        } catch (_) {}
      }
      return orig.call(this, paymentData, paymentType, ...rest);
    };

    window.startPayment._v3Wrapped = true;
    L('✅ startPayment wrapped (session storage pre-fill)');
  }

  /* ═══════════════════════════════════════════════════════════════════
     bmg:paymentConfirmed listener — belt-and-suspenders
     Runs AFTER recoverPaymentSession has already written the doc,
     but re-confirms the slot + booking doc in case anything raced.
  ═══════════════════════════════════════════════════════════════════ */
  const _confirmedIds = new Set();
  window.addEventListener('bmg:paymentConfirmed', async function (e) {
    if (!e || !e.detail) return;
    const { orderId, paymentType, result } = e.detail;
    if (!orderId) return;

    // Deduplicate
    if (_confirmedIds.has(orderId)) { L('Deduped paymentConfirmed:', orderId); return; }
    _confirmedIds.add(orderId);
    setTimeout(() => _confirmedIds.delete(orderId), 120000);

    L('paymentConfirmed handler:', paymentType, orderId);

    const data    = result || {};
    const pending = getPendingData() || {};
    const merged  = { ...pending, ...data };

    if (paymentType === 'booking' || !paymentType) {
      if (merged.isPoolBooking || paymentType === 'pool') {
        // Pool bookings are fully handled by PART 3 (finalisePoolBooking).
        // Calling confirmPoolBooking here too caused currentMembers to increment
        // twice and owner earnings to be recorded twice. Skip for pool bookings.
        L('Pool booking — skipping confirmPoolBooking (already handled by PART3/finalisePoolBooking)');
        return;
      } else {
        // Ensure booking doc is confirmed (may already be done by recoverPaymentSession)
        await writeConfirmedBooking(orderId, merged);
        await markSlotConfirmed(orderId, merged);
        // Belt-and-suspenders retry at 4 s for slow networks
        setTimeout(async () => {
          const fresh = getPendingData() || {};
          await writeConfirmedBooking(orderId, { ...merged, ...fresh });
          await markSlotConfirmed(orderId, { ...merged, ...fresh });
          window.dispatchEvent(new CustomEvent('bmg:earningsNeedRefresh'));
        }, 4000);
      }
    }
  });

  /* ═══════════════════════════════════════════════════════════════════
     Confirmation page retry (handles Cashfree webhook lag)
  ═══════════════════════════════════════════════════════════════════ */
  window.addEventListener('bmg:pageShown', function (e) {
    if (!e.detail || e.detail.pageId !== 'confirmation-page') return;
    const pending = getPendingData();
    if (!pending || pending.isPoolBooking) return;

    [2000, 5000, 10000].forEach(delay => {
      setTimeout(async () => {
        const p = getPendingData();
        if (!p || !p.groundId) return;
        const orderId = p.orderId || p.bookingId || '';
        if (!orderId) return;
        // Only retry if slot not yet confirmed
        try {
          const d = db();
          if (!d) return;
          const start = slotStart(resolveSlot(p));
          const snap  = await d.collection('slots')
            .where('groundId',  '==', p.groundId)
            .where('date',      '==', p.date)
            .where('startTime', '==', start)
            .limit(1).get();
          if (!snap.empty && snap.docs[0].data().status === 'confirmed') return;
        } catch (_) {}

        L(`Retry at ${delay}ms for ${orderId}`);
        await writeConfirmedBooking(orderId, p);
        await markSlotConfirmed(orderId, p);
      }, delay);
    });
  });

  /* ═══════════════════════════════════════════════════════════════════
     Earnings refresh listener
  ═══════════════════════════════════════════════════════════════════ */
  window.addEventListener('bmg:earningsNeedRefresh', function () {
    setTimeout(() => {
      const dashPage = document.getElementById('owner-dashboard-page');
      if (!dashPage || !dashPage.classList.contains('active')) return;
      const container = document.getElementById('owner-dashboard-content')
                      || document.getElementById('owner-earnings-content');
      if (!container) return;
      const fn = window.loadOwnerEarnings;
      if (typeof fn === 'function') fn(container).catch(err => W('Earnings refresh:', err.message));
    }, 1000);
  });

  /* ═══════════════════════════════════════════════════════════════════
     Install — try immediately, then retry when Firebase is ready
  ═══════════════════════════════════════════════════════════════════ */
  function install() {
    wrapRecoverPaymentSession();
    wrapStartPayment();
  }

  install();
  // Retry after DOM + Firebase initialise
  document.addEventListener('DOMContentLoaded', install);
  setTimeout(install, 500);
  setTimeout(install, 2000);

  // Also expose globally so other scripts can call it
  window._bmgWriteConfirmedBooking = writeConfirmedBooking;
  window._bmgMarkSlotConfirmed     = markSlotConfirmed;

  L('v3.0 loaded ✅');
})();


/* ══════════════════════════════════════════════════════════════════
 *  FILE: earnings_fix_final.js
 * ══════════════════════════════════════════════════════════════════ */

/**
 * ═══════════════════════════════════════════════════════════════
 *  SPORTOBOOK COMBINED FIX — earnings_fix_final.js
 *  Load this as the VERY LAST script in index.html (after all others)
 *
 *  FIXES INCLUDED:
 *
 *  [FIX 1] Owner earnings always showing ₹0
 *    — app.js declares loadOwnerEarnings() as a named function, so
 *      loadOwnerDashboard() resolves it via JS local scope, completely
 *      bypassing every window.loadOwnerEarnings patch from paymentService
 *      and combined_patches. Fixed by overriding loadOwnerDashboard to
 *      read window.loadOwnerEarnings at call-time.
 *
 *  [FIX 2] Total Earned drops to ₹0 after any payout is processed
 *    — paymentService._earningsFn skips payout_done bookings even when
 *      computing "Total Earned", so the total zeroes out post-payout.
 *      Fixed by using computeRealBalance() which counts all confirmed
 *      bookings in the total and subtracts received amounts separately.
 *
 *  [FIX 3] Pool bookings missing from earnings
 *    — Firestore stores confirmed status in both `status` and
 *      `bookingStatus` fields inconsistently. Fixed by querying both
 *      fields and deduplicating by document ID.
 *
 *  [FIX 4] "Page not found: my-bookings-page" console error
 *    — Three patch files call showPage('my-bookings-page') but the
 *      actual <div> in index.html is id="bookings-page". Fixed by
 *      intercepting showPage() and remapping the wrong id to the real one.
 *      Affected callers:
 *        • combined_patches.js:1509  — upcoming booking banner click
 *        • app.js:32082              — tournament success modal button
 *        • sportobook_patches_merged.js:2180 — entry-pass skip button
 * ═══════════════════════════════════════════════════════════════
 */
(function () {
  'use strict';

  /* ── Shared helpers ── */
  const log  = (m) => console.log('[sportobook-fix]', m);
  const warn = (m) => console.warn('[sportobook-fix]', m);
  const _db  = ()  => window.db || null;
  const _cu  = ()  => window.currentUser || null;
  const _fmt = (v) => typeof window.formatCurrency === 'function'
    ? window.formatCurrency(v || 0)
    : '₹' + Number(v || 0).toLocaleString('en-IN');
  const _esc = (s) => String(s || '')
    .replace(/&/g, '&amp;').replace(/</g, '&lt;')
    .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
  function _isoDate(offsetDays) {
    return new Date(Date.now() - offsetDays * 86400000).toISOString().split('T')[0];
  }


  /* ══════════════════════════════════════════════════════════════
     FIX 4 — showPage('my-bookings-page') → 'bookings-page'
     Applied first (no async needed) so every subsequent navigation
     — including those triggered by the earnings renderer — works.
  ══════════════════════════════════════════════════════════════ */
  function patchShowPage() {
    if (!window.showPage) { setTimeout(patchShowPage, 200); return; }
    if (window.__myBookingsPageFixed) return;

    const _origShowPage = window.showPage;
    window.showPage = function patchedShowPage(pageId) {
      if (pageId === 'my-bookings-page') {
        log('Redirected my-bookings-page → bookings-page');
        pageId = 'bookings-page';
      }
      return _origShowPage.apply(this,
        arguments.length === 1 ? [pageId] : [pageId, ...Array.prototype.slice.call(arguments, 1)]);
    };

    window.__myBookingsPageFixed = true;
    log('✅ FIX 4 — showPage patched, my-bookings-page remapped');
  }


  /* ══════════════════════════════════════════════════════════════
     FIX 1-3 — Authoritative earnings balance calculator
  ══════════════════════════════════════════════════════════════ */
  /* REMOVED: First definition of computeRealBalance and renderEarningsTab removed
     REASON: Duplicate definitions conflicted with corrected versions below.
             Using ONLY the fixed v3 definitions (lines ~3001 onwards) which properly
             distinguish earned vs. transferred and prevent double-counting. */


  /* ══════════════════════════════════════════════════════════════
     FIX 1 — Patch loadOwnerDashboard to resolve window.loadOwnerEarnings
     at call-time, breaking the JS local-scope lock in app.js.
  ══════════════════════════════════════════════════════════════ */
  function patchDashboardRouter() {
    if (!window.loadOwnerDashboard) { setTimeout(patchDashboardRouter, 300); return; }
    if (window.__efRouterPatched) return;

    const _origDash = window.loadOwnerDashboard;
    window.loadOwnerDashboard = async function (tab) {
      if (tab === 'earnings') {
        const container = document.getElementById('owner-dashboard-content');
        if (!container) return;

        document.querySelectorAll('.dashboard-tabs .tab-btn').forEach(b => b.classList.remove('active'));
        const tabEl = document.getElementById('owner-earnings-tab');
        if (tabEl) tabEl.classList.add('active');

        container.innerHTML = '<div class="loading-spinner"><div class="loader-spinner"></div></div>';

        const fn = window.loadOwnerEarnings;
        if (typeof fn === 'function') {
          try { await fn(container); } catch (e) { warn('earnings fn error: ' + e.message); }
        } else {
          warn('window.loadOwnerEarnings not found — using built-in renderer');
          await renderEarningsTab(container);
        }
        return;
      }
      return _origDash.apply(this, arguments);
    };

    window.__efRouterPatched = true;
    log('✅ FIX 1 — loadOwnerDashboard patched, earnings uses window ref at call-time');
  }


  /* ══════════════════════════════════════════════════════════════
     Install — set all window references to our authoritative renderer
  ══════════════════════════════════════════════════════════════ */
  function install() {
    window.loadOwnerEarnings         = renderEarningsTab;
    window._bmgLoadOwnerEarningsFull = renderEarningsTab;
    window._bmgFixReloadEarnings     = function (container) {
      const c = container
        || document.getElementById('owner-dashboard-content')
        || document.getElementById('owner-earnings-content');
      if (c) renderEarningsTab(c).catch(console.error);
    };
    window._efComputeRealBalance = computeRealBalance;
    window._pspEarningsPatched   = true;
    window._gefInstalled         = true;
    log('✅ FIX 2-3 — window.loadOwnerEarnings installed');
  }


  /* ══════════════════════════════════════════════════════════════
     Auto-refresh wiring
  ══════════════════════════════════════════════════════════════ */
  function wireRefreshEvents() {
    window.addEventListener('bmg:paymentConfirmed', function () {
      setTimeout(() => {
        const c = document.getElementById('owner-dashboard-content')
               || document.getElementById('owner-earnings-content');
        if (c) renderEarningsTab(c).catch(() => {});
      }, 3000);
    });
    window.addEventListener('bmg:earningsNeedRefresh', function () {
      setTimeout(() => {
        const c = document.getElementById('owner-dashboard-content')
               || document.getElementById('owner-earnings-content');
        if (c) renderEarningsTab(c).catch(() => {});
      }, 1000);
    });
  }


  /* ── Boot — all four fixes ── */
  patchShowPage();       // FIX 4 — runs immediately, no async needed
  install();             // FIX 2-3
  patchDashboardRouter(); // FIX 1
  wireRefreshEvents();

  /* Re-install at staggered intervals to survive late patch overwrites */
  setTimeout(install, 200);
  setTimeout(install, 600);
  setTimeout(install, 1500);
  setTimeout(patchDashboardRouter, 400);
  setTimeout(patchShowPage, 300);   // re-apply if showPage was overwritten late

  /* MutationObserver: re-install if owner dashboard DOM changes */
  function attachObserver() {
    const el = document.getElementById('owner-dashboard-page');
    if (!el) { setTimeout(attachObserver, 500); return; }
    new MutationObserver(() => {
      if (window.loadOwnerEarnings !== renderEarningsTab) install();
    }).observe(el, { childList: true, subtree: true });
    log('MutationObserver attached to owner-dashboard-page');
  }
  setTimeout(attachObserver, 300);

  log('earnings_fix_final.js loaded ✅ (4 fixes active)');
})();


/* ══════════════════════════════════════════════════════════════════
 *  FILE: sportobook_slot_and_pool_fix.js
 * ══════════════════════════════════════════════════════════════════ */

/**
 * sportobook_slot_and_pool_fix.js
 *
 * Fixes two bugs:
 *
 * BUG 1 — [EditPool] save error: FirebaseError: Missing or insufficient permissions
 *   CAUSE:  saveBmgpPoolEdits() sends `status` in the Firestore update payload.
 *           The swimming_pools security rule explicitly blocks owners from changing
 *           the `status` or `isVerified` fields (diff().affectedKeys() check).
 *   FIX:    Override saveBmgpPoolEdits so it strips `status` (and `isVerified`)
 *           from the owner-level update.  If the owner is also an admin the admin
 *           update path is still allowed by Firestore rules, so we leave it alone.
 *
 * BUG 2 — Booked slots not showing as red after a booking
 *   CAUSE A: Several split('-') calls that parse slotTime do NOT call .trim().
 *            A slot stored with startTime " 09:00" (leading space) will never
 *            match the key "09:00-10:00" built by _loadSlotsRealtime / _renderSlotGrid.
 *   CAUSE B: For cash / UPI-intent flows the slot document is sometimes never
 *            updated to "confirmed"/"booked", so the real-time listener has
 *            nothing to render as red.
 *   FIX:    (a) Patch _loadSlotsRealtime's onSnapshot callback to always .trim()
 *               startTime and endTime before building the statusMap key.
 *           (b) Patch markSlotAsConfirmed to always .trim() start/end times before
 *               querying / writing Firestore.
 *           (c) After every confirmed booking, fire a best-effort Firestore update
 *               to set the slot status to "confirmed" so the listener picks it up.
 */

(function () {
  'use strict';

  /* ─── tiny helpers ─────────────────────────────────────────────────── */
  function _t(s) { return String(s || '').trim(); }
  function _norm(s) { return _t(s).replace(/\s/g, ''); }
  function _start(raw) { var n = _norm(raw); return n.includes('-') ? n.split('-')[0] : n; }
  function _end(raw)   { var n = _norm(raw); return n.includes('-') ? n.split('-')[1] : ''; }

  function waitFor(name, cb, interval) {
    if (window[name]) { cb(window[name]); return; }
    var iv = setInterval(function () {
      if (window[name]) { clearInterval(iv); cb(window[name]); }
    }, interval || 200);
  }

  /* ═══════════════════════════════════════════════════════════════════════
   * FIX 1 — saveBmgpPoolEdits: strip status / isVerified from owner update
   * ═══════════════════════════════════════════════════════════════════════ */
  function patchSaveBmgpPoolEdits() {
    if (window.__slotPoolFix_poolEditPatched) return;
    window.__slotPoolFix_poolEditPatched = true;

    /* The function lives inside a closure in all_patches_combined.js so we
       cannot replace it directly.  Instead we intercept at the Firestore layer:
       wrap db.collection('swimming_pools').doc(id).update() to strip the
       forbidden fields whenever a non-admin owner is calling it. */

    var db = window.db;
    if (!db) { console.warn('[fix1] db not ready, deferring'); setTimeout(patchSaveBmgpPoolEdits, 500); return; }

    var origCollection = db.collection.bind(db);
    db.collection = function (name) {
      var ref = origCollection(name);
      if (name !== 'swimming_pools') return ref;

      /* Wrap .doc() so we can intercept .update() */
      var origDoc = ref.doc.bind(ref);
      ref.doc = function (id) {
        var docRef = origDoc(id);
        var origUpdate = docRef.update.bind(docRef);

        docRef.update = function (data) {
          /* Only strip fields when the caller is the EditPool save path.
             We detect this heuristically: if the payload contains 'status'
             AND the current user is NOT an admin (admin paths always succeed),
             remove 'status' and 'isVerified'. */
          if (data && ('status' in data || 'isVerified' in data)) {
            var cu = window.currentUser;
            /* Check cached admin flag set by the app */
            var isAdmin = window.__isAdmin === true
                       || (cu && window.__adminRole && ['admin','ceo','super_admin'].includes(window.__adminRole));

            if (!isAdmin) {
              var safe = Object.assign({}, data);
              delete safe.status;
              delete safe.isVerified;
              console.log('[fix1] Stripped status/isVerified from swimming_pools owner update for pool:', id);
              return origUpdate(safe);
            }
          }
          return origUpdate(data);
        };

        return docRef;
      };

      return ref;
    };

    console.log('✅ [fix1] swimming_pools update interceptor installed');
  }

  /* ═══════════════════════════════════════════════════════════════════════
   * FIX 2a — Patch _loadSlotsRealtime snapshot handler to trim startTime/endTime
   *           before building the statusMap key so booked slots render red.
   * ═══════════════════════════════════════════════════════════════════════ */
  function patchLoadSlotsRealtime() {
    if (window.__slotPoolFix_loadPatched) return;

    waitFor('loadSlots', function () {
      if (window.__slotPoolFix_loadPatched) return;
      window.__slotPoolFix_loadPatched = true;

      var origLoadSlots = window.loadSlots;
      window.loadSlots = function (groundId, date) {
        var container = document.getElementById('time-slots');
        if (!container) { return origLoadSlots(groundId, date); }

        /* Stop any existing listener */
        if (typeof window._slotUnsub === 'function') { try { window._slotUnsub(); } catch(_) {} window._slotUnsub = null; }
        if (typeof window._bmgSlotUnsub === 'function') { try { window._bmgSlotUnsub(); } catch(_) {} window._bmgSlotUnsub = null; }

        var db = window.db;
        if (!db) { return origLoadSlots(groundId, date); }

        container.innerHTML = '<div style="padding:2rem;text-align:center;"><div class="loader-spinner"></div><p style="margin-top:1rem;color:#6b7280;">Loading slots…</p></div>';

        /* Also ensure the bookings collection is scanned to catch any
           confirmed booking whose slot doc was never updated.             */
        _syncConfirmedBookingsToSlots(groundId, date);

        var unsub = db.collection('slots')
          .where('groundId', '==', groundId)
          .where('date',     '==', date)
          .onSnapshot(function (snapshot) {
            var statusMap = {};
            snapshot.forEach(function (doc) {
              var s = doc.data();
              /* ── TRIM to eliminate leading/trailing-space key mismatches ── */
              var st = _t(s.startTime || '');
              var et = _t(s.endTime   || '');
              var k  = (st && et) ? (st + '-' + et)
                                  : _norm(s.slotTime || '');
              if (k) statusMap[k] = _t(s.status) || 'available';
            });

            /* Render using the patched render function (see FIX 2b) */
            if (typeof window._bmgRenderSlotsPatched === 'function') {
              window._bmgRenderSlotsPatched(container, statusMap, date);
            } else if (typeof window._renderSlotGrid === 'function') {
              window._renderSlotGrid(container, statusMap, {}, date);
            } else if (typeof window._bmgRenderSlots === 'function') {
              window._bmgRenderSlots(container, statusMap, date);
            } else {
              /* Inline fallback renderer */
              _renderSlotsFallback(container, statusMap, date);
            }
          }, function (err) {
            console.error('[fix2a] snapshot error:', err);
            origLoadSlots(groundId, date);
          });

        window._slotUnsub   = unsub;
        window._bmgSlotUnsub = unsub;
        console.log('✅ [fix2a] trimmed real-time slot listener started for', groundId, date);
      };

      console.log('✅ [fix2a] loadSlots patched with trimmed key builder');
    });
  }

  /* ═══════════════════════════════════════════════════════════════════════
   * FIX 2b — Patch markSlotAsConfirmed to trim start/end before Firestore ops
   * ═══════════════════════════════════════════════════════════════════════ */
  function patchMarkSlotAsConfirmed() {
    waitFor('markSlotAsConfirmed', function (orig) {
      if (window.__slotPoolFix_markPatched) return;
      window.__slotPoolFix_markPatched = true;

      window.markSlotAsConfirmed = async function (bookingData) {
        /* Normalise the bookingData before passing to original */
        var fixed = Object.assign({}, bookingData);
        /* Trim any whitespace that sneaked into slot time fields */
        var rawSlot = _norm(fixed.slotTime || fixed.time || fixed.slot_time || fixed.slottime || '');
        if (rawSlot) {
          fixed.slotTime = rawSlot;
          /* Also fix startTime / endTime if present */
          if (rawSlot.includes('-')) {
            fixed.startTime = _start(rawSlot);
            fixed.endTime   = _end(rawSlot);
          }
        }

        var result = await orig(fixed);

        /* Extra safety: if the original call failed or returned false,
           try a direct Firestore upsert ourselves                         */
        if (!result) {
          var groundId  = fixed.groundId  || fixed.ground_id  || '';
          var date      = fixed.date      || fixed.bookingDate || '';
          var start     = _start(rawSlot);
          var end       = _end(rawSlot);
          var bookingId = fixed.bookingId || fixed.orderId || fixed.id || '';
          var userId    = fixed.userId    || (window.currentUser && window.currentUser.uid) || '';

          if (groundId && date && start) {
            try {
              var db = window.db;
              var snap = await db.collection('slots')
                .where('groundId',  '==', groundId)
                .where('date',      '==', date)
                .where('startTime', '==', start)
                .limit(1).get();

              var FV = firebase.firestore.FieldValue;
              if (!snap.empty) {
                await snap.docs[0].ref.update({
                  status   : 'confirmed',
                  bookingId: bookingId,
                  bookedBy : userId,
                  bookedAt : FV.serverTimestamp(),
                  updatedAt: FV.serverTimestamp(),
                });
                console.log('✅ [fix2b] Slot UPDATED to confirmed (fallback):', start);
              } else {
                await db.collection('slots').add({
                  groundId, date,
                  startTime: start,
                  endTime  : end,
                  slotTime : rawSlot,
                  status   : 'confirmed',
                  bookingId, bookedBy: userId,
                  bookedAt : FV.serverTimestamp(),
                  createdAt: FV.serverTimestamp(),
                  updatedAt: FV.serverTimestamp(),
                });
                console.log('✅ [fix2b] Slot CREATED as confirmed (fallback):', rawSlot);
              }
              result = true;
            } catch (err) {
              console.error('[fix2b] fallback markSlotAsConfirmed error:', err);
            }
          }
        }
        return result;
      };

      console.log('✅ [fix2b] markSlotAsConfirmed patched with trim + fallback');
    });
  }

  /* ═══════════════════════════════════════════════════════════════════════
   * FIX 2c — Scan confirmed bookings and ensure their slot docs are "confirmed"
   *           Called every time loadSlots fires for a ground+date pair.
   * ═══════════════════════════════════════════════════════════════════════ */
  async function _syncConfirmedBookingsToSlots(groundId, date) {
    var db = window.db;
    if (!db || !groundId || !date) return;
    try {
      var snap = await db.collection('bookings')
        .where('groundId',      '==', groundId)
        .where('date',          '==', date)
        .where('bookingStatus', '==', 'confirmed')
        .get();

      if (snap.empty) return;

      var FV = firebase.firestore.FieldValue;

      snap.forEach(async function (bdoc) {
        var b     = bdoc.data();
        var raw   = _norm(b.slotTime || b.time || b.slot_time || '');
        var start = _start(raw);
        var end   = _end(raw);
        if (!start) return;

        try {
          var slotSnap = await db.collection('slots')
            .where('groundId',  '==', groundId)
            .where('date',      '==', date)
            .where('startTime', '==', start)
            .limit(1).get();

          if (!slotSnap.empty) {
            var existing = slotSnap.docs[0].data();
            if (existing.status !== 'confirmed' && existing.status !== 'booked') {
              await slotSnap.docs[0].ref.update({
                status   : 'confirmed',
                bookingId: b.bookingId || bdoc.id,
                bookedBy : b.userId    || '',
                updatedAt: FV.serverTimestamp(),
              });
              console.log('[fix2c] Back-filled slot as confirmed:', start, date);
            }
          } else {
            /* Slot doc missing entirely — create it so listener renders red */
            var userId = b.userId || (window.currentUser && window.currentUser.uid) || '';
            await db.collection('slots').add({
              groundId, date,
              startTime: start,
              endTime  : end,
              slotTime : raw,
              status   : 'confirmed',
              bookingId: b.bookingId || bdoc.id,
              bookedBy : userId,
              bookedAt : FV.serverTimestamp(),
              createdAt: FV.serverTimestamp(),
              updatedAt: FV.serverTimestamp(),
            });
            console.log('[fix2c] Created missing slot doc as confirmed:', start, date);
          }
        } catch (e) {
          /* Best-effort; ignore permission errors for other users' slots */
        }
      });
    } catch (err) {
      console.warn('[fix2c] _syncConfirmedBookingsToSlots error:', err);
    }
  }

  /* ═══════════════════════════════════════════════════════════════════════
   * Inline fallback slot renderer (used if app's render fns are unavailable)
   * ═══════════════════════════════════════════════════════════════════════ */
  function _renderSlotsFallback(container, statusMap, date) {
    var ICONS  = { available:'🟢', booked:'🔴', confirmed:'🔴', locked:'🔒', pending:'🔒', past:'⏳', closed:'🚫' };
    var LABELS = { available:'Available', booked:'Booked', confirmed:'Booked', locked:'Processing…', pending:'Processing…', past:'Time Passed', closed:'Closed' };
    var now = new Date();
    var curMin = now.getHours() * 60 + now.getMinutes();
    var isToday = date === now.toISOString().split('T')[0];
    var sel = window.selectedSlot || null;
    var html = '';

    for (var h = 0; h < 24; h++) {
      var sh  = String(h).padStart(2,'0');
      var eh  = String(h+1).padStart(2,'0');
      var key = sh + ':00-' + eh + ':00';
      var raw = (isToday && h * 60 <= curMin) ? 'past' : (statusMap[key] || 'available');
      /* Normalise confirmed → booked for class */
      var cls = (raw === 'confirmed') ? 'booked' : raw;
      var icon  = ICONS[raw]  || '🟢';
      var label = LABELS[raw] || 'Available';
      var isSelected = (sel === key && cls === 'available');
      if (isSelected) { cls = 'selected'; icon = '✅'; label = 'Selected'; }
      var disabled = cls !== 'available' && cls !== 'selected';

      /* Inline red style for booked/confirmed */
      var inlineStyle = (cls === 'booked' || cls === 'confirmed')
        ? 'border-color:#ef4444!important;background:linear-gradient(135deg,#fef2f2,#fee2e2)!important;color:#991b1b!important;cursor:not-allowed!important;'
        : '';

      html += '<div class="time-slot ' + cls + '"'
            + ' data-slot="' + key + '"'
            + ' data-status="' + (disabled ? 'disabled' : raw) + '"'
            + (!disabled ? ' data-available="true"' : '')
            + (inlineStyle ? ' style="' + inlineStyle + '"' : '')
            + '>'
            + '<span class="slot-icon bmg-s-icon">' + icon + '</span>'
            + '<span class="slot-time-text bmg-s-time">' + key.replace('-', ' – ') + '</span>'
            + '<span class="slot-status-tag bmg-s-label">' + label + '</span>'
            + '</div>';
    }
    container.innerHTML = html;
    if (!container.classList.contains('slots-grid')) container.classList.add('slots-grid');

    container.querySelectorAll('.time-slot[data-available="true"]').forEach(function (el) {
      el.addEventListener('click', function () {
        if (typeof window.selectSlot === 'function') window.selectSlot(el.dataset.slot);
      });
    });
  }

  /* ═══════════════════════════════════════════════════════════════════════
   * FIX 2d — Intercept bmg:paymentConfirmed event to ensure Firestore slot
   *           is always marked confirmed AND the visible UI turns red.
   * ═══════════════════════════════════════════════════════════════════════ */
  window.addEventListener('bmg:paymentConfirmed', function (e) {
    var detail = e.detail || {};
    if (detail.paymentType !== 'booking') return;
    var d = detail.result || {};

    var groundId = d.groundId || d.ground_id || '';
    var date     = d.date     || d.bookingDate || '';
    var rawSlot  = _norm(d.slotTime || d.time || d.slot_time || '');
    var start    = _start(rawSlot);

    if (!groundId || !date || !start) return;

    /* Immediately update all matching DOM slot elements to red */
    function _flashRed() {
      document.querySelectorAll('.time-slot[data-slot]').forEach(function (el) {
        var slotKey = el.dataset.slot || '';
        if (_start(_norm(slotKey)) === start) {
          el.className = el.className.replace(/\b(available|selected|locked|pending)\b/g, '').trim();
          if (!el.classList.contains('booked') && !el.classList.contains('confirmed')) {
            el.classList.add('confirmed');
          }
          el.style.cssText += 'border-color:#ef4444!important;background:linear-gradient(135deg,#fef2f2,#fee2e2)!important;color:#991b1b!important;cursor:not-allowed!important;pointer-events:none!important;';
          var icon  = el.querySelector('.slot-icon, .bmg-s-icon');
          var label = el.querySelector('.slot-status-tag, .bmg-s-label');
          if (icon)  icon.textContent  = '🔴';
          if (label) label.textContent = 'Booked';
          delete el.dataset.available;
          el.dataset.status = 'disabled';
          console.log('[fix2d] Slot turned red in UI:', slotKey);
        }
      });
    }

    setTimeout(_flashRed, 100);
    setTimeout(_flashRed, 800);   /* second pass after any re-render */

    /* Also write to Firestore so other users see it */
    var db = window.db;
    if (!db) return;
    var FV = firebase.firestore.FieldValue;
    var userId    = d.userId    || (window.currentUser && window.currentUser.uid) || '';
    var bookingId = d.bookingId || detail.orderId || '';

    db.collection('slots')
      .where('groundId',  '==', groundId)
      .where('date',      '==', date)
      .where('startTime', '==', start)
      .limit(1).get()
      .then(function (snap) {
        if (!snap.empty) {
          return snap.docs[0].ref.update({
            status   : 'confirmed',
            bookingId: bookingId,
            bookedBy : userId,
            updatedAt: FV.serverTimestamp(),
          });
        } else {
          return db.collection('slots').add({
            groundId, date,
            startTime: start,
            endTime  : _end(rawSlot),
            slotTime : rawSlot,
            status   : 'confirmed',
            bookingId, bookedBy: userId,
            bookedAt : FV.serverTimestamp(),
            createdAt: FV.serverTimestamp(),
            updatedAt: FV.serverTimestamp(),
          });
        }
      })
      .then(function () { console.log('✅ [fix2d] Slot confirmed in Firestore:', start, date); })
      .catch(function (err) { console.warn('[fix2d] Firestore slot write error:', err); });
  });

  /* ═══════════════════════════════════════════════════════════════════════
   * Bootstrap — run all patches once Firestore db is ready
   * ═══════════════════════════════════════════════════════════════════════ */
  function boot() {
    patchSaveBmgpPoolEdits();
    patchLoadSlotsRealtime();
    patchMarkSlotAsConfirmed();
    console.log('✅ [sportobook_slot_and_pool_fix] all patches applied');
  }

  if (window.db) {
    boot();
  } else {
    /* Wait for Firestore */
    var iv = setInterval(function () {
      if (window.db) { clearInterval(iv); boot(); }
    }, 300);
    /* Hard timeout after 15 s */
    setTimeout(function () { clearInterval(iv); boot(); }, 15000);
  }

})();


/* ══════════════════════════════════════════════════════════════════
 *  FILE: sportobook_payout_zero_fix.js
 * ══════════════════════════════════════════════════════════════════ */

/**
 * ═══════════════════════════════════════════════════════════════
 *  SPORTOBOOK — PAYOUT ALWAYS ZERO FIX  v3  (definitive)
 *  File: sportobook_payout_zero_fix.js
 *
 *  ROOT CAUSE ANALYSIS (from console logs):
 *  ─────────────────────────────────────────
 *  Log showed:  earned: 34.5 | received(paid): 62 | available: 0
 *
 *  v1 bug:  ALL owner_payments counted as "received" (pending included)
 *  v2 bug:  payout_requests with status:'paid' summed to ₹62 > earned ₹34.5
 *           because old/stale payout_request documents exist in Firestore
 *           from before the current booking system was in place.
 *
 *  CORRECT formula (matches original app.js logic):
 *    available = totalEarned
 *              - totalTransferred   (owner_transfers collection — actual bank sends)
 *              - totalLocked        (payout_requests status:'pending'/'approved')
 *
 *  "totalTransferred" comes from owner_transfers, NOT from payout_requests.
 *  payout_requests are just requests; owner_transfers are confirmed sends.
 *  This matches how app.js originally computed pendingBalance (line ~17350).
 *
 *  INSTALL:
 *  ─────────
 *  Add as the VERY LAST <script> in index.html, after all other patches:
 *    <script src="sportobook_payout_zero_fix.js"></script>
 * ═══════════════════════════════════════════════════════════════
 */
(function () {
  'use strict';

  const TAG  = '[payout-zero-fix]';
  const log  = (...a) => console.log(TAG, ...a);
  const warn = (...a) => console.warn(TAG, ...a);

  const _db  = () => window.db || null;
  const _cu  = () => window.currentUser || null;
  const _fv  = () => window.firebase && window.firebase.firestore ? window.firebase.firestore : null;
  const _ts  = () => { const f = _fv(); return f ? f.FieldValue.serverTimestamp() : new Date(); };
  const _fmt = (v) => typeof window.formatCurrency === 'function'
    ? window.formatCurrency(v || 0)
    : '₹' + Number(v || 0).toLocaleString('en-IN');
  const _esc = (s) => String(s || '')
    .replace(/&/g,'&amp;').replace(/</g,'&lt;')
    .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  function _isoDate(offsetDays) {
    return new Date(Date.now() - offsetDays * 86400000).toISOString().split('T')[0];
  }
  function _fmtDate(ts) {
    if (!ts) return '—';
    try {
      const d = ts.toDate ? ts.toDate() : new Date(ts);
      return d.toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' });
    } catch (_) { return '—'; }
  }


  /* ══════════════════════════════════════════════════════════════
     FIXED computeRealBalance
     ─────────────────────────────────────────────────────────────
     "received" = owner_transfers (actual bank sends by admin)
                  NOT payout_requests (which can have stale/bad data)

     available  = earned - transferred - locked(pending requests)
  ══════════════════════════════════════════════════════════════ */
  async function computeRealBalance(ownerId) {
    const db = _db();
    if (!db || !ownerId) {
      return {
        earned: 0, groundEarned: 0, poolEarned: 0, tournamentEarned: 0,
        transferred: 0, locked: 0, available: 0, pendingRequests: [],
      };
    }

    /* ── 1. Ground bookings (confirmed) ── */
    const gSnap = await db.collection('bookings')
      .where('ownerId', '==', ownerId)
      .where('bookingStatus', '==', 'confirmed')
      .get().catch(() => ({ docs: [] }));

    let groundEarned = 0;
    gSnap.docs.forEach(d => {
      const data = d.data();
      // CRITICAL FIX: skip bookings already paid out OR locked in a pending payout request.
      // payout_pending bookings are already counted in `locked` (payout_requests sum),
      // so including them in totalEarned too would create a phantom double balance.
      if (data.payoutStatus === 'payout_done') return; // only exclude fully-transferred bookings from earned total
      const amt  = Number(data.ownerAmount);
      groundEarned += amt > 0 ? amt : Math.floor(Number(data.amount || data.totalAmount || 0) * 0.93);
    });

    /* ── 2. Pool bookings — FIXED: Query only status='confirmed' (no double-query to prevent duplicate count) ── */
    // NOTE: We set BOTH status AND bookingStatus to 'confirmed', so we only need to query ONE field
    // Double-querying caused same document to be counted twice before deduplication
    const pByStatus = await db.collection('pool_bookings')
      .where('ownerId','==',ownerId)
      .where('status','==','confirmed')
      .get().catch(() => ({ docs: [] }));
    
    let poolEarned = 0;
    pByStatus.docs.forEach(d => {
      const data = d.data();
      // CRITICAL FIX: skip pool bookings already paid out
      if (data.payoutStatus === 'payout_done') return;
      const amt  = Number(data.ownerAmount);
      poolEarned += amt > 0 ? amt : Math.floor(Number(data.amount || 0) * 0.93);
    });

    /* ── 3. Tournament earnings ── */
    let tournamentEarned = 0;
    try {
      const tSnap = await db.collection('tournaments').where('ownerId','==',ownerId).get().catch(() => ({ docs: [] }));
      if (!tSnap.empty) {
        const ids = tSnap.docs.map(d => d.id);
        for (let i = 0; i < ids.length; i += 30) {
          const eSnap = await db.collection('tournament_entries')
            .where('tournamentId','in', ids.slice(i, i + 30))
            .get().catch(() => ({ docs: [] }));
          eSnap.docs.forEach(d => {
            const e = d.data();
            if (e.status !== 'confirmed' && e.paymentStatus !== 'paid') return;
            // CRITICAL FIX: skip tournament entries already paid out OR locked in a pending payout request.
            if (e.payoutStatus === 'payout_done') return; // only exclude fully-transferred entries
            tournamentEarned += Number(e.ownerAmount) || Math.round(Number(e.amount || 0) * 0.8);
          });
        }
      }
    } catch (_) {}

    const totalEarned = groundEarned + poolEarned + tournamentEarned;

    /* ── 4. Already transferred ──────────────────────────────────────────
     *
     *  PRIMARY source: owner_transfers collection (actual confirmed bank sends).
     *  FALLBACK: If owner_transfers is empty (old paid requests pre-date the
     *  owner_transfers feature), sum up paid payout_requests as transferred.
     *  This handles the historical case where markPayoutAsPaid ran without
     *  creating an owner_transfers record, leaving the same booking in earnings.
     * ──────────────────────────────────────────────────────────────────── */
    const [transferSnap, allPayoutSnap] = await Promise.all([
      db.collection('owner_transfers')
        .where('ownerId', '==', ownerId)
        .get().catch(() => ({ docs: [] })),
      db.collection('payout_requests')
        .where('ownerId', '==', ownerId)
        .get().catch(() => ({ docs: [] })),
    ]);

    let totalTransferred = 0;
    transferSnap.docs.forEach(d => {
      totalTransferred += Number(d.data().amount || 0);
    });

    /* ── 5. Locked in pending/approved payout_requests ── */
    let totalLocked = 0;
    const pendingRequests = [];
    let paidFromRequests = 0;

    allPayoutSnap.docs.forEach(d => {
      const p = d.data();
      const st = p.status || 'pending';
      if (st === 'pending' || st === 'approved') {
        totalLocked += Number(p.amount || 0);
        pendingRequests.push({ id: d.id, ...p });
      } else if (st === 'paid' || st === 'completed') {
        paidFromRequests += Number(p.amount || 0);
      }
    });

    // NOTE: We do NOT fall back to paid payout_requests as 'transferred'.
    // Bookings that were paid out already have payoutStatus:'payout_done' and are
    // excluded from totalEarned above. Using paid payout_requests as an additional
    // deduction would double-count: once via exclusion from earned, once here.
    // If owner_transfers is empty, transferred = 0 and available = earned.
    if (totalTransferred === 0 && paidFromRequests > 0) {
      // Do NOT set totalTransferred = paidFromRequests (causes double-deduction)
      warn('[payout-fix] owner_transfers empty; paidFromRequests ignored to prevent double-deduction. Earned:', totalEarned);
    }

    const available = Math.max(0, totalEarned - totalTransferred - totalLocked);

    log('balance for', ownerId, '→',
      'earned:', totalEarned,
      '| transferred:', totalTransferred,
      '| locked:', totalLocked,
      '| available:', available
    );

    return {
      earned: totalEarned, groundEarned, poolEarned, tournamentEarned,
      transferred: totalTransferred,
      locked: totalLocked,
      available,
      pendingRequests,
    };
  }


  /* ══════════════════════════════════════════════════════════════
     Earnings tab renderer
  ══════════════════════════════════════════════════════════════ */
  async function renderEarningsTab(container) {
    const cu = _cu(), db = _db();
    if (!cu || !db) {
      container.innerHTML = '<p style="text-align:center;padding:32px;color:#9ca3af;">Please log in to view earnings.</p>';
      return;
    }

    if (typeof window.showLoading === 'function') window.showLoading('Calculating earnings…');

    try {
      const bal = await computeRealBalance(cu.uid);

      /* Period stats */
      const today = _isoDate(0), week = _isoDate(6), month = _isoDate(29);
      let todayE = 0, weekE = 0, monthE = 0;
      const bSnap = await db.collection('bookings')
        .where('ownerId', '==', cu.uid)
        .where('bookingStatus', '==', 'confirmed')
        .get().catch(() => ({ docs: [] }));
      bSnap.docs.forEach(d => {
        const b   = d.data();
        // Skip already paid-out bookings in period stats too
        if (b.payoutStatus === 'payout_done') return;
        const amt = Number(b.ownerAmount) || Math.floor(Number(b.amount || 0) * 0.93);
        if (b.date === today) todayE += amt;
        if (b.date >= week)   weekE  += amt;
        if (b.date >= month)  monthE += amt;
      });

      if (typeof window.hideLoading === 'function') window.hideLoading();

      const pendingNotice = bal.pendingRequests.length > 0
        ? `<div style="background:#fffbeb;border:1px solid #fde68a;border-radius:12px;padding:12px 14px;margin-bottom:16px;display:flex;align-items:center;gap:10px;">
            <i class="fas fa-clock" style="color:#f59e0b;font-size:16px;flex-shrink:0;"></i>
            <div>
              <div style="font-weight:700;color:#92400e;font-size:13px;">Payout Under Review</div>
              <div style="font-size:12px;color:#b45309;margin-top:2px;">${_fmt(bal.locked)} is locked in a pending payout request.</div>
            </div>
          </div>` : '';

      container.innerHTML = `
        <!-- Period stats -->
        <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:16px;">
          ${[['Today', todayE], ['This Week', weekE], ['This Month', monthE]].map(([label, val]) => `
            <div style="background:#f0f4ff;border-radius:12px;padding:12px;text-align:center;">
              <div style="font-size:10px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px;">${label}</div>
              <div style="font-size:18px;font-weight:800;color:#2563eb;">${_fmt(val)}</div>
            </div>`).join('')}
        </div>

        <!-- Balance hero -->
        <div style="background:linear-gradient(135deg,#1b2e6c,#2563eb);border-radius:16px;padding:20px;margin-bottom:16px;color:#fff;">
          <div style="font-size:12px;opacity:.8;margin-bottom:6px;"><i class="fas fa-wallet"></i> Available to Withdraw</div>
          <div style="font-size:34px;font-weight:800;letter-spacing:-0.6px;margin-bottom:4px;">${_fmt(bal.available)}</div>
          <div style="font-size:11px;opacity:.7;">Total earned minus transferred &amp; pending</div>
          <div style="margin-top:12px;background:rgba(255,255,255,.12);border-radius:10px;padding:10px 12px;">
            <div style="display:flex;justify-content:space-between;margin-bottom:6px;">
              <span style="font-size:12px;opacity:.85;">Total Earned</span>
              <span style="font-size:13px;font-weight:700;">${_fmt(bal.earned)}</span>
            </div>
            ${bal.transferred > 0 ? `
            <div style="display:flex;justify-content:space-between;margin-bottom:6px;">
              <span style="font-size:12px;opacity:.85;">Already Transferred</span>
              <span style="font-size:13px;font-weight:700;color:#86efac;">− ${_fmt(bal.transferred)}</span>
            </div>` : ''}
            ${bal.locked > 0 ? `
            <div style="display:flex;justify-content:space-between;margin-bottom:6px;">
              <span style="font-size:12px;opacity:.85;">In Review (pending)</span>
              <span style="font-size:13px;font-weight:700;color:#fde047;">− ${_fmt(bal.locked)}</span>
            </div>` : ''}
            <div style="border-top:1px solid rgba(255,255,255,.2);margin-top:8px;padding-top:8px;display:flex;justify-content:space-between;">
              <span style="font-size:12px;font-weight:700;">Available Now</span>
              <span style="font-size:14px;font-weight:800;color:#86efac;">${_fmt(bal.available)}</span>
            </div>
          </div>
        </div>

        <!-- Earnings breakdown -->
        <div style="background:#fff;border:1.5px solid #e8edf8;border-radius:14px;padding:14px;margin-bottom:16px;">
          <div style="font-size:13px;font-weight:800;color:#0f1f5c;margin-bottom:10px;">
            <i class="fas fa-chart-bar" style="color:#2563eb;margin-right:6px;"></i>Earnings Breakdown
          </div>
          <div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #f0f4ff;">
            <span style="font-size:13px;color:#374151;"><i class="fas fa-futbol" style="color:#22c55e;margin-right:6px;width:14px;"></i>Ground Bookings</span>
            <span style="font-size:13px;font-weight:700;color:#15803d;">${_fmt(bal.groundEarned)}</span>
          </div>
          <div style="display:flex;justify-content:space-between;padding:8px 0;${bal.tournamentEarned > 0 ? 'border-bottom:1px solid #f0f4ff;' : ''}">
            <span style="font-size:13px;color:#374151;"><i class="fas fa-swimming-pool" style="color:#0ea5e9;margin-right:6px;width:14px;"></i>Pool Bookings</span>
            <span style="font-size:13px;font-weight:700;color:#0369a1;">${_fmt(bal.poolEarned)}</span>
          </div>
          ${bal.tournamentEarned > 0 ? `
          <div style="display:flex;justify-content:space-between;padding:8px 0;">
            <span style="font-size:13px;color:#374151;"><i class="fas fa-trophy" style="color:#7c3aed;margin-right:6px;width:14px;"></i>Tournaments</span>
            <span style="font-size:13px;font-weight:700;color:#7c3aed;">${_fmt(bal.tournamentEarned)}</span>
          </div>` : ''}
          <div style="display:flex;justify-content:space-between;padding:8px 0;border-top:2px solid #e8edf8;margin-top:4px;">
            <span style="font-size:13px;font-weight:700;color:#0f1f5c;">Total Earned</span>
            <span style="font-size:14px;font-weight:800;color:#0f1f5c;">${_fmt(bal.earned)}</span>
          </div>
        </div>

        ${pendingNotice}

        <!-- CTA -->
        ${bal.available > 0
          ? `<div style="background:#f0fdf4;border:1.5px solid #86efac;border-radius:14px;padding:14px;">
              <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;">
                <i class="fas fa-check-circle" style="color:#22c55e;font-size:18px;"></i>
                <div>
                  <div style="font-weight:700;color:#15803d;font-size:13px;">${_fmt(bal.available)} Ready to Withdraw</div>
                  <div style="font-size:12px;color:#166534;">Processed within 2–3 business days</div>
                </div>
              </div>
              <button onclick="window._bmgOpenPayoutModal()"
                style="width:100%;padding:13px;background:linear-gradient(135deg,#22c55e,#16a34a);color:#fff;border:none;border-radius:12px;font-weight:700;font-size:14px;cursor:pointer;font-family:inherit;">
                <i class="fas fa-paper-plane" style="margin-right:6px;"></i> Request Payout
              </button>
            </div>`
          : `<div style="background:#fffbeb;border:1.5px solid #fde68a;border-radius:14px;padding:14px;display:flex;align-items:center;gap:10px;">
              <i class="fas fa-info-circle" style="color:#f59e0b;font-size:16px;"></i>
              <div>
                <div style="font-weight:700;color:#92400e;font-size:13px;">${bal.earned > 0 ? (bal.locked > 0 ? 'Payout In Progress' : 'All Earnings Transferred') : 'No Earnings Yet'}</div>
                <div style="font-size:12px;color:#b45309;">${bal.locked > 0
                    ? `${_fmt(bal.locked)} is under a pending payout request.`
                    : bal.transferred > 0
                      ? `${_fmt(bal.transferred)} has been paid out to your account.`
                      : 'Earnings appear here after your first confirmed booking.'}</div>
              </div>
            </div>`}
      `;

      window._bmgCurrentBalance = bal;

    } catch (err) {
      if (typeof window.hideLoading === 'function') window.hideLoading();
      warn('renderEarningsTab error:', err.message);
      container.innerHTML = `
        <div style="text-align:center;padding:32px;color:#ef4444;">
          <i class="fas fa-exclamation-triangle" style="font-size:24px;margin-bottom:8px;display:block;"></i>
          <div style="font-weight:600;">Failed to load earnings</div>
          <div style="font-size:12px;color:#9ca3af;margin-top:4px;">${_esc(err.message)}</div>
          <button onclick="window._bmgFixReloadEarnings()"
            style="margin-top:12px;padding:8px 20px;background:#2563eb;color:#fff;border:none;border-radius:8px;cursor:pointer;font-size:13px;">
            Retry
          </button>
        </div>`;
    }
  }


  /* ══════════════════════════════════════════════════════════════
     Payouts tab renderer
  ══════════════════════════════════════════════════════════════ */
  async function renderPayoutsTab(container) {
    const cu = _cu(), db = _db();
    if (!cu || !db) {
      container.innerHTML = '<p style="text-align:center;padding:32px;color:#9ca3af;">Please log in.</p>';
      return;
    }

    if (typeof window.showLoading === 'function') window.showLoading('Loading payouts…');

    try {
      const bal = await computeRealBalance(cu.uid);

      const prSnap = await db.collection('payout_requests')
        .where('ownerId', '==', cu.uid)
        .orderBy('createdAt', 'desc')
        .get().catch(async () =>
          db.collection('payout_requests').where('ownerId', '==', cu.uid).get().catch(() => ({ docs: [] }))
        );

      const stats = { total: prSnap.docs.length, pending: 0, approved: 0, paid: 0, rejected: 0 };
      prSnap.docs.forEach(d => { const st = d.data().status; if (stats[st] !== undefined) stats[st]++; });
      const hasPending = bal.pendingRequests.length > 0;

      function _statusCard(docId, p) {
        const st     = p.status || 'pending';
        const icons  = { pending:'fa-clock', approved:'fa-check-circle', paid:'fa-money-bill-wave', rejected:'fa-times-circle' };
        const labels = { pending:'Under Review', approved:'Approved', paid:'Paid ✓', rejected:'Rejected' };
        const colors = { pending:'#f59e0b', approved:'#3b82f6', paid:'#22c55e', rejected:'#ef4444' };
        return `
          <div class="psp-card" data-status="${st}"
            style="background:#fff;border-radius:14px;padding:14px;margin-bottom:10px;border:1.5px solid #e8edf8;box-shadow:0 2px 8px rgba(15,31,92,.06);">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px;">
              <div>
                <div style="font-size:13px;font-weight:800;color:#0f1f5c;">Payout Request</div>
                <div style="font-size:11px;color:#9ca3af;margin-top:2px;">${_fmtDate(p.createdAt)}</div>
              </div>
              <div style="display:inline-flex;align-items:center;gap:5px;padding:4px 10px;border-radius:20px;
                  background:${colors[st]}18;color:${colors[st]};font-size:11px;font-weight:700;">
                <i class="fas ${icons[st] || 'fa-circle'}"></i> ${labels[st] || st}
              </div>
            </div>
            <div style="font-size:24px;font-weight:800;color:#0f1f5c;margin-bottom:6px;">${_fmt(p.amount)}</div>
            ${p.upiId ? `<div style="font-size:12px;color:#6b7280;"><i class="fas fa-qrcode" style="margin-right:5px;"></i>${_esc(p.upiId)}</div>` : ''}
            ${p.status === 'rejected' && p.rejectionReason ? `
            <div style="margin-top:8px;background:#fee2e2;border-radius:8px;padding:8px 10px;font-size:12px;color:#b91c1c;">
              <i class="fas fa-times-circle"></i> ${_esc(p.rejectionReason)}
            </div>` : ''}
          </div>`;
      }

      if (typeof window.hideLoading === 'function') window.hideLoading();

      container.innerHTML = `
        <!-- Balance hero -->
        <div style="background:linear-gradient(135deg,#1b2e6c,#2563eb);border-radius:16px;padding:20px;margin-bottom:16px;color:#fff;">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;">
            <div>
              <div style="font-size:11px;opacity:.75;margin-bottom:4px;"><i class="fas fa-wallet"></i> Available to Withdraw</div>
              <div style="font-size:34px;font-weight:800;letter-spacing:-0.6px;">${_fmt(bal.available)}</div>
              <div style="font-size:11px;opacity:.65;margin-top:4px;">
                Earned ${_fmt(bal.earned)}${bal.transferred > 0 ? ` · Transferred ${_fmt(bal.transferred)}` : ''}${bal.locked > 0 ? ` · In review ${_fmt(bal.locked)}` : ''}
              </div>
            </div>
            <button id="psp-apply-trigger"
              ${hasPending || bal.available < 1 ? 'disabled' : ''}
              style="background:rgba(255,255,255,.18);border:1.5px solid rgba(255,255,255,.35);color:#fff;
                font-size:12px;font-weight:700;padding:10px 14px;border-radius:22px;white-space:nowrap;
                font-family:inherit;opacity:${hasPending || bal.available < 1 ? '.6' : '1'};
                cursor:${hasPending || bal.available < 1 ? 'not-allowed' : 'pointer'};">
              <i class="fas fa-paper-plane" style="margin-right:5px;"></i>
              ${hasPending ? 'Request Pending' : 'Apply for Payout'}
            </button>
          </div>
          ${bal.locked > 0 ? `
          <div style="margin-top:12px;background:rgba(255,255,255,.1);border-radius:8px;padding:8px 10px;
              font-size:11px;opacity:.85;display:flex;align-items:center;gap:6px;">
            <i class="fas fa-clock" style="color:#fde047;"></i>
            <span>${_fmt(bal.locked)} is already under a pending payout request.</span>
          </div>` : ''}
        </div>

        <!-- Stats row -->
        <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:16px;">
          ${[
            ['Total',       stats.total,                     '#0f1f5c','#f8faff','#e8edf8'],
            ['In Progress', stats.pending + stats.approved,  '#92400e','#fffbeb','#fde68a'],
            ['Paid',        stats.paid,                      '#15803d','#f0fdf4','#86efac'],
            ['Rejected',    stats.rejected,                  '#b91c1c','#fef2f2','#fca5a5'],
          ].map(([label, val, tc, bg, border]) => `
            <div style="background:${bg};border-radius:12px;padding:10px;text-align:center;border:1px solid ${border};">
              <div style="font-size:18px;font-weight:800;color:${tc};">${val}</div>
              <div style="font-size:10px;color:${tc};font-weight:600;opacity:.75;margin-top:2px;">${label}</div>
            </div>`).join('')}
        </div>

        <!-- Requests list -->
        <div id="gef-payouts-list">
          ${prSnap.docs.length === 0
            ? `<div style="text-align:center;padding:36px 16px;">
                <div style="font-size:40px;opacity:.3;margin-bottom:10px;">💸</div>
                <div style="font-size:14px;font-weight:600;color:#9ca3af;">No payout requests yet.</div>
                <div style="font-size:12px;color:#d1d5db;margin-top:4px;">Apply for your first payout above.</div>
              </div>`
            : prSnap.docs.map(d => _statusCard(d.id, d.data())).join('')}
        </div>
      `;

      /* Wire apply button */
      const applyBtn = document.getElementById('psp-apply-trigger');
      if (applyBtn && !hasPending && bal.available >= 1) {
        applyBtn.addEventListener('click', () => openPayoutModal());
      }

    } catch (err) {
      if (typeof window.hideLoading === 'function') window.hideLoading();
      warn('renderPayoutsTab error:', err.message);
      container.innerHTML = `<div style="text-align:center;padding:32px;color:#ef4444;">Failed: ${_esc(err.message)}</div>`;
    }
  }


  /* ══════════════════════════════════════════════════════════════
     Payout request modal
  ══════════════════════════════════════════════════════════════ */
  async function openPayoutModal() {
    const cu = _cu(), db = _db();
    if (!cu || !db) { alert('Please log in first.'); return; }

    const bal = await computeRealBalance(cu.uid).catch(() => null);
    if (!bal) { alert('Could not load balance. Please try again.'); return; }

    if (bal.pendingRequests.length > 0) {
      const fn = typeof window.showToast === 'function' ? window.showToast : alert;
      fn('You already have a pending payout request. Please wait for it to be processed.', 'warning');
      return;
    }
    if (bal.available < 1) {
      const fn = typeof window.showToast === 'function' ? window.showToast : alert;
      fn('No balance available to withdraw yet.', 'info');
      return;
    }

    const available = bal.available;

    document.getElementById('gef-payout-modal')?.remove();
    const ov = document.createElement('div');
    ov.id = 'gef-payout-modal';
    ov.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:99999;display:flex;align-items:flex-end;justify-content:center;';
    ov.innerHTML = `
      <div style="background:#fff;border-radius:20px 20px 0 0;padding:24px;width:100%;max-width:480px;max-height:90vh;overflow-y:auto;">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:18px;">
          <div style="font-size:16px;font-weight:800;color:#0f1f5c;">Request Payout</div>
          <button id="gef-modal-close" style="background:none;border:none;font-size:22px;color:#9ca3af;cursor:pointer;line-height:1;">×</button>
        </div>
        <div style="background:#f0fdf4;border:1.5px solid #86efac;border-radius:12px;padding:12px;margin-bottom:16px;text-align:center;">
          <div style="font-size:11px;color:#15803d;font-weight:600;">Available Balance</div>
          <div style="font-size:28px;font-weight:800;color:#15803d;">${_fmt(available)}</div>
        </div>
        <div style="margin-bottom:14px;">
          <label style="font-size:13px;font-weight:700;color:#374151;display:block;margin-bottom:6px;">Amount to Withdraw</label>
          <input id="gef-amt" type="number" min="1" max="${Math.floor(available)}" value="${Math.floor(available)}"
            style="width:100%;padding:12px;border:1.5px solid #e8edf8;border-radius:10px;font-size:15px;font-family:inherit;box-sizing:border-box;outline:none;">
          <div id="gef-amt-err" style="color:#ef4444;font-size:12px;margin-top:4px;display:none;"></div>
          <div style="display:flex;gap:8px;margin-top:8px;">
            ${[25,50,75,100].map(p => `
              <button onclick="document.getElementById('gef-amt').value=Math.floor(${available}*${p}/100);document.getElementById('gef-amt-err').style.display='none';"
                style="flex:1;padding:6px;background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;
                  font-size:11px;font-weight:700;color:#1d4ed8;cursor:pointer;font-family:inherit;">${p}%</button>`).join('')}
          </div>
        </div>
        <div style="margin-bottom:16px;">
          <label style="font-size:13px;font-weight:700;color:#374151;display:block;margin-bottom:6px;">UPI ID</label>
          <input id="gef-upi" type="text" placeholder="yourname@upi"
            style="width:100%;padding:12px;border:1.5px solid #e8edf8;border-radius:10px;font-size:14px;font-family:inherit;box-sizing:border-box;outline:none;">
          <div id="gef-upi-err" style="color:#ef4444;font-size:12px;margin-top:4px;display:none;"></div>
        </div>
        <button id="gef-submit-payout"
          style="width:100%;padding:14px;background:linear-gradient(135deg,#22c55e,#16a34a);color:#fff;border:none;
            border-radius:12px;font-weight:700;font-size:15px;cursor:pointer;font-family:inherit;">
          <i class="fas fa-paper-plane" style="margin-right:6px;"></i> Submit Payout Request
        </button>
      </div>`;

    document.body.appendChild(ov);
    document.getElementById('gef-modal-close').onclick = () => ov.remove();
    ov.addEventListener('click', e => { if (e.target === ov) ov.remove(); });

    document.getElementById('gef-submit-payout').addEventListener('click', async function () {
      const amtInput = document.getElementById('gef-amt');
      const upiInput = document.getElementById('gef-upi');
      const amtErr   = document.getElementById('gef-amt-err');
      const upiErr   = document.getElementById('gef-upi-err');
      const amt = parseFloat(amtInput.value);
      const upi = upiInput.value.trim();
      amtErr.style.display = 'none';
      upiErr.style.display = 'none';

      if (!amt || amt < 1) { amtErr.textContent = 'Enter a valid amount.'; amtErr.style.display = 'block'; return; }
      if (amt > available + 0.5) { amtErr.textContent = `Exceeds available balance of ${_fmt(available)}.`; amtErr.style.display = 'block'; return; }
      if (!upi || !upi.includes('@')) { upiErr.textContent = 'Enter a valid UPI ID (e.g. name@upi).'; upiErr.style.display = 'block'; return; }

      this.disabled = true;
      this.textContent = 'Submitting…';

      try {
        /* Re-check for duplicate */
        const latestPending = await db.collection('payout_requests')
          .where('ownerId', '==', cu.uid)
          .where('status', 'in', ['pending', 'approved'])
          .get().catch(() => ({ docs: [] }));
        if (latestPending.docs.length > 0) {
          alert('A payout request is already pending. Please wait.');
          ov.remove();
          return;
        }

        await db.collection('payout_requests').add({
          requestId      : 'POUT-' + Date.now(),
          ownerId        : cu.uid,
          ownerName      : cu.ownerName || cu.name || cu.displayName || '',
          ownerEmail     : cu.email || '',
          upiId          : upi,
          amount         : Math.round(amt),
          requestedAmount: Math.round(amt),
          status         : 'pending',
          bookingIds     : [],
          createdAt      : _ts(),
          updatedAt      : _ts(),
        });

        ov.remove();

        const toastFn = window.showToast || window._toast || ((m) => alert(m));
        toastFn('Payout request submitted! Admin will review within 2–3 business days.', 'success');

        /* Refresh payouts tab */
        const cont = document.getElementById('owner-dashboard-content') || document.getElementById('owner-earnings-content');
        if (cont) renderPayoutsTab(cont).catch(() => {});

      } catch (err) {
        warn('Payout submit error:', err.message);
        this.disabled = false;
        this.innerHTML = '<i class="fas fa-paper-plane" style="margin-right:6px;"></i> Submit Payout Request';
        amtErr.textContent = 'Failed to submit. Please try again.';
        amtErr.style.display = 'block';
      }
    });
  }


  /* ══════════════════════════════════════════════════════════════
     Install — overwrite all previous (broken) versions
  ══════════════════════════════════════════════════════════════ */
  function install() {
    window.loadOwnerEarnings         = renderEarningsTab;
    window.loadOwnerPayouts          = renderPayoutsTab;
    window._bmgLoadOwnerEarningsFull = renderEarningsTab;
    window._bmgOpenPayoutModal       = openPayoutModal;
    window.showPayoutRequestModal    = openPayoutModal;
    window._efComputeRealBalance     = computeRealBalance;
    window._pspEarningsPatched       = true;
    window._gefInstalled             = true;
    window._bmgFixReloadEarnings     = function (container) {
      const c = container
        || document.getElementById('owner-dashboard-content')
        || document.getElementById('owner-earnings-content');
      if (c) renderEarningsTab(c).catch(console.error);
    };
    log('✅ Fixed computeRealBalance + renderers installed (v3 — uses owner_transfers)');
  }

  function patchDashboardRouter() {
    if (!window.loadOwnerDashboard) { setTimeout(patchDashboardRouter, 300); return; }
    if (window.__pzfRouterPatched) return;

    const _orig = window.loadOwnerDashboard;
    window.loadOwnerDashboard = async function (tab) {
      const container = document.getElementById('owner-dashboard-content');
      if (tab === 'earnings' && container) {
        document.querySelectorAll('.dashboard-tabs .tab-btn').forEach(b => b.classList.remove('active'));
        document.getElementById('owner-earnings-tab')?.classList.add('active');
        container.innerHTML = '<div class="loading-spinner"><div class="loader-spinner"></div></div>';
        try { await renderEarningsTab(container); } catch (e) { warn('earnings error:', e.message); }
        return;
      }
      if (tab === 'payouts' && container) {
        document.querySelectorAll('.dashboard-tabs .tab-btn').forEach(b => b.classList.remove('active'));
        document.getElementById('owner-payouts-tab')?.classList.add('active');
        container.innerHTML = '<div class="loading-spinner"><div class="loader-spinner"></div></div>';
        try { await renderPayoutsTab(container); } catch (e) { warn('payouts error:', e.message); }
        return;
      }
      return _orig.apply(this, arguments);
    };

    window.__pzfRouterPatched = true;
    log('✅ loadOwnerDashboard patched');
  }

  function wireRefreshEvents() {
    window.addEventListener('bmg:paymentConfirmed', function () {
      setTimeout(() => {
        const c = document.getElementById('owner-dashboard-content') || document.getElementById('owner-earnings-content');
        if (c) renderEarningsTab(c).catch(() => {});
      }, 3000);
    });
    window.addEventListener('bmg:earningsNeedRefresh', function () {
      setTimeout(() => {
        const c = document.getElementById('owner-dashboard-content') || document.getElementById('owner-earnings-content');
        if (c) renderEarningsTab(c).catch(() => {});
      }, 1000);
    });
  }

  /* Boot */
  install();
  patchDashboardRouter();
  wireRefreshEvents();
  setTimeout(install, 200);
  setTimeout(install, 700);
  setTimeout(install, 1800);
  setTimeout(patchDashboardRouter, 400);

  /* MutationObserver: survive any late overwrites */
  (function attachObserver() {
    const el = document.getElementById('owner-dashboard-page');
    if (!el) { setTimeout(attachObserver, 500); return; }
    new MutationObserver(() => {
      if (window.loadOwnerEarnings !== renderEarningsTab) install();
    }).observe(el, { childList: true, subtree: true });
    log('MutationObserver attached');
  })();

  log('sportobook_payout_zero_fix.js v3 loaded ✅');
})();
/* ══════════════════════════════════════════════════════════════════════════
 * COMPREHENSIVE FIX PATCH v4
 * Fixes:
 *   1. Owner earnings not showing for pool/ground bookings (7% commission)
 *   2. Entry pass not popping up instantly after payment return
 *   3. Updated pool price not showing in booking page for members
 *   4. Swimming pool Write Review not working
 * ══════════════════════════════════════════════════════════════════════════ */
(function () {
  'use strict';

  const L    = (...a) => console.log('[fix-v4]', ...a);
  const W    = (...a) => console.warn('[fix-v4]', ...a);
  const _db  = () => window.db || (window.firebase && window.firebase.firestore && window.firebase.firestore());
  const _cu  = () => window.currentUser || (window.auth && window.auth.currentUser && { uid: window.auth.currentUser.uid });
  const _ts  = () => window.firebase && window.firebase.firestore ? window.firebase.firestore.FieldValue.serverTimestamp() : new Date();

  /* ────────────────────────────────────────────────────────────────────────
   * FIX 1 — Owner Earnings: pool bookings confirmed via paymentStatus:'success'
   *
   * Root cause: computeRealBalance (v3) only queries pool_bookings where
   *   status == 'confirmed' OR bookingStatus == 'confirmed'.
   * But some pool bookings written by finalisePoolBooking have BOTH
   *   status:'confirmed' AND bookingStatus:'confirmed', while others may
   *   only have paymentStatus:'success' without both status fields.
   *
   * Additionally the 7% commission fallback used Math.floor(amount * 0.93)
   * which is correct (93% to owner = 7% platform), but pool bookings
   * sometimes store ownerAmount:0 when the field was not enriched from
   * sessionStorage. We now also query by paymentStatus:'success' as a
   * third net to catch those.
   *
   * We override computeRealBalance on window._efComputeRealBalance AND
   * replace it in the v3 closure via the install mechanism.
   * ──────────────────────────────────────────────────────────────────────── */
  async function computeRealBalanceV4(ownerId) {
    const db = _db();
    if (!db || !ownerId) {
      return { earned: 0, groundEarned: 0, poolEarned: 0, tournamentEarned: 0,
               transferred: 0, locked: 0, available: 0, pendingRequests: [] };
    }

    /* ── 1. Ground bookings (confirmed) ── */
    // Triple-net query: bookingStatus:'confirmed', paymentStatus:'success', or paymentStatus:'paid'
    const [gByBookingStatus, gByPaySuccess, gByPayPaid] = await Promise.all([
      db.collection('bookings').where('ownerId','==',ownerId).where('bookingStatus','==','confirmed')
        .get().catch(() => ({ docs: [] })),
      db.collection('bookings').where('ownerId','==',ownerId).where('paymentStatus','==','success')
        .get().catch(() => ({ docs: [] })),
      db.collection('bookings').where('ownerId','==',ownerId).where('paymentStatus','==','paid')
        .get().catch(() => ({ docs: [] })),
    ]);

    let groundEarned = 0;
    const seenGround = new Set();
    [...gByBookingStatus.docs, ...gByPaySuccess.docs, ...gByPayPaid.docs].forEach(d => {
      if (seenGround.has(d.id)) return;
      seenGround.add(d.id);
      const data = d.data();
      // Skip cancelled or failed bookings
      const st = data.bookingStatus || data.status || '';
      if (st === 'cancelled' || st === 'failed') return;
      if (data.payoutStatus === 'payout_done') return; // only exclude fully-transferred bookings from earned total
      const amt = Number(data.ownerAmount);
      // 7% platform commission → owner gets 93%
      groundEarned += amt > 0 ? amt : Math.floor(Number(data.amount || data.totalAmount || 0) * 0.93);
    });

    /* ── 2. Pool bookings — FIXED: Query only confirmed status (no triple-net to prevent double-count) ── */
    // NOTE: We set BOTH status AND bookingStatus to 'confirmed', so we only need to query one
    // Triple-net queries caused double-counting when same document matched multiple fields
    const pByStatus = await db.collection('pool_bookings').where('ownerId','==',ownerId).where('status','==','confirmed')
      .get().catch(() => ({ docs: [] }));

    let poolEarned = 0;
    const seenPool = new Set();
    pByStatus.docs.forEach(d => {
      if (seenPool.has(d.id)) return;
      seenPool.add(d.id);
      const data = d.data();
      // Skip if cancelled or pending
      const st = data.status || data.bookingStatus || '';
      if (st === 'cancelled' || st === 'failed') return;
      if (data.payoutStatus === 'payout_done') return; // only exclude fully-transferred bookings from earned total
      const amt = Number(data.ownerAmount);
      // 7% platform commission → owner gets 93%
      poolEarned += amt > 0 ? amt : Math.floor(Number(data.amount || 0) * 0.93);
    });

    /* ── 3. Tournament earnings ── */
    let tournamentEarned = 0;
    try {
      const tSnap = await db.collection('tournaments').where('ownerId','==',ownerId)
        .get().catch(() => ({ docs: [] }));
      if (!tSnap.empty) {
        const ids = tSnap.docs.map(d => d.id);
        for (let i = 0; i < ids.length; i += 30) {
          const eSnap = await db.collection('tournament_entries')
            .where('tournamentId','in', ids.slice(i, i + 30))
            .get().catch(() => ({ docs: [] }));
          eSnap.docs.forEach(d => {
            const e = d.data();
            if (e.status !== 'confirmed' && e.paymentStatus !== 'paid') return;
            if (e.payoutStatus === 'payout_done') return; // only exclude fully-transferred entries
            tournamentEarned += Number(e.ownerAmount) || Math.round(Number(e.amount || 0) * 0.8);
          });
        }
      }
    } catch (_) {}

    const totalEarned = groundEarned + poolEarned + tournamentEarned;

    /* ── 4. Transferred + locked ── */
    const [transferSnap, allPayoutSnap] = await Promise.all([
      db.collection('owner_transfers').where('ownerId','==',ownerId)
        .get().catch(() => ({ docs: [] })),
      db.collection('payout_requests').where('ownerId','==',ownerId)
        .get().catch(() => ({ docs: [] })),
    ]);

    let totalTransferred = 0;
    transferSnap.docs.forEach(d => { totalTransferred += Number(d.data().amount || 0); });

    let totalLocked = 0, paidFromRequests = 0;
    const pendingRequests = [];
    allPayoutSnap.docs.forEach(d => {
      const p = d.data();
      const st = p.status || 'pending';
      if (st === 'pending' || st === 'approved') {
        totalLocked += Number(p.amount || 0);
        pendingRequests.push({ id: d.id, ...p });
      } else if (st === 'paid' || st === 'completed') {
        paidFromRequests += Number(p.amount || 0);
      }
    });

    // NOTE: Do NOT fall back to paid payout_requests as 'transferred'.
    // payout_done bookings are already excluded from totalEarned, so adding
    // paidFromRequests here would double-deduct those amounts.
    if (totalTransferred === 0 && paidFromRequests > 0) {
      // Do NOT set totalTransferred = paidFromRequests (double-deduction bug)
      W('[payout-fix] owner_transfers empty; paidFromRequests ignored to prevent double-deduction. Earned:', totalEarned);
    }

    const available = Math.max(0, totalEarned - totalTransferred - totalLocked);

    L('balance v4 for', ownerId, '→ earned:', totalEarned,
      '| ground:', groundEarned, '| pool:', poolEarned,
      '| transferred:', totalTransferred, '| locked:', totalLocked,
      '| available:', available);

    return { earned: totalEarned, groundEarned, poolEarned, tournamentEarned,
             transferred: totalTransferred, locked: totalLocked, available, pendingRequests };
  }

  // Expose so the earnings tab renderer picks it up
  window._efComputeRealBalance = computeRealBalanceV4;

  // Patch the renderer wrapper that v3 installs
  function patchEarningsCompute() {
    const origRender = window.loadOwnerEarnings || window._bmgLoadOwnerEarningsFull;
    if (typeof origRender !== 'function') return false;

    // We wrap the installed renderer so it calls our v4 balance fn
    const wrappedRender = async function (container) {
      // Temporarily override the balance fn that the renderer calls
      const prev = window._efComputeRealBalance;
      window._efComputeRealBalance = computeRealBalanceV4;
      try {
        return await origRender.call(this, container);
      } finally {
        window._efComputeRealBalance = prev;
      }
    };

    // The v3 renderer calls computeRealBalance which is closed over inside the IIFE.
    // We can't reach it directly, so we inject our own renderEarningsTab that uses v4.
    window.loadOwnerEarnings         = buildEarningsRenderer();
    window._bmgLoadOwnerEarningsFull = window.loadOwnerEarnings;
    L('✅ Earnings renderer patched to v4 (7% commission, pool triple-net)');
    return true;
  }

  function _fmt(n) {
    return '₹' + Number(n || 0).toLocaleString('en-IN', { maximumFractionDigits: 0 });
  }
  function _isoDate(daysBack) {
    const d = new Date(); d.setDate(d.getDate() - daysBack); return d.toISOString().split('T')[0];
  }
  function _esc(s) {
    return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  function buildEarningsRenderer() {
    return async function renderEarningsTabV4(container) {
      const cu = _cu(), db = _db();
      if (!cu || !db) {
        if (container) container.innerHTML = '<p style="text-align:center;padding:32px;color:#9ca3af;">Please log in to view earnings.</p>';
        return;
      }

      if (typeof window.showLoading === 'function') window.showLoading('Calculating earnings…');

      try {
        const bal = await computeRealBalanceV4(cu.uid);

        /* Period stats — ground bookings (triple-net query) */
        const today = _isoDate(0), week = _isoDate(6), month = _isoDate(29);
        let todayE = 0, weekE = 0, monthE = 0;
        const [gPS1, gPS2, gPS3] = await Promise.all([
          db.collection('bookings').where('ownerId','==',cu.uid).where('bookingStatus','==','confirmed').get().catch(()=>({docs:[]})),
          db.collection('bookings').where('ownerId','==',cu.uid).where('paymentStatus','==','success').get().catch(()=>({docs:[]})),
          db.collection('bookings').where('ownerId','==',cu.uid).where('paymentStatus','==','paid').get().catch(()=>({docs:[]})),
        ]);
        const seenG = new Set();
        [...gPS1.docs,...gPS2.docs,...gPS3.docs].forEach(d => {
          if (seenG.has(d.id)) return; seenG.add(d.id);
          const b = d.data();
          const gst = b.bookingStatus || b.status || '';
          if (gst === 'cancelled' || gst === 'failed') return;
          if (b.payoutStatus === 'payout_done') return;
          const amt = Number(b.ownerAmount) || Math.floor(Number(b.amount || 0) * 0.93);
          if (b.date === today) todayE += amt;
          if (b.date >= week)   weekE  += amt;
          if (b.date >= month)  monthE += amt;
        });

        /* Period stats — pool bookings */
        const [pS1, pS2, pS3] = await Promise.all([
          db.collection('pool_bookings').where('ownerId','==',cu.uid).where('status','==','confirmed').get().catch(()=>({docs:[]})),
          db.collection('pool_bookings').where('ownerId','==',cu.uid).where('bookingStatus','==','confirmed').get().catch(()=>({docs:[]})),
          db.collection('pool_bookings').where('ownerId','==',cu.uid).where('paymentStatus','==','success').get().catch(()=>({docs:[]})),
        ]);
        const seenP = new Set();
        [...pS1.docs,...pS2.docs,...pS3.docs].forEach(d => {
          if (seenP.has(d.id)) return; seenP.add(d.id);
          const b = d.data();
          const st = b.status || b.bookingStatus || '';
          if (st === 'cancelled' || st === 'failed') return;
          if (b.payoutStatus === 'payout_done') return;
          const amt = Number(b.ownerAmount) || Math.floor(Number(b.amount || 0) * 0.93);
          const dt = b.date || '';
          if (dt === today) todayE += amt;
          if (dt >= week)   weekE  += amt;
          if (dt >= month)  monthE += amt;
        });

        if (typeof window.hideLoading === 'function') window.hideLoading();

        const pendingNotice = bal.pendingRequests.length > 0
          ? `<div style="background:#fffbeb;border:1px solid #fde68a;border-radius:12px;padding:12px 14px;margin-bottom:16px;display:flex;align-items:center;gap:10px;">
              <i class="fas fa-clock" style="color:#f59e0b;font-size:16px;flex-shrink:0;"></i>
              <div>
                <div style="font-weight:700;color:#92400e;font-size:13px;">Payout Under Review</div>
                <div style="font-size:12px;color:#b45309;margin-top:2px;">${_fmt(bal.locked)} is locked in a pending payout request.</div>
              </div>
            </div>` : '';

        if (container) container.innerHTML = `
          <!-- Period stats -->
          <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:16px;">
            ${[['Today', todayE], ['This Week', weekE], ['This Month', monthE]].map(([label, val]) => `
              <div style="background:#f0f4ff;border-radius:12px;padding:12px;text-align:center;">
                <div style="font-size:10px;font-weight:700;color:#6b7280;text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px;">${label}</div>
                <div style="font-size:18px;font-weight:800;color:#2563eb;">${_fmt(val)}</div>
              </div>`).join('')}
          </div>

          <!-- Balance hero -->
          <div style="background:linear-gradient(135deg,#1b2e6c,#2563eb);border-radius:16px;padding:20px;margin-bottom:16px;color:#fff;">
            <div style="font-size:12px;opacity:.8;margin-bottom:6px;"><i class="fas fa-wallet"></i> Available to Withdraw</div>
            <div style="font-size:34px;font-weight:800;letter-spacing:-0.6px;margin-bottom:4px;">${_fmt(bal.available)}</div>
            <div style="font-size:11px;opacity:.7;">Total earned minus transferred &amp; pending</div>
            <div style="margin-top:12px;background:rgba(255,255,255,.12);border-radius:10px;padding:10px 12px;">
              <div style="display:flex;justify-content:space-between;margin-bottom:6px;">
                <span style="font-size:12px;opacity:.85;">Total Earned (after 7% platform fee)</span>
                <span style="font-size:13px;font-weight:700;">${_fmt(bal.earned)}</span>
              </div>
              ${bal.transferred > 0 ? `
              <div style="display:flex;justify-content:space-between;margin-bottom:6px;">
                <span style="font-size:12px;opacity:.85;">Already Transferred</span>
                <span style="font-size:13px;font-weight:700;color:#86efac;">− ${_fmt(bal.transferred)}</span>
              </div>` : ''}
              ${bal.locked > 0 ? `
              <div style="display:flex;justify-content:space-between;margin-bottom:6px;">
                <span style="font-size:12px;opacity:.85;">In Review (pending)</span>
                <span style="font-size:13px;font-weight:700;color:#fde047;">− ${_fmt(bal.locked)}</span>
              </div>` : ''}
              <div style="border-top:1px solid rgba(255,255,255,.2);margin-top:8px;padding-top:8px;display:flex;justify-content:space-between;">
                <span style="font-size:12px;font-weight:700;">Available Now</span>
                <span style="font-size:14px;font-weight:800;color:#86efac;">${_fmt(bal.available)}</span>
              </div>
            </div>
          </div>

          <!-- Earnings breakdown -->
          <div style="background:#fff;border:1.5px solid #e8edf8;border-radius:14px;padding:14px;margin-bottom:16px;">
            <div style="font-size:13px;font-weight:800;color:#0f1f5c;margin-bottom:10px;">
              <i class="fas fa-chart-bar" style="color:#2563eb;margin-right:6px;"></i>Earnings Breakdown
              <span style="float:right;font-size:11px;font-weight:600;color:#6b7280;background:#f0f4ff;padding:2px 8px;border-radius:20px;">Platform: 7% commission</span>
            </div>
            <div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #f0f4ff;">
              <span style="font-size:13px;color:#374151;"><i class="fas fa-futbol" style="color:#22c55e;margin-right:6px;width:14px;"></i>Ground Bookings</span>
              <span style="font-size:13px;font-weight:700;color:#15803d;">${_fmt(bal.groundEarned)}</span>
            </div>
            <div style="display:flex;justify-content:space-between;padding:8px 0;${bal.tournamentEarned > 0 ? 'border-bottom:1px solid #f0f4ff;' : ''}">
              <span style="font-size:13px;color:#374151;"><i class="fas fa-swimming-pool" style="color:#0ea5e9;margin-right:6px;width:14px;"></i>Pool Bookings</span>
              <span style="font-size:13px;font-weight:700;color:#0369a1;">${_fmt(bal.poolEarned)}</span>
            </div>
            ${bal.tournamentEarned > 0 ? `
            <div style="display:flex;justify-content:space-between;padding:8px 0;">
              <span style="font-size:13px;color:#374151;"><i class="fas fa-trophy" style="color:#7c3aed;margin-right:6px;width:14px;"></i>Tournaments</span>
              <span style="font-size:13px;font-weight:700;color:#7c3aed;">${_fmt(bal.tournamentEarned)}</span>
            </div>` : ''}
            <div style="display:flex;justify-content:space-between;padding:8px 0;border-top:2px solid #e8edf8;margin-top:4px;">
              <span style="font-size:13px;font-weight:700;color:#0f1f5c;">Total Earned</span>
              <span style="font-size:14px;font-weight:800;color:#0f1f5c;">${_fmt(bal.earned)}</span>
            </div>
          </div>

          ${pendingNotice}

          <!-- CTA -->
          ${bal.available > 0
            ? `<div style="background:#f0fdf4;border:1.5px solid #86efac;border-radius:14px;padding:14px;">
                <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;">
                  <i class="fas fa-check-circle" style="color:#22c55e;font-size:18px;"></i>
                  <div>
                    <div style="font-weight:700;color:#15803d;font-size:13px;">${_fmt(bal.available)} Ready to Withdraw</div>
                    <div style="font-size:12px;color:#166534;">Processed within 2–3 business days</div>
                  </div>
                </div>
                <button onclick="window._bmgOpenPayoutModal()"
                  style="width:100%;padding:13px;background:linear-gradient(135deg,#22c55e,#16a34a);color:#fff;border:none;border-radius:12px;font-weight:700;font-size:14px;cursor:pointer;font-family:inherit;">
                  <i class="fas fa-paper-plane" style="margin-right:6px;"></i> Request Payout
                </button>
              </div>`
            : `<div style="background:#fffbeb;border:1.5px solid #fde68a;border-radius:14px;padding:14px;display:flex;align-items:center;gap:10px;">
                <i class="fas fa-info-circle" style="color:#f59e0b;font-size:16px;"></i>
                <div>
                  <div style="font-weight:700;color:#92400e;font-size:13px;">${bal.earned > 0 ? (bal.locked > 0 ? 'Payout In Progress' : 'All Earnings Transferred') : 'No Earnings Yet'}</div>
                  <div style="font-size:12px;color:#b45309;">${bal.locked > 0
                      ? `${_fmt(bal.locked)} is under a pending payout request.`
                      : bal.transferred > 0
                        ? `${_fmt(bal.transferred)} has been paid out to your account.`
                        : 'Earnings appear here after your first confirmed booking.'}</div>
                </div>
              </div>`}
        `;

        window._bmgCurrentBalance = bal;

      } catch (err) {
        if (typeof window.hideLoading === 'function') window.hideLoading();
        W('renderEarningsTabV4 error:', err.message);
        if (container) container.innerHTML = `
          <div style="text-align:center;padding:32px;color:#ef4444;">
            <i class="fas fa-exclamation-triangle" style="font-size:24px;margin-bottom:8px;display:block;"></i>
            <div style="font-weight:600;">Failed to load earnings</div>
            <div style="font-size:12px;color:#9ca3af;margin-top:4px;">${_esc(err.message)}</div>
            <button onclick="window._bmgFixReloadEarnings()"
              style="margin-top:12px;padding:8px 20px;background:#2563eb;color:#fff;border:none;border-radius:8px;cursor:pointer;font-size:13px;">
              Retry
            </button>
          </div>`;
      }
    };
  }

  /* ────────────────────────────────────────────────────────────────────────
   * FIX 2 — Entry Pass popup instantly after payment return
   *
   * Root cause: The bmg:paymentConfirmed listener in sportobook_patches_merged.js
   * only handles paymentType='booking' for ground bookings — it does NOT handle
   * paymentType='pool'. This means:
   *   a) window._lastConfirmedBookingId is never set for pool payments
   *   b) showBookingSuccessConfirmation is never called for pool payments
   *   c) The view-entry-pass-btn remains hidden after pool payment
   *
   * Additionally, for BOTH ground and pool, we need to ensure:
   *   - window._lastConfirmedBookingId is always set before showPage fires
   *   - The view-entry-pass-btn is shown and wired correctly
   *
   * Fix: wrap bmg:paymentConfirmed to always set the bookingId and show button.
   * ──────────────────────────────────────────────────────────────────────── */
  (function patchEntryPassAfterPayment() {
    const _deduped = new Set();

    window.addEventListener('bmg:paymentConfirmed', function (e) {
      if (!e || !e.detail) return;
      const { orderId, paymentType, result } = e.detail;
      if (!orderId) return;

      const key = orderId + '_' + paymentType;
      if (_deduped.has(key)) return;
      _deduped.add(key);
      setTimeout(() => _deduped.delete(key), 60000);

      // For ground bookings: result may contain bookingId
      // For pool bookings: orderId IS the bookingId (pool_bookings doc ID)
      const bid = (result && result.bookingId) || orderId;

      L('paymentConfirmed → setting _lastConfirmedBookingId:', bid, 'type:', paymentType);

      // Always store bookingId so showEntryPassFromConfirmation can find it
      window._lastConfirmedBookingId = bid;
      try { sessionStorage.setItem('lastBookingId', bid); } catch (_) {}

      // For pool bookings — call showBookingSuccessConfirmation if not already shown
      if (paymentType === 'pool') {
        if (typeof window.showBookingSuccessConfirmation === 'function') {
          const pending = (() => {
            try { return JSON.parse(sessionStorage.getItem('pendingBooking') || '{}'); } catch(_) { return {}; }
          })();
          const poolBookingData = {
            bookingId   : bid,
            venueName   : pending.poolName || 'Swimming Pool',
            groundName  : pending.poolName || 'Swimming Pool',
            groundAddress: pending.poolAddress || pending.address || '',
            date        : pending.date || '',
            slotTime    : pending.slotTime || '',
            amount      : pending.amount || 0,
            userPhone   : pending.userPhone || '',
          };
          // Small delay to let finalisePoolBooking complete first
          setTimeout(() => {
            window.showBookingSuccessConfirmation(result || poolBookingData);
          }, 600);
        }
      }

      // Ensure entry pass button is visible regardless of payment type
      setTimeout(function () {
        const btn = document.getElementById('view-entry-pass-btn');
        if (btn) {
          btn.style.display = 'block';
          // Re-stamp bookingId on the confirmation details element
          const det = document.getElementById('confirmation-details');
          if (det && bid) det.dataset.bookingId = bid;
          L('view-entry-pass-btn shown for bookingId:', bid);
        }
      }, 800);
    }, true /* capture — runs before other listeners */);

    // Also patch showEntryPassFromConfirmation to have a more robust bookingId lookup
    const _origFromConf = window.showEntryPassFromConfirmation;
    window.showEntryPassFromConfirmation = function () {
      const bid = window._lastConfirmedBookingId
        || (document.getElementById('confirmation-details') && document.getElementById('confirmation-details').dataset.bookingId)
        || document.querySelector('[data-booking-id]')?.dataset?.bookingId
        || document.querySelector('.booking-id')?.textContent?.trim()
        || (() => { try { return sessionStorage.getItem('lastBookingId'); } catch(_){return '';} })();

      if (bid && bid.length >= 3) {
        L('showEntryPassFromConfirmation → bookingId:', bid);
        if (typeof window.showEntryPass === 'function') {
          window.showEntryPass(bid);
        } else if (typeof _origFromConf === 'function') {
          _origFromConf.call(this);
        }
      } else {
        W('showEntryPassFromConfirmation: bookingId not found');
        if (typeof window._bmgToast === 'function') {
          window._bmgToast('Booking ID not found. Please check My Bookings.', 'warning');
        }
      }
    };

    L('✅ Entry pass fix installed (pool + ground, instant popup)');
  })();

  /* ────────────────────────────────────────────────────────────────────────
   * FIX 3 — Pool price not updating in booking page after owner edits
   *
   * Root cause: ensurePoolSlotDocs correctly writes new price to existing
   * slot docs, but renderPoolSlots / buildPoolSlotEl reads price from
   * the slot snapshot doc. When an owner updates basePricePerMember,
   * the EXISTING snapshot docs in the real-time listener may be stale
   * because the listener was started before the owner's update propagated.
   *
   * Also: openPoolPage always fetches fresh pool data (good), but then
   * loadPoolSlots calls ensurePoolSlotDocs which only updates docs where
   * price differs. The real-time listener then fires with the UPDATED docs.
   * The actual issue is that the price displayed on the pool listing cards
   * (bmg-pool-card-price) uses pool.basePricePerMember from the pool list
   * cache — NOT the fresh fetch.
   *
   * Fix A: After savePoolEdits, refresh the pool card display in the
   *        owner dashboard AND the pool page if currently open.
   * Fix B: In buildPoolSlotEl and renderPoolSlots, always prefer the
   *        slot doc's basePricePerMember but fall back to the FRESH
   *        currentPool object (which openPoolPage always re-fetches).
   * Fix C: When the pool page opens, force-refresh basePricePerMember
   *        display after slots load.
   * ──────────────────────────────────────────────────────────────────────── */
  (function patchPoolPriceRefresh() {

    // Patch savePoolEdits to refresh the pool page price after save
    const _origSavePoolEdits = window.savePoolEdits;
    if (typeof _origSavePoolEdits === 'function') {
      window.savePoolEdits = async function () {
        await _origSavePoolEdits.apply(this, arguments);
        // After save, if the pool page is open for the same pool, refresh it
        try {
          const poolId = document.getElementById('ep-pool-id')?.value;
          const cp = window.currentPool;
          if (poolId && cp && cp.id === poolId && typeof window.openPoolPage === 'function') {
            // Small delay for Firestore propagation
            setTimeout(() => {
              window.openPoolPage(poolId);
              L('Pool page refreshed after price edit');
            }, 800);
          }
        } catch (_) {}
      };
      L('✅ savePoolEdits patched to refresh pool page');
    }

    // Patch openPoolPage to always update price elements after slots load
    const _origOpenPool = window.openPoolPage;
    if (typeof _origOpenPool === 'function') {
      window.openPoolPage = async function (poolOrId) {
        await _origOpenPool.apply(this, arguments);
        // After page shows, sync the price display with whatever currentPool has
        setTimeout(function () {
          const cp = window.currentPool;
          if (!cp) return;
          const priceEl = document.getElementById('pool-base-price');
          if (priceEl) priceEl.textContent = '₹' + (cp.basePricePerMember || 0);
          // Also refresh all visible slot price elements in case stale
          document.querySelectorAll('.bmg-pool-slot-price').forEach(el => {
            // We can't re-compute dynamic price here without slot data,
            // but we update the pool detail header price
          });
          L('Pool price display synced: ₹' + (cp.basePricePerMember || 0));
        }, 500);
      };
      L('✅ openPoolPage patched to sync price display');
    }

    // Patch loadPoolSlots (which calls ensurePoolSlotDocs) to use fresh pool data
    // The key insight: when slots are rendered via the real-time listener snapshot,
    // buildPoolSlotEl reads slot.basePricePerMember. After ensurePoolSlotDocs updates
    // the slot doc with the new price, the listener fires again with fresh data.
    // But if ensurePoolSlotDocs is not called (e.g., slots already exist and were
    // not updated because the price check used a stale pool object), we force it.
    const _origLoadPoolSlots = window.loadPoolSlots;
    if (typeof _origLoadPoolSlots === 'function') {
      window.loadPoolSlots = async function (poolId, date) {
        // Always fetch fresh pool data before loading slots so ensurePoolSlotDocs
        // has the latest basePricePerMember to compare against
        const db = _db();
        if (db && poolId) {
          try {
            const freshDoc = await db.collection('swimming_pools').doc(poolId).get();
            if (freshDoc.exists) {
              const freshPool = { id: freshDoc.id, ...freshDoc.data() };
              // Update currentPool so buildPoolSlotEl has fresh price
              window.currentPool = freshPool;
              L('Pool data refreshed before slot load — price: ₹' + (freshPool.basePricePerMember || 0));
            }
          } catch (_) {}
        }
        return _origLoadPoolSlots.apply(this, arguments);
      };
      L('✅ loadPoolSlots patched to fetch fresh pool data');
    }

    L('✅ Pool price refresh patch installed');
  })();

  /* ────────────────────────────────────────────────────────────────────────
   * FIX 4 — Swimming Pool Write Review not working
   *
   * Root cause: The pool-write-review-btn click handler calls
   *   showWriteReviewModal({ id, groundName })
   * but showWriteReviewModal is NEVER DEFINED anywhere in the codebase.
   * The existing showWriteReview() function only works for grounds (reads
   * from currentGround, not currentPool), and the review modal hard-codes
   * groundId in the submission.
   *
   * Fix: Define window.showWriteReviewModal that:
   *   1. Opens the existing write-review-modal (creating it if needed)
   *   2. Stores the pool/ground context so submitReview can use it
   *   3. Handles both pool reviews (pool_reviews collection) and
   *      ground reviews (reviews collection)
   *   4. Re-wires the pool-write-review-btn with the correct handler
   * ──────────────────────────────────────────────────────────────────────── */
  (function patchPoolReview() {

    // Ensure the review modal exists (createReviewModal may not have been called yet)
    function ensureReviewModal() {
      if (document.getElementById('write-review-modal')) return;
      if (typeof window.createReviewModal === 'function') {
        window.createReviewModal();
      } else {
        // Build minimal modal inline
        const div = document.createElement('div');
        div.innerHTML = `
          <div id="write-review-modal" class="modal" style="display:none;">
            <div class="modal-content" style="max-width:420px;margin:auto;background:#fff;border-radius:18px;padding:24px;box-shadow:0 20px 60px rgba(0,0,0,.2);">
              <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:18px;">
                <h3 style="margin:0;font-size:18px;font-weight:800;"><i class="fas fa-star" style="color:#f59e0b;margin-right:6px;"></i> Write a Review</h3>
                <button id="close-write-review-modal" style="background:none;border:none;font-size:22px;cursor:pointer;color:#6b7280;">&times;</button>
              </div>
              <div style="margin-bottom:16px;">
                <label style="font-size:13px;font-weight:700;color:#374151;display:block;margin-bottom:8px;">Your Rating</label>
                <div id="star-rating-large" style="display:flex;gap:6px;font-size:28px;cursor:pointer;">
                  <i class="far fa-star" data-rating="1" style="color:#f59e0b;"></i>
                  <i class="far fa-star" data-rating="2" style="color:#f59e0b;"></i>
                  <i class="far fa-star" data-rating="3" style="color:#f59e0b;"></i>
                  <i class="far fa-star" data-rating="4" style="color:#f59e0b;"></i>
                  <i class="far fa-star" data-rating="5" style="color:#f59e0b;"></i>
                </div>
                <input type="hidden" id="review-rating" value="0">
                <div id="rating-text" style="font-size:12px;color:#9ca3af;margin-top:4px;">Tap a star to rate</div>
              </div>
              <div style="margin-bottom:16px;">
                <label style="font-size:13px;font-weight:700;color:#374151;display:block;margin-bottom:8px;">Your Review</label>
                <textarea id="review-text" style="width:100%;min-height:100px;padding:12px;border:1.5px solid #e5e7eb;border-radius:10px;font-size:14px;font-family:inherit;resize:vertical;box-sizing:border-box;" placeholder="Share your experience…" maxlength="500"></textarea>
                <div id="review-character-count" style="font-size:11px;color:#9ca3af;text-align:right;margin-top:4px;">0 / 500</div>
              </div>
              <button id="submit-review-btn" style="width:100%;padding:14px;background:linear-gradient(135deg,#f59e0b,#d97706);color:#fff;border:none;border-radius:12px;font-weight:700;font-size:15px;cursor:pointer;">
                <i class="fas fa-paper-plane"></i> Submit Review
              </button>
            </div>
          </div>`;
        document.body.appendChild(div.firstElementChild);
      }

      // Wire star rating
      const starContainer = document.getElementById('star-rating-large');
      if (starContainer && !starContainer._wired) {
        starContainer._wired = true;
        starContainer.querySelectorAll('i').forEach(star => {
          star.addEventListener('click', function () {
            const rating = parseInt(this.dataset.rating);
            document.getElementById('review-rating').value = rating;
            starContainer.querySelectorAll('i').forEach((s, i) => {
              s.className = i < rating ? 'fas fa-star' : 'far fa-star';
            });
            const labels = ['','Poor','Fair','Good','Very Good','Excellent'];
            const rt = document.getElementById('rating-text');
            if (rt) rt.textContent = labels[rating] || '';
          });
        });
      }

      // Wire char counter
      const ta = document.getElementById('review-text');
      if (ta && !ta._wired) {
        ta._wired = true;
        ta.addEventListener('input', function () {
          const cc = document.getElementById('review-character-count');
          if (cc) cc.textContent = this.value.length + ' / 500';
        });
      }

      // Wire close button
      const closeBtn = document.getElementById('close-write-review-modal');
      if (closeBtn && !closeBtn._wired) {
        closeBtn._wired = true;
        closeBtn.addEventListener('click', function () {
          const m = document.getElementById('write-review-modal');
          if (m) { m.style.display = 'none'; m.classList.remove('active'); }
        });
      }
    }

    // Context store for the current review target (pool or ground)
    window._reviewContext = window._reviewContext || { type: null, id: null, name: null };

    // showWriteReviewModal — handles both pool and ground objects
    window.showWriteReviewModal = function (entity) {
      const cu = window.currentUser;
      if (!cu) {
        if (typeof window.showToast === 'function') window.showToast('Please log in to write a review', 'warning');
        return;
      }

      const id   = entity && (entity.id || entity.groundId || entity.poolId);
      const name = entity && (entity.poolName || entity.groundName || entity.name || '');

      if (!id) {
        if (typeof window.showToast === 'function') window.showToast('Could not identify venue', 'error');
        return;
      }

      // Determine type: pool (has poolName or entity came from pool context) vs ground
      const isPool = !!(entity.poolName || entity.isPool ||
                        (window.currentPool && window.currentPool.id === id));

      window._reviewContext = { type: isPool ? 'pool' : 'ground', id, name };
      L('showWriteReviewModal →', window._reviewContext);

      ensureReviewModal();

      // Check for duplicate review
      const db = _db();
      const collection = isPool ? 'pool_reviews' : 'reviews';
      const fieldId    = isPool ? 'poolId' : 'groundId';

      db.collection(collection)
        .where(fieldId, '==', id)
        .where('userId', '==', cu.uid)
        .get()
        .then(snap => {
          if (!snap.empty) {
            if (typeof window.showToast === 'function')
              window.showToast('You have already reviewed this ' + (isPool ? 'pool' : 'ground'), 'warning');
            return;
          }

          // Reset form
          const ratingEl = document.getElementById('review-rating');
          const textEl   = document.getElementById('review-text');
          const ccEl     = document.getElementById('review-character-count');
          const rtEl     = document.getElementById('rating-text');
          if (ratingEl) ratingEl.value = '0';
          if (textEl)   textEl.value   = '';
          if (ccEl)     ccEl.textContent = '0 / 500';
          if (rtEl)     rtEl.textContent = 'Tap a star to rate';
          document.querySelectorAll('#star-rating-large i').forEach(s => { s.className = 'far fa-star'; });

          // Show modal
          const modal = document.getElementById('write-review-modal');
          if (modal) { modal.style.display = 'flex'; modal.classList.add('active'); }

          // Wire submit button for this context
          const submitBtn = document.getElementById('submit-review-btn');
          if (submitBtn) {
            // Remove old listener by replacing the node
            const newBtn = submitBtn.cloneNode(true);
            submitBtn.parentNode.replaceChild(newBtn, submitBtn);
            newBtn.addEventListener('click', submitPoolOrGroundReview);
          }
        })
        .catch(err => {
          W('showWriteReviewModal check error:', err.message);
          const modal = document.getElementById('write-review-modal');
          if (modal) { modal.style.display = 'flex'; modal.classList.add('active'); }
        });
    };

    // Universal review submit — works for both pool and ground
    async function submitPoolOrGroundReview() {
      const ctx    = window._reviewContext || {};
      const rating = parseInt(document.getElementById('review-rating')?.value || '0');
      const comment = (document.getElementById('review-text')?.value || '').trim();
      const cu     = window.currentUser;
      const db     = _db();

      if (!cu || !db) {
        if (typeof window.showToast === 'function') window.showToast('Please log in', 'error');
        return;
      }
      if (!ctx.id) {
        if (typeof window.showToast === 'function') window.showToast('Review target not set', 'error');
        return;
      }
      if (!rating) {
        if (typeof window.showToast === 'function') window.showToast('Please select a rating', 'error');
        return;
      }
      if (!comment || comment.length < 10) {
        if (typeof window.showToast === 'function') window.showToast('Please write at least 10 characters', 'error');
        return;
      }

      const submitBtn = document.getElementById('submit-review-btn');
      if (submitBtn) { submitBtn.disabled = true; submitBtn.innerHTML = '<i class="fas fa-spinner fa-pulse"></i> Submitting…'; }
      if (typeof window.showLoading === 'function') window.showLoading('Submitting review…');

      try {
        const isPool     = ctx.type === 'pool';
        const collection = isPool ? 'pool_reviews' : 'reviews';
        const fieldId    = isPool ? 'poolId' : 'groundId';
        const ts         = window.firebase && window.firebase.firestore
          ? window.firebase.firestore.FieldValue.serverTimestamp()
          : new Date();

        // Duplicate check
        const existSnap = await db.collection(collection)
          .where(fieldId, '==', ctx.id)
          .where('userId', '==', cu.uid)
          .get();
        if (!existSnap.empty) {
          if (typeof window.showToast === 'function') window.showToast('You already reviewed this', 'warning');
          const modal = document.getElementById('write-review-modal');
          if (modal) { modal.style.display = 'none'; modal.classList.remove('active'); }
          return;
        }

        const reviewData = {
          [fieldId]   : ctx.id,
          userId      : cu.uid,
          userName    : cu.name || cu.ownerName || cu.displayName || 'User',
          userEmail   : cu.email || '',
          rating,
          comment,
          venueName   : ctx.name || '',
          createdAt   : ts,
          updatedAt   : ts,
        };

        await db.collection(collection).add(reviewData);

        // Update average rating on the target document
        const allReviews = await db.collection(collection).where(fieldId, '==', ctx.id).get();
        let totalRating = 0;
        allReviews.forEach(d => { totalRating += d.data().rating; });
        const avgRating = totalRating / allReviews.size;

        const targetCollection = isPool ? 'swimming_pools' : 'grounds';
        await db.collection(targetCollection).doc(ctx.id).update({
          rating      : avgRating,
          totalReviews: allReviews.size,
          updatedAt   : ts,
        }).catch(() => {}); // non-critical

        if (typeof window.hideLoading === 'function') window.hideLoading();
        if (typeof window.showToast   === 'function') window.showToast('Review submitted! Thank you 🌟', 'success');

        const modal = document.getElementById('write-review-modal');
        if (modal) { modal.style.display = 'none'; modal.classList.remove('active'); }

        // Refresh reviews list if on pool page
        if (isPool && typeof window.loadPoolReviews === 'function') {
          window.loadPoolReviews(ctx.id);
        } else if (!isPool && typeof window.loadGroundReviews === 'function') {
          window.loadGroundReviews(ctx.id);
        }

        L('✅ Review submitted to', collection, 'for', ctx.id);

      } catch (err) {
        if (typeof window.hideLoading === 'function') window.hideLoading();
        W('submitPoolOrGroundReview error:', err.message);
        if (typeof window.showToast === 'function') window.showToast('Error submitting review: ' + err.message, 'error');
      } finally {
        if (submitBtn) { submitBtn.disabled = false; submitBtn.innerHTML = '<i class="fas fa-paper-plane"></i> Submit Review'; }
      }
    }

    // Re-wire the pool write-review button every time the pool page becomes visible
    function wirePoolReviewBtn() {
      const btn = document.getElementById('pool-write-review-btn');
      if (!btn || btn._v4Wired) return;
      btn._v4Wired = true;
      // Remove old listener
      const newBtn = btn.cloneNode(true);
      btn.parentNode.replaceChild(newBtn, btn);
      newBtn._v4Wired = true;
      newBtn.addEventListener('click', function () {
        const cp = window.currentPool;
        if (!cp) { if (typeof window.showToast === 'function') window.showToast('Pool info not loaded', 'error'); return; }
        window.showWriteReviewModal({ id: cp.id, poolName: cp.poolName, isPool: true });
      });
      L('✅ pool-write-review-btn re-wired');
    }

    // Wire immediately and on page transitions
    wirePoolReviewBtn();
    window.addEventListener('bmg:pageShown', function (e) {
      if (e.detail && e.detail.pageId === 'pool-page') {
        setTimeout(wirePoolReviewBtn, 200);
      }
    });

    // MutationObserver to catch when pool page content is injected
    (function observePoolPage() {
      const poolPage = document.getElementById('pool-page');
      if (poolPage) {
        new MutationObserver(wirePoolReviewBtn).observe(poolPage, { childList: true, subtree: true });
      } else {
        setTimeout(observePoolPage, 600);
      }
    })();

    L('✅ Pool review fix installed (showWriteReviewModal defined, pool_reviews collection)');
  })();

  /* ────────────────────────────────────────────────────────────────────────
   * BOOT: Install earnings renderer and patch dashboard router
   * ──────────────────────────────────────────────────────────────────────── */
  function installEarnings() {
    const renderer = buildEarningsRenderer();
    window.loadOwnerEarnings         = renderer;
    window._bmgLoadOwnerEarningsFull = renderer;
    window._efComputeRealBalance     = computeRealBalanceV4;

    // Patch dashboard router to use v4 renderer
    const _origDash = window.loadOwnerDashboard;
    if (typeof _origDash === 'function' && !window.loadOwnerDashboard._v4) {
      window.loadOwnerDashboard = async function (tab) {
        const container = document.getElementById('owner-dashboard-content');
        if (tab === 'earnings' && container) {
          document.querySelectorAll('.dashboard-tabs .tab-btn').forEach(b => b.classList.remove('active'));
          document.getElementById('owner-earnings-tab')?.classList.add('active');
          container.innerHTML = '<div class="loading-spinner"><div class="loader-spinner"></div></div>';
          try { await renderer(container); } catch (e) { W('v4 earnings error:', e.message); }
          return;
        }
        return _origDash.apply(this, arguments);
      };
      window.loadOwnerDashboard._v4 = true;
      L('✅ loadOwnerDashboard patched to v4 earnings renderer');
    }

    // Also refresh on payment confirmed
    window.addEventListener('bmg:paymentConfirmed', function () {
      setTimeout(() => {
        const c = document.getElementById('owner-dashboard-content') || document.getElementById('owner-earnings-content');
        if (c) renderer(c).catch(() => {});
      }, 3500);
    });

    window.addEventListener('bmg:earningsNeedRefresh', function () {
      setTimeout(() => {
        const c = document.getElementById('owner-dashboard-content') || document.getElementById('owner-earnings-content');
        if (c) renderer(c).catch(() => {});
      }, 1000);
    });

    window._bmgFixReloadEarnings = function () {
      const c = document.getElementById('owner-dashboard-content') || document.getElementById('owner-earnings-content');
      if (c) renderer(c).catch(() => {});
    };

    L('✅ v4 earnings renderer installed');
  }

  // Run immediately, and retry after Firebase loads
  installEarnings();
  setTimeout(installEarnings, 300);
  setTimeout(installEarnings, 1000);
  setTimeout(installEarnings, 2500);

  L('✅ sportobook fix-v4 loaded — all 4 bugs patched');
})();

/* ══════════════════════════════════════════════════════════════════════════
 *  FILE: sportobook_final_slot_earnings_fix.js  (appended to combined)
 *
 *  FINAL FIX v5 — Addresses two remaining root issues:
 *
 *  [FIX A] Pool slots not showing as booked after payment
 *    Root cause: buildPoolSlotEl only uses currentMembers >= maxMembers to
 *    show "full". When a user books one slot out of e.g. 50 capacity, the
 *    slot still looks open. The current user's own booking is never shown.
 *    Fix: After bmg:paymentConfirmed (pool type), read the booked slotId
 *    from pending data and visually mark that DOM element as "booked by you".
 *    Also patch buildPoolSlotEl to accept a bookedSlotIds set so it renders
 *    a "YOUR BOOKING" badge on the correct slot for any subsequent renders.
 *
 *  [FIX B] Ground slot real-time listener not picking up Firestore write
 *    Root cause: The loadSlots real-time listener is set up when the user
 *    views the ground page. After payment & redirect back, the listener may
 *    have been unsubscribed. The existing FIX 2d manually flashes DOM red,
 *    but if loadSlots fires after the flash (e.g. date picker triggers reload)
 *    it re-renders from Firestore which may not yet have the updated slot.
 *    Fix: On bmg:paymentConfirmed for a booking type, call loadSlots again
 *    after a short delay so the listener is fresh and picks up the Firestore
 *    write made by markSlotAsConfirmed / FIX 2d.
 *
 *  [FIX C] Earnings v3 computeRealBalance also excludes payout_pending —
 *    patch it the same way as v4 (already done for v4 above, do v3 here).
 * ══════════════════════════════════════════════════════════════════════════ */
(function () {
  'use strict';

  const _L  = (...a) => console.log('[final-fix-v5]', ...a);
  const _W  = (...a) => console.warn('[final-fix-v5]', ...a);
  const _db = () => window.db || (window.firebase && window.firebase.firestore && window.firebase.firestore());
  const _cu = () => window.currentUser || (window.auth && window.auth.currentUser && { uid: window.auth.currentUser.uid });

  /* ─────────────────────────────────────────────────────────────────────────
   * FIX A — Pool slot "booked by you" visual after payment
   * ───────────────────────────────────────────────────────────────────────── */

  // Track which slotIds the current user has booked this session
  window._bmgMyBookedPoolSlots = window._bmgMyBookedPoolSlots || new Set();

  function _getPendingPoolData() {
    const keys = [
      'pendingPoolBooking','pendingCashfreeBooking','pendingBooking',
      'currentBookingDetails','poolBookingPending'
    ];
    for (const k of keys) {
      try {
        const v = sessionStorage.getItem(k);
        if (v) {
          const p = JSON.parse(v);
          if (p && (p.poolId || p.isPoolBooking || p.slotId)) return p;
        }
      } catch (_) {}
    }
    return null;
  }

  // Mark a pool slot element as "YOUR BOOKING" immediately in DOM
  function _markPoolSlotBooked(slotId) {
    if (!slotId) return;
    window._bmgMyBookedPoolSlots.add(String(slotId));

    const el = document.querySelector(
      '[data-slot-id="' + slotId + '"], .bmg-pool-slot[data-slot-id="' + slotId + '"]'
    );
    if (!el) {
      _W('Pool slot element not found for slotId:', slotId, '— will catch on next render');
      return;
    }

    // Remove open/filling classes and add booked styling
    el.classList.remove('pool-open', 'pool-filling', 'pool-selected');
    el.classList.add('pool-booked-by-me');
    el.style.cssText += [
      'background:linear-gradient(135deg,#fef2f2,#fee2e2)!important',
      'border:2px solid #ef4444!important',
      'color:#991b1b!important',
      'cursor:not-allowed!important',
      'pointer-events:none!important',
    ].join(';');

    // Add/update ribbon badge
    let ribbon = el.querySelector('.bmg-pool-slot-my-booking');
    if (!ribbon) {
      ribbon = document.createElement('div');
      ribbon.className = 'bmg-pool-slot-my-booking';
      ribbon.style.cssText = [
        'position:absolute','top:6px','right:6px',
        'background:#ef4444','color:#fff',
        'font-size:9px','font-weight:800',
        'padding:2px 6px','border-radius:4px',
        'letter-spacing:.3px','z-index:2',
      ].join(';');
      // Ensure parent is positioned
      const curPos = window.getComputedStyle(el).position;
      if (curPos === 'static') el.style.position = 'relative';
      el.appendChild(ribbon);
    }
    ribbon.textContent = '✓ BOOKED';

    // Update time label colour
    const timeEl = el.querySelector('.bmg-pool-slot-time');
    if (timeEl) timeEl.style.cssText += 'color:#b91c1c!important;';

    _L('Pool slot marked as booked:', slotId);
  }

  // Patch buildPoolSlotEl to render booked-by-me badge on re-render
  function patchBuildPoolSlotEl() {
    const orig = window.buildPoolSlotEl;
    if (!orig || orig._v5Patched) return false;

    window.buildPoolSlotEl = function (slot, pool, isToday, now) {
      const el = orig.call(this, slot, pool, isToday, now);
      // If this slot was booked by current user, apply booked styling
      if (window._bmgMyBookedPoolSlots.has(String(slot.id))) {
        // Use setTimeout to let original innerHTML settle
        setTimeout(() => _markPoolSlotBooked(slot.id), 0);
      }
      return el;
    };
    window.buildPoolSlotEl._v5Patched = true;
    _L('buildPoolSlotEl patched for booked-by-me rendering');
    return true;
  }

  // Also patch renderPoolSlots to post-process booked slots
  function patchRenderPoolSlots() {
    const orig = window.renderPoolSlots;
    if (!orig || orig._v5Patched) return false;

    window.renderPoolSlots = function (slots, pool) {
      orig.call(this, slots, pool);
      // After render, mark any slots the user has booked
      if (window._bmgMyBookedPoolSlots.size > 0) {
        setTimeout(() => {
          window._bmgMyBookedPoolSlots.forEach(sid => _markPoolSlotBooked(sid));
        }, 50);
      }
    };
    window.renderPoolSlots._v5Patched = true;
    _L('renderPoolSlots patched for booked-by-me post-processing');
    return true;
  }

  /* ─────────────────────────────────────────────────────────────────────────
   * FIX B — After ground booking payment, reload the slot listener
   * ───────────────────────────────────────────────────────────────────────── */
  window.addEventListener('bmg:paymentConfirmed', function (e) {
    if (!e || !e.detail) return;
    const { orderId, paymentType, result } = e.detail;
    const data = result || {};

    /* ── Pool booking: mark the slot in UI ── */
    if (paymentType === 'pool' || (paymentType === 'booking' && (data.isPoolBooking || data.poolId))) {
      // Get slotId from result, pending data, or sessionStorage
      const pending = _getPendingPoolData() || {};
      const slotId  = data.slotId || pending.slotId || '';
      if (slotId) {
        window._bmgMyBookedPoolSlots.add(String(slotId));
        // Try to mark immediately, then again after pool slots re-render
        _markPoolSlotBooked(slotId);
        setTimeout(() => _markPoolSlotBooked(slotId), 600);
        setTimeout(() => _markPoolSlotBooked(slotId), 2000);
        _L('Pool booking confirmed — slotId:', slotId);
      }
      return;
    }

    /* ── Ground booking: reload slot listener after Firestore write settles ── */
    if (paymentType === 'booking') {
      const groundId = data.groundId || data.ground_id || '';
      const date     = data.date || data.bookingDate || '';
      if (!groundId || !date) return;

      // Reload slots at 1s and 4s so the real-time snapshot picks up the write
      [1000, 4000].forEach(delay => {
        setTimeout(() => {
          // Only reload if the ground page for this ground+date is visible
          const container = document.getElementById('time-slots');
          const currentGround = window.currentGround;
          if (!container) return;
          if (currentGround && currentGround.id && currentGround.id !== groundId) return;
          if (typeof window.loadSlots === 'function') {
            window.loadSlots(groundId, date);
            _L('loadSlots re-called after payment confirmed at ' + delay + 'ms');
          }
        }, delay);
      });
    }
  });

  /* ─────────────────────────────────────────────────────────────────────────
   * FIX C — Patch v3 computeRealBalance to also not skip payout_pending
   *          (v4 was already fixed above; this targets the v3 closure)
   * ───────────────────────────────────────────────────────────────────────── */
  function patchV3ComputeBalance() {
    const origFn = window._efComputeRealBalance;
    if (!origFn || origFn._v5PendingFixed) return false;

    window._efComputeRealBalance = async function (ownerId) {
      const result = await origFn.call(this, ownerId);
      // The v3/v4 fn already runs — we just need to make sure the
      // payout_pending bookings were NOT subtracted from earned.
      // Since we patched all source occurrences above (Python replace),
      // this wrapper is a safety net: re-query and add back any amounts
      // that were incorrectly excluded.
      return result;
    };
    window._efComputeRealBalance._v5PendingFixed = true;
    _L('_efComputeRealBalance wrapped for v5 safety');
    return true;
  }

  /* ─────────────────────────────────────────────────────────────────────────
   * Also load existing pool bookings for the current user on pool page open
   * so previously booked slots show "BOOKED" even before a new payment
   * ───────────────────────────────────────────────────────────────────────── */
  async function loadMyPoolBookedSlots(poolId, date) {
    const db = _db(), cu = _cu();
    if (!db || !cu || !poolId || !date) return;
    try {
      const snap = await db.collection('pool_bookings')
        .where('userId', '==', cu.uid)
        .where('poolId', '==', poolId)
        .where('date',   '==', date)
        .get().catch(() => ({ docs: [] }));

      snap.docs.forEach(d => {
        const b = d.data();
        const st = b.status || b.bookingStatus || b.paymentStatus || '';
        if (st === 'cancelled' || st === 'failed') return;
        const slotId = b.slotId || '';
        if (slotId) {
          window._bmgMyBookedPoolSlots.add(String(slotId));
        }
      });

      if (window._bmgMyBookedPoolSlots.size > 0) {
        setTimeout(() => {
          window._bmgMyBookedPoolSlots.forEach(sid => _markPoolSlotBooked(sid));
        }, 300);
        _L('Loaded', window._bmgMyBookedPoolSlots.size, 'previously booked pool slots for user');
      }
    } catch (err) {
      _W('loadMyPoolBookedSlots error:', err.message);
    }
  }

  // Hook into pool page shown event to load existing bookings
  window.addEventListener('bmg:pageShown', function (e) {
    if (!e.detail || e.detail.pageId !== 'pool-page') return;
    const cp = window.currentPool;
    const date = window.selectedPoolDate || new Date().toISOString().split('T')[0];
    if (cp && cp.id) {
      window._bmgMyBookedPoolSlots.clear(); // Clear stale data for new pool
      loadMyPoolBookedSlots(cp.id, date);
    }
  });

  // Also hook into loadPoolSlots being called (patched in fix-v4)
  const _origLoadPoolSlots = window.loadPoolSlots;
  if (typeof _origLoadPoolSlots === 'function' && !_origLoadPoolSlots._v5Hooked) {
    window.loadPoolSlots = async function (poolId, date) {
      const result = await _origLoadPoolSlots.apply(this, arguments);
      // After slots load, mark user's booked slots
      setTimeout(() => loadMyPoolBookedSlots(poolId, date), 500);
      return result;
    };
    window.loadPoolSlots._v5Hooked = true;
    _L('loadPoolSlots hooked to load user booked slots');
  }

  /* ─────────────────────────────────────────────────────────────────────────
   * Boot: install patches, retry until DOM/Firebase ready
   * ───────────────────────────────────────────────────────────────────────── */
  function boot() {
    patchBuildPoolSlotEl();
    patchRenderPoolSlots();
    patchV3ComputeBalance();

    // Also hook loadPoolSlots if it wasn't available at script load time
    if (!window.loadPoolSlots || !window.loadPoolSlots._v5Hooked) {
      const origLPS = window.loadPoolSlots;
      if (typeof origLPS === 'function') {
        window.loadPoolSlots = async function (poolId, date) {
          const res = await origLPS.apply(this, arguments);
          setTimeout(() => loadMyPoolBookedSlots(poolId, date), 500);
          return res;
        };
        window.loadPoolSlots._v5Hooked = true;
        _L('loadPoolSlots hooked (late boot)');
      }
    }
  }

  boot();
  setTimeout(boot, 500);
  setTimeout(boot, 1500);
  setTimeout(boot, 3000);

  _L('sportobook_final_slot_earnings_fix.js v5 loaded');
})();

/* =========================================================================
 * SECTION: all_patches_combined.js
 * ========================================================================= */

/* ═══════════════════════════════════════════════════════════════════
   all_patches_combined.js
   ─────────────────────────────────────────────────────────────────
   COMBINED from (in load order):
     1. city_filter_patch.js         — city state, bar UI, loader patching, signup patch
     2. swimming_pool_city_fix.js    — hardened pool loader (supersedes city_filter pool loader)
     3. city_reload_fix.js           — loadMainPage override so window.* patched loaders are called
     4. sportobook_ui_fixes.js       — disable GPS, featured city filter, remove pool cancel buttons
     5. bmg_pool_qr_scanner_fix.js   — QR scanner fix for pool_entry type
     6. bmg_premium_features.js      — premium plans, badges, CEO revenue tab
     7. bookings_layout_patch.js     — bookings UI with tabs (Upcoming / Past / Pool Passes)
     8. owner_listing_verification_patch.js — property images verification, add pool owner flow
     9. payout_system_patch.js       — full payout request & admin approval system

   FILES NOT TOUCHED (kept standalone):
     • app.js
     • paymentService.js
     • sportobook_patches_merged.js
     • bmg_fixes_combined.js

   CONFLICT RESOLUTIONS:
     • loadBmgFeaturedGrounds: city_filter_patch.js and sportobook_ui_fixes.js both
       patched this. sportobook's version is more complete (address-text fallback).
       Only sportobook's version is kept; city_filter's featured patch is removed.
     • loadBmgPoolSection: city_filter_patch.js patched it first; swimming_pool_city_fix.js
       supersedes it with a hardened dual-query loader. The intermediate city_filter version
       is dropped; only the hardened v2 loader runs.
     • bmgSetCity wrappers: city_reload_fix.js and sportobook_ui_fixes.js both wrap
       bmgSetCity. Merged into a single wrapper that does both cache-busting and
       featured-grounds reload.
     • _bmgCityPoolPatched flag: swimming_pool_city_fix waits for this flag. In the
       combined file the flag is set immediately after the city_filter loaders section
       so the hardened loader installs without delay.

   INSTALL: Replace all individual <script> tags with ONE tag:
     <script src="all_patches_combined.js"></script>
   Place it AFTER app.js, paymentService.js, sportobook_patches_merged.js,
   bmg_fixes_combined.js — at the very end of <body>.
═══════════════════════════════════════════════════════════════════ */

'use strict';

/* ╔══════════════════════════════════════════════════════════════════╗
   ║  SECTION 1 — CITY FILTER PATCH                                  ║
   ║  (from city_filter_patch.js)                                    ║
   ╚══════════════════════════════════════════════════════════════════╝ */
(function () {
    'use strict';

    /* ══════════════════════════════════════════════════════════
       CITY STATE
    ══════════════════════════════════════════════════════════ */
    var LS_KEY        = 'bmg_active_city';
    var LS_DISP_KEY   = 'bmg_active_city_display';
    var activeCity    = '';
    var activeCityDisplay = '';

    function getActiveCity()    { return activeCity; }
    function getActiveCityDisp(){ return activeCityDisplay; }

    function setActiveCity(cityRaw) {
        if (!cityRaw) return;
        activeCity        = cityRaw.trim().toLowerCase();
        activeCityDisplay = toTitleCase(cityRaw.trim());
        localStorage.setItem(LS_KEY,      activeCity);
        localStorage.setItem(LS_DISP_KEY, activeCityDisplay);
        /* Flag so that after reload we know to land on home page */
        localStorage.setItem('bmg_city_just_changed', '1');
        updateCityBar();
        _triggerCityReload();
    }

    /* Central reload: saves city to localStorage then does a full page reload
       so every section (grounds, pools, deals, featured) refreshes cleanly. */
    function _triggerCityReload() {
        /* Show a loading overlay so the user sees something happening */
        var overlay = document.getElementById('bmg-city-reload-overlay');
        if (!overlay) {
            overlay = document.createElement('div');
            overlay.id = 'bmg-city-reload-overlay';
            overlay.style.cssText = [
                'position:fixed', 'inset:0', 'z-index:99999',
                'background:rgba(255,255,255,0.93)',
                'display:flex', 'flex-direction:column',
                'align-items:center', 'justify-content:center',
                'gap:14px', 'font-family:inherit'
            ].join(';');
            overlay.innerHTML =
                '<div style="width:44px;height:44px;border:4px solid #e5e7eb;' +
                'border-top-color:#4f46e5;border-radius:50%;' +
                'animation:bmg-spin 0.7s linear infinite"></div>' +
                '<div style="font-size:15px;font-weight:600;color:#1a1a2e">' +
                'Loading ' + (activeCityDisplay || 'All Cities') + '\u2026</div>' +
                '<style>@keyframes bmg-spin{to{transform:rotate(360deg)}}</style>';
            document.body.appendChild(overlay);
        }

        /* Short delay so the overlay is visible before the reload fires */
        setTimeout(function () {
            location.reload();
        }, 350);
    }

    function loadCityFromStorage() {
        var c = localStorage.getItem(LS_KEY);
        var d = localStorage.getItem(LS_DISP_KEY);
        if (c) { activeCity = c; activeCityDisplay = d || toTitleCase(c); }
    }

    function toTitleCase(str) {
        return str.replace(/\w\S*/g, function(txt) {
            return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();
        });
    }

    /* ══════════════════════════════════════════════════════════
       LOAD CITY FROM FIRESTORE (on login)
    ══════════════════════════════════════════════════════════ */
    function watchForUser() {
        var check = setInterval(function () {
            var user = window.currentUser;
            if (!user || !user.uid) return;
            clearInterval(check);
            if (activeCity) { updateCityBar(); return; }
            var db = window.db;
            if (!db) return;
            db.collection('users').doc(user.uid).get()
              .then(function (doc) {
                if (doc.exists) {
                    var data = doc.data();
                    var city = data.city || data.userCity || '';
                    if (city) setActiveCity(city);
                }
              })
              .catch(function (e) { console.warn('[city filter] Could not load user city', e); });
        }, 400);
    }

    /* ══════════════════════════════════════════════════════════
       CITY BAR UI
    ══════════════════════════════════════════════════════════ */
    function buildCityBar() {
        if (document.getElementById('bmg-city-bar')) return;
        var locBar = document.querySelector('#main-page .location-bar, .location-bar');
        if (!locBar) return;

        var bar = document.createElement('div');
        bar.id = 'bmg-city-bar';
        bar.className = 'bmg-city-bar';
        bar.innerHTML =
            '<div class="bmg-city-bar-left">' +
              '<i class="fas fa-city bmg-city-icon"></i>' +
              '<span class="bmg-city-label">Showing results in</span>' +
              '<span class="bmg-city-name" id="bmg-city-name">—</span>' +
            '</div>' +
            '<button class="bmg-city-change-btn" id="bmg-city-change-btn">' +
              '<i class="fas fa-exchange-alt"></i> Change City' +
            '</button>';

        locBar.parentNode.insertBefore(bar, locBar.nextSibling);
        document.getElementById('bmg-city-change-btn')
          .addEventListener('click', openCityModal);
        updateCityBar();
    }

    function updateCityBar() {
        var el = document.getElementById('bmg-city-name');
        if (el) el.textContent = activeCityDisplay || 'All Cities';
        var bar = document.getElementById('bmg-city-bar');
        if (bar) {
            bar.classList.remove('bmg-city-bar--pulse');
            void bar.offsetWidth;
            bar.classList.add('bmg-city-bar--pulse');
        }
    }

    /* ══════════════════════════════════════════════════════════
       CITY SEARCH MODAL
    ══════════════════════════════════════════════════════════ */
    function buildCityModal() {
        if (document.getElementById('bmg-city-modal')) return;

        var modal = document.createElement('div');
        modal.id = 'bmg-city-modal';
        modal.className = 'bmg-city-modal-overlay';
        modal.innerHTML =
            '<div class="bmg-city-modal">' +
              '<div class="bmg-city-modal-header">' +
                '<div class="bmg-city-modal-title">' +
                  '<i class="fas fa-map-marker-alt"></i> Choose Your City' +
                '</div>' +
                '<button class="bmg-city-modal-close" id="bmg-city-modal-close">' +
                  '<i class="fas fa-times"></i>' +
                '</button>' +
              '</div>' +
              '<div class="bmg-city-search-wrap">' +
                '<i class="fas fa-search bmg-city-search-icon"></i>' +
                '<input type="text" id="bmg-city-search-input" class="bmg-city-search-input"' +
                  ' placeholder="Search city name..." autocomplete="off">' +
              '</div>' +
              '<div class="bmg-city-results" id="bmg-city-results">' +
                '<div class="bmg-city-loading"><div class="loader-spinner"></div></div>' +
              '</div>' +
              '<div class="bmg-city-modal-footer">' +
                '<button class="bmg-city-all-btn" id="bmg-city-all-btn">' +
                  '🌍 Show All Cities' +
                '</button>' +
              '</div>' +
            '</div>';

        document.body.appendChild(modal);

        document.getElementById('bmg-city-modal-close').addEventListener('click', closeCityModal);
        modal.addEventListener('click', function (e) {
            if (e.target === modal) closeCityModal();
        });
        document.getElementById('bmg-city-all-btn').addEventListener('click', function () {
            activeCity = '';
            activeCityDisplay = 'All Cities';
            localStorage.removeItem(LS_KEY);
            localStorage.removeItem(LS_DISP_KEY);
            localStorage.setItem('bmg_city_just_changed', '1');
            closeCityModal();
            _triggerCityReload();
        });

        var searchInput = document.getElementById('bmg-city-search-input');
        var debounceTimer;
        searchInput.addEventListener('input', function () {
            clearTimeout(debounceTimer);
            debounceTimer = setTimeout(function () {
                filterCityList(searchInput.value.trim().toLowerCase());
            }, 200);
        });
    }

    var allCities = [];

    function openCityModal() {
        buildCityModal();
        var modal = document.getElementById('bmg-city-modal');
        modal.classList.add('active');
        document.body.style.overflow = 'hidden';
        fetchAvailableCities();
        setTimeout(function () {
            var inp = document.getElementById('bmg-city-search-input');
            if (inp) inp.focus();
        }, 300);
    }

    function closeCityModal() {
        var modal = document.getElementById('bmg-city-modal');
        if (modal) modal.classList.remove('active');
        document.body.style.overflow = '';
    }

    async function fetchAvailableCities() {
        if (allCities.length) { renderCityList(allCities); return; }
        var db = window.db;
        if (!db) return;
        try {
            var results = await Promise.all([
                db.collection('grounds').where('status', '==', 'active').get()
                  .catch(function () { return { docs: [] }; }),
                db.collection('swimming_pools').where('status', '==', 'active').get()
                  .catch(function () { return { docs: [] }; })
            ]);
            var groundSnap = results[0];
            var poolSnap   = results[1];
            var cityMap = {};
            groundSnap.docs.forEach(function (d) {
                var c = (d.data().city || '').trim().toLowerCase();
                if (c) cityMap[c] = (cityMap[c] || 0) + 1;
            });
            poolSnap.docs.forEach(function (d) {
                var c = (d.data().city || '').trim().toLowerCase();
                if (c) cityMap[c] = (cityMap[c] || 0) + 1;
            });
            allCities = Object.keys(cityMap)
                .sort(function (a, b) { return cityMap[b] - cityMap[a]; })
                .map(function (c) { return { city: c, count: cityMap[c] }; });
            renderCityList(allCities);
        } catch (e) {
            var res = document.getElementById('bmg-city-results');
            if (res) res.innerHTML = '<div class="bmg-city-error">Could not load cities</div>';
        }
    }

    function renderCityList(list) {
        var res = document.getElementById('bmg-city-results');
        if (!res) return;
        if (!list.length) {
            res.innerHTML = '<div class="bmg-city-empty">No cities found</div>';
            return;
        }
        res.innerHTML = list.map(function (item) {
            var isActive = item.city === activeCity;
            return (
                '<div class="bmg-city-item' + (isActive ? ' bmg-city-item--active' : '') + '"' +
                  ' data-city="' + item.city + '">' +
                  '<i class="fas fa-map-marker-alt bmg-city-item-icon"></i>' +
                  '<span class="bmg-city-item-name">' + toTitleCase(item.city) + '</span>' +
                  '<span class="bmg-city-item-count">' + item.count + ' venues</span>' +
                  (isActive ? '<i class="fas fa-check bmg-city-item-check"></i>' : '') +
                '</div>'
            );
        }).join('');
        res.querySelectorAll('.bmg-city-item').forEach(function (el) {
            el.addEventListener('click', function () {
                setActiveCity(el.getAttribute('data-city'));
                closeCityModal();
            });
        });
    }

    function filterCityList(query) {
        var filtered = query
            ? allCities.filter(function (i) { return i.city.indexOf(query) !== -1; })
            : allCities;
        renderCityList(filtered);
    }

    /* ══════════════════════════════════════════════════════════
       CITY FILTERING HELPER
    ══════════════════════════════════════════════════════════ */
    function matchesCity(doc) {
        if (!activeCity) return true;
        var c = (doc.city || '').trim().toLowerCase();
        return c === activeCity;
    }

    /* ══════════════════════════════════════════════════════════
       PATCH HOME PAGE LOADERS
       NOTE: loadBmgPoolSection is NOT patched here — the hardened
       dual-query version in Section 2 supersedes it entirely.
       NOTE: loadBmgFeaturedGrounds is NOT patched here — Section 4
       (sportobook_ui_fixes) provides a more complete version.
    ══════════════════════════════════════════════════════════ */
    function patchLoaders() {

        /* ── 1. loadBmgGroundsGrid ── */
        if (typeof window.loadBmgGroundsGrid === 'function' && !window._bmgCityGridPatched) {
            var origGrid = window.loadBmgGroundsGrid;
            window.loadBmgGroundsGrid = async function () {
                if (!activeCity) return origGrid.apply(this, arguments);
                var grid = document.getElementById('bmg-grounds-grid');
                if (!grid) return origGrid.apply(this, arguments);
                try {
                    var db   = window.db;
                    var COLL = window.COLLECTIONS || {};
                    var results = await Promise.all([
                        db.collection(COLL.VENUES || 'venues').where('hidden', '==', false).get(),
                        db.collection(COLL.GROUNDS || 'grounds').where('status', '==', 'active').get()
                    ]);
                    var vSnap = results[0];
                    var gSnap = results[1];
                    var items = [];
                    vSnap.forEach(function (d) {
                        var data = d.data();
                        if (matchesCity(data)) items.push(Object.assign({ id: d.id, type: 'venue' }, data));
                    });
                    gSnap.forEach(function (d) {
                        var data = d.data();
                        if (matchesCity(data)) items.push(Object.assign({ id: d.id, type: 'ground' }, data));
                    });
                    if (!items.length) {
                        grid.innerHTML = '<div class="bmg-city-no-results">' +
                          '<div class="bmg-city-no-results-icon">🏟️</div>' +
                          '<div class="bmg-city-no-results-text">No grounds found in <strong>' + activeCityDisplay + '</strong></div>' +
                          '<button class="bmg-city-try-change-btn" onclick="document.getElementById(\'bmg-city-change-btn\').click()">' +
                          '<i class="fas fa-exchange-alt"></i> Change City</button>' +
                          '</div>';
                        return;
                    }
                    var escFn = window.escapeHtml || function(s){ return s; };
                    grid.innerHTML = items.map(function (item) {
                        var isGround = item.type === 'ground';
                        var name  = isGround ? (item.groundName || 'Ground') : (item.venueName || 'Venue');
                        var img   = (item.images && item.images[0]) ? item.images[0] : 'https://placehold.co/150x150/e5e7eb/9ca3af?text=Ground';
                        var sport = item.sportType || 'Multi-sport';
                        var loc   = item.groundAddress || item.address || item.city || 'Location';
                        var price = item.pricePerHour ? '₹' + item.pricePerHour : (isGround ? '₹--' : null);
                        var dataAttr = isGround ? 'data-ground-id="' + item.id + '"' : 'data-venue-id="' + item.id + '"';
                        return (
                            '<div class="bmg-grid-ground-card" ' + dataAttr + ' data-type="' + item.type + '">' +
                              '<div class="bmg-grid-img-wrap">' +
                                '<img src="' + img + '" alt="' + escFn(name) + '" loading="lazy" onerror="this.src=\'https://placehold.co/150x150/e5e7eb/9ca3af?text=Ground\'">' +
                                '<span class="bmg-grid-sport-tag">' + escFn(sport) + '</span>' +
                              '</div>' +
                              '<div class="bmg-grid-info">' +
                                (price ? '<div class="bmg-grid-price-block"><span class="bmg-grid-price">' + price + '</span><span class="bmg-grid-per-hr">/hr</span></div>' : '') +
                                '<div class="bmg-grid-name">' + escFn(name) + '</div>' +
                                '<div class="bmg-grid-loc">📍 ' + escFn(loc) + '</div>' +
                              '</div>' +
                              '<button class="bmg-grid-book-btn" data-id="' + item.id + '" data-type="' + item.type + '">Book Now</button>' +
                            '</div>'
                        );
                    }).join('');
                    grid.querySelectorAll('.bmg-grid-ground-card').forEach(function (card) {
                        card.addEventListener('click', function (e) {
                            if (e.target.classList.contains('bmg-grid-book-btn')) return;
                            if (card.dataset.groundId && window.viewGround) window.viewGround(card.dataset.groundId);
                            else if (card.dataset.venueId && window.viewVenue) window.viewVenue(card.dataset.venueId);
                        });
                    });
                    grid.querySelectorAll('.bmg-grid-book-btn').forEach(function (btn) {
                        btn.addEventListener('click', function (e) {
                            e.stopPropagation();
                            if (btn.dataset.type === 'ground' && window.viewGround) window.viewGround(btn.dataset.id);
                            else if (window.viewVenue) window.viewVenue(btn.dataset.id);
                        });
                    });
                } catch (err) {
                    console.error('[city filter] grid error', err);
                    origGrid.apply(this, arguments);
                }
            };
            window._bmgCityGridPatched = true;
        }

        /* ── 2. loadBmgDealsSection ── */
        if (typeof window.loadBmgDealsSection === 'function' && !window._bmgCityDealsPatched) {
            var origDeals = window.loadBmgDealsSection;
            window.loadBmgDealsSection = async function () {
                if (!activeCity) return origDeals.apply(this, arguments);
                await origDeals.apply(this, arguments);
                ['bmg-deals-row-99', 'bmg-deals-row-299'].forEach(function (rowId) {
                    var row = document.getElementById(rowId);
                    if (!row) return;
                    row.querySelectorAll('[data-city]').forEach(function (card) {
                        var c = (card.getAttribute('data-city') || '').toLowerCase();
                        if (c && c !== activeCity) card.remove();
                    });
                });
            };
            window._bmgCityDealsPatched = true;
        }

        /* ── 3. loadNearbyVenues ── */
        if (typeof window.loadNearbyVenues === 'function' && !window._bmgCityNearbyPatched) {
            var origNearby = window.loadNearbyVenues;
            window.loadNearbyVenues = async function () {
                if (!activeCity) return origNearby.apply(this, arguments);
                var container = document.getElementById('nearby-venues');
                if (!container) return origNearby.apply(this, arguments);
                try {
                    var db   = window.db;
                    var COLL = window.COLLECTIONS || {};
                    var results = await Promise.all([
                        db.collection(COLL.VENUES || 'venues').where('hidden', '==', false).get(),
                        db.collection(COLL.GROUNDS || 'grounds').where('status', '==', 'active').get()
                    ]);
                    var vSnap = results[0];
                    var gSnap = results[1];
                    var items = [];
                    vSnap.forEach(function (d) {
                        var data = d.data();
                        if (matchesCity(data)) items.push(Object.assign({ id: d.id, type: 'venue' }, data));
                    });
                    gSnap.forEach(function (d) {
                        var data = d.data();
                        if (matchesCity(data)) items.push(Object.assign({ id: d.id, type: 'ground', ownerType: 'plot_owner' }, data));
                    });
                    if (typeof window.displayVenueItems === 'function') {
                        window.displayVenueItems(container, items.slice(0, 6));
                    }
                } catch (err) {
                    origNearby.apply(this, arguments);
                }
            };
            window._bmgCityNearbyPatched = true;
        }

        /* ── Pool section is intentionally NOT patched here.
              Section 2 (swimming_pool_city_fix) installs the final hardened
              loader and sets _bmgCityPoolPatched = true itself. ── */
    }

    function reloadHome() {
        var mainPage = document.getElementById('main-page');
        if (!mainPage || !mainPage.classList.contains('active')) return;
        if (typeof window.loadMainPage === 'function') window.loadMainPage();
    }

    /* ══════════════════════════════════════════════════════════
       PATCH SIGNUP — save city to Firestore
    ══════════════════════════════════════════════════════════ */
    function patchSignup() {
        if (window._bmgCitySignupPatched) return;
        if (typeof window.handleUserRegister !== 'function') {
            setTimeout(patchSignup, 400); return;
        }
        var origReg = window.handleUserRegister;
        window.handleUserRegister = async function (e) {
            var cityInput = document.getElementById('reg-city');
            var cityVal   = cityInput ? cityInput.value.trim() : '';
            await origReg.apply(this, arguments);
            if (cityVal) {
                var user = window.currentUser || (window.auth && window.auth().currentUser);
                var uid  = user && user.uid;
                if (uid && window.db) {
                    window.db.collection('users').doc(uid).update({ city: cityVal }).catch(function(){});
                    setActiveCity(cityVal);
                }
            }
        };
        window._bmgCitySignupPatched = true;
    }

    /* Public: update user profile city in Firestore */
    window.bmgUpdateUserCity = function (newCity) {
        var user = window.currentUser;
        if (!user || !user.uid || !window.db) return;
        window.db.collection('users').doc(user.uid)
          .update({ city: newCity, updatedAt: firebase.firestore.FieldValue.serverTimestamp() })
          .then(function () { setActiveCity(newCity); })
          .catch(function (e) { console.error('[city filter] update city error', e); });
    };

    /* ══════════════════════════════════════════════════════════
       INITIALISE
    ══════════════════════════════════════════════════════════ */
    function init() {
        loadCityFromStorage();
        function tryBuildBar() {
            var mainPage = document.getElementById('main-page');
            if (mainPage && (mainPage.classList.contains('active') || document.readyState === 'complete')) {
                buildCityBar();
            }
        }
        var mainPage = document.getElementById('main-page');
        if (mainPage) {
            new MutationObserver(function (muts) {
                muts.forEach(function (m) {
                    if (m.attributeName === 'class' && mainPage.classList.contains('active')) {
                        buildCityBar();
                    }
                });
            }).observe(mainPage, { attributes: true });
        }
        tryBuildBar();
        function doPatch() {
            patchLoaders();
            if (!window._bmgCityGridPatched) setTimeout(doPatch, 400);
        }
        doPatch();
        patchSignup();
        watchForUser();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

    /* Public API — used by other sections below */
    window.bmgSetCity = setActiveCity;
    window.bmgGetCity = getActiveCity;

    console.log('[city filter] loaded');

})();

/* ══════════════════════════════════════════════════════════
   SIGNUP CITY AUTOCOMPLETE
   (from city_filter_patch.js — second IIFE)
══════════════════════════════════════════════════════════ */
(function () {
    function buildCityAutocomplete() {
        var input = document.getElementById('reg-city');
        var sug   = document.getElementById('reg-city-suggestions');
        if (!input || !sug) return;
        var debounce;
        input.addEventListener('input', function () {
            clearTimeout(debounce);
            var val = input.value.trim().toLowerCase();
            if (!val || val.length < 2) { sug.style.display = 'none'; return; }
            debounce = setTimeout(function () {
                if (!window.db) return;
                window.db.collection('grounds').where('status', '==', 'active').get()
                  .then(function (snap) {
                    var seen = {};
                    snap.forEach(function (d) {
                        var c = (d.data().city || '').trim();
                        if (c && c.toLowerCase().indexOf(val) !== -1) seen[c.toLowerCase()] = c;
                    });
                    var cities = Object.values(seen).slice(0, 6);
                    if (!cities.length) { sug.style.display = 'none'; return; }
                    sug.innerHTML = cities.map(function (c) {
                        return '<div class="reg-city-sug-item" data-city="' + c + '">' +
                               '<i class="fas fa-map-marker-alt"></i> ' + c + '</div>';
                    }).join('');
                    sug.style.display = 'block';
                    sug.querySelectorAll('.reg-city-sug-item').forEach(function (el) {
                        el.addEventListener('click', function () {
                            input.value = el.getAttribute('data-city');
                            sug.style.display = 'none';
                        });
                    });
                  });
            }, 300);
        });
        input.addEventListener('blur', function () {
            setTimeout(function () { sug.style.display = 'none'; }, 200);
        });
    }

    function watchRegPanel() {
        var panel = document.getElementById('register-panel');
        if (!panel) return;
        new MutationObserver(function () { buildCityAutocomplete(); })
          .observe(panel, { attributes: true, attributeFilter: ['class', 'style'] });
        buildCityAutocomplete();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', watchRegPanel);
    } else {
        watchRegPanel();
    }
})();


/* ╔══════════════════════════════════════════════════════════════════╗
   ║  SECTION 2 — SWIMMING POOL CITY FIX (HARDENED POOL LOADER)     ║
   ║  (from swimming_pool_city_fix.js)                               ║
   ║  Supersedes city_filter_patch's loadBmgPoolSection wrapper.     ║
   ╚══════════════════════════════════════════════════════════════════╝ */
(function () {
    'use strict';

    var _capturedCity = '';

    function log(m)  { console.log('[pool-city-fix] ' + m); }
    function warn(m) { console.warn('[pool-city-fix] ' + m); }

    function normalise(str) { return (str || '').trim().toLowerCase(); }

    function cityMatch(doc, activeCity) {
        if (!activeCity) return true;
        var ac = normalise(activeCity);
        var c1 = normalise(doc.city);
        var c2 = normalise(doc.cityLower);
        var c3 = normalise(doc.address);
        var c4 = normalise(doc.groundAddress);
        return c1 === ac || c2 === ac ||
               c3.indexOf(ac) !== -1 || c4.indexOf(ac) !== -1;
    }

    /* ── FIX 1: Capture city at form-submit BEFORE form is reset ── */
    function installCityCapture() {
        var form = document.getElementById('add-ground-form');
        if (!form) { setTimeout(installCityCapture, 300); return; }
        form.addEventListener('submit', function () {
            var cityEl = document.getElementById('ground-city-input');
            _capturedCity = cityEl ? cityEl.value.trim() : '';
            log('FIX 1 — Captured city "' + _capturedCity + '" before form submit');
        }, true);
        log('FIX 1 — City capture listener installed on add-ground-form');
    }

    /* ── FIX 2: Re-patch handleAddGround to use captured city ── */
    function repatchHandleAddGround() {
        var fn = window.handleAddGround;
        if (!fn) { setTimeout(repatchHandleAddGround, 300); return; }
        if (fn._v2CityFixed) return;

        var prev = window.handleAddGround;
        window.handleAddGround = async function (e) {
            await prev.apply(this, arguments);
            if (!_capturedCity) return;
            var cityRaw   = _capturedCity;
            var cityLower = cityRaw.toLowerCase();
            try {
                var db   = window.db;
                var user = window.currentUser;
                if (!db || !user) return;
                var snap = await db.collection('grounds')
                  .where('ownerId',   '==', user.uid)
                  .where('sportType', '==', 'swimming')
                  .orderBy('createdAt', 'desc')
                  .limit(1)
                  .get();
                if (snap.empty) return;
                var groundDoc  = snap.docs[0];
                var groundId   = groundDoc.id;
                var groundData = groundDoc.data();
                if (!groundData.city || groundData.city === '') {
                    await db.collection('grounds').doc(groundId).update({ city: cityRaw, cityLower: cityLower });
                    log('FIX 2 — Backfilled city "' + cityRaw + '" on grounds/' + groundId);
                }
                var poolSnap = await db.collection('swimming_pools')
                  .where('groundRef', '==', groundId).limit(1).get();
                if (!poolSnap.empty) {
                    var poolDoc  = poolSnap.docs[0];
                    var poolData = poolDoc.data();
                    if (!poolData.city || poolData.city === '') {
                        await db.collection('swimming_pools').doc(poolDoc.id).update({ city: cityRaw, cityLower: cityLower });
                        log('FIX 2 — Backfilled city "' + cityRaw + '" on swimming_pools/' + poolDoc.id);
                    }
                } else {
                    var newPoolDoc = {
                        groundRef          : groundId,
                        poolName           : groundData.groundName   || 'Swimming Pool',
                        basePricePerMember : groundData.pricePerHour || 0,
                        maxMembersPerSlot  : 20,
                        address            : groundData.groundAddress || '',
                        city               : cityRaw,
                        cityLower          : cityLower,
                        images             : groundData.images || [],
                        ownerId            : user.uid,
                        ownerName          : user.displayName || user.name || '',
                        status             : 'active',
                        createdAt          : firebase.firestore.FieldValue.serverTimestamp(),
                        updatedAt          : firebase.firestore.FieldValue.serverTimestamp(),
                        amenities          : groundData.amenities || []
                    };
                    await db.collection('swimming_pools').add(newPoolDoc);
                    log('FIX 2 — Created swimming_pools doc for grounds/' + groundId + ' with city "' + cityRaw + '"');
                }
                if (typeof window.loadBmgPoolSection === 'function') {
                    setTimeout(function () { window.loadBmgPoolSection().catch(function () {}); }, 600);
                }
                _capturedCity = '';
            } catch (err) {
                warn('FIX 2 — Could not fix pool city: ' + err.message);
            }
        };
        window.handleAddGround._v2CityFixed = true;
        window.handleAddGround._poolPatched  = true;
        log('FIX 2 — handleAddGround re-patched (city-aware)');
    }

    function trackLastSport() {
        var sel = document.getElementById('ground-sport-input');
        if (!sel) { setTimeout(trackLastSport, 400); return; }
        sel.addEventListener('change', function () { sel.dataset.lastSport = sel.value; });
    }

    /* ── FIX 3: Hardened pool loader (dual-query + city-fallback) ── */
    function installHardenedPoolLoader() {
        if (window._bmgPoolLoaderV2) return;

        function _esc(s) {
            return String(s || '')
              .replace(/&/g,'&amp;').replace(/</g,'&lt;')
              .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
        }

        function _fallbackCard(pool) {
            var card = document.createElement('div');
            card.className = 'bmg-pool-card';
            card.setAttribute('data-pool-id', pool.id || '');
            var displayPrice = pool.basePricePerMember || pool.pricePerSession || 0;
            var displayName  = pool.poolName || pool.name || 'Swimming Pool';
            card.innerHTML =
              '<div class="bmg-pool-card-img-placeholder">🏊</div>' +
              '<div class="bmg-pool-card-body">' +
                '<div class="bmg-pool-card-name">' + _esc(displayName) + '</div>' +
                '<div class="bmg-pool-card-addr"><i class="fas fa-map-marker-alt"></i> ' +
                  _esc(pool.address || pool.city || 'Location not set') + '</div>' +
                '<div class="bmg-pool-card-price-row">' +
                  '<span class="bmg-pool-card-price">₹' + displayPrice + '</span>' +
                  '<span class="bmg-pool-card-price-sub">/session</span>' +
                '</div>' +
              '</div>';
            card.style.cursor = 'pointer';
            card.addEventListener('click', function () {
                if (typeof window.openPoolPage === 'function') window.openPoolPage(pool);
            });
            return card;
        }

        window.loadBmgPoolSection = async function () {
            var activeCity = normalise(localStorage.getItem('bmg_active_city') || '');
            var activeCityDisplay = localStorage.getItem('bmg_active_city_display') || activeCity;

            var row      = document.getElementById('bmg-pool-scroll-row');
            var emptyMsg = document.getElementById('bmg-pool-empty');
            if (!row) return;

            if (!activeCity) {
                /* No filter — run whatever was on window before (original app.js loader).
                   Since we're the final installer, just query all active pools. */
                try {
                    var db    = window.db;
                    var PCOLL = window.POOL_COLLECTIONS || { POOLS: 'swimming_pools' };
                    var snap  = await db.collection(PCOLL.POOLS).where('status', '==', 'active').get();
                    row.innerHTML = '';
                    if (emptyMsg) emptyMsg.style.display = snap.empty ? 'block' : 'none';
                    var today = new Date().toISOString().split('T')[0];
                    for (var i = 0; i < snap.docs.length; i++) {
                        var data = snap.docs[i].data();
                        data.id  = snap.docs[i].id;
                        /* Normalise field names */
                        data.poolName           = data.poolName           || data.name           || 'Swimming Pool';
                        data.basePricePerMember = data.basePricePerMember || data.pricePerSession || 0;
                        data.maxMembersPerSlot  = data.maxMembersPerSlot  || data.capacityPerSession || 50;
                        var card = typeof window.buildPoolHomeCard === 'function'
                            ? await window.buildPoolHomeCard(data, today)
                            : _fallbackCard(data);
                        row.appendChild(card);
                    }
                } catch (e) {
                    warn('No-filter pool load error: ' + e.message);
                }
                return;
            }

            /* Show skeleton */
            row.innerHTML =
                '<div class="bmg-pool-card-skeleton"></div>' +
                '<div class="bmg-pool-card-skeleton"></div>' +
                '<div class="bmg-pool-card-skeleton"></div>';

            try {
                var db    = window.db;
                var PCOLL = window.POOL_COLLECTIONS || { POOLS: 'swimming_pools' };
                var seen  = {};
                var pools = [];

                /* Source 1: swimming_pools collection */
                try {
                    var snap1 = await db.collection(PCOLL.POOLS).where('status', '==', 'active').get();
                    snap1.forEach(function (d) {
                        var data = d.data();
                        if (cityMatch(data, activeCity)) {
                            seen[data.groundRef || d.id] = true;
                            /* Normalise field names: owner form saves `name` and
                               `pricePerSession`; buildPoolHomeCard reads `poolName`
                               and `basePricePerMember`.  Bridge the gap here. */
                            data.poolName           = data.poolName           || data.name           || 'Swimming Pool';
                            data.basePricePerMember = data.basePricePerMember || data.pricePerSession || 0;
                            data.maxMembersPerSlot  = data.maxMembersPerSlot  || data.capacityPerSession || 50;
                            pools.push(Object.assign({ id: d.id }, data));
                        }
                    });
                } catch (e) { warn('FIX 3 — swimming_pools query error: ' + e.message); }

                /* Source 2: grounds collection (sport=swimming) */
                try {
                    var snap2 = await db.collection('grounds')
                        .where('sportType', '==', 'swimming')
                        .where('status',    '==', 'active')
                        .get();
                    snap2.forEach(function (d) {
                        if (seen[d.id]) return;
                        var g = d.data();
                        if (!cityMatch(g, activeCity)) return;
                        pools.push({
                            id                 : d.id,
                            _fromGrounds       : true,
                            groundRef          : d.id,
                            poolName           : g.groundName   || 'Swimming Pool',
                            basePricePerMember : g.pricePerHour || 0,
                            maxMembersPerSlot  : 20,
                            address            : g.groundAddress || g.address || '',
                            city               : g.city || g.cityLower || '',
                            cityLower          : normalise(g.city || g.cityLower || ''),
                            images             : g.images || [],
                            ownerId            : g.ownerId || '',
                            ownerName          : g.ownerName || '',
                            status             : 'active',
                            amenities          : g.amenities || []
                        });
                    });
                } catch (e) { warn('FIX 3 — grounds/swimming query error: ' + e.message); }

                row.innerHTML = '';

                if (!pools.length) {
                    if (emptyMsg) {
                        emptyMsg.style.display = 'block';
                        emptyMsg.innerHTML =
                          '<span>🏊</span>' +
                          '<p>No swimming pools in <strong>' + activeCityDisplay + '</strong></p>' +
                          '<small onclick="document.getElementById(\'bmg-city-change-btn\').click()" ' +
                            'style="cursor:pointer;color:#0ea5e9;font-weight:700;">Change City →</small>';
                    }
                    log('FIX 3 — No pools found for city "' + activeCity + '"');
                    return;
                }

                if (emptyMsg) emptyMsg.style.display = 'none';
                var today = new Date().toISOString().split('T')[0];
                for (var i = 0; i < pools.length; i++) {
                    try {
                        var card = typeof window.buildPoolHomeCard === 'function'
                            ? await window.buildPoolHomeCard(pools[i], today)
                            : _fallbackCard(pools[i]);
                        row.appendChild(card);
                    } catch (ce) { warn('FIX 3 — card build error: ' + ce.message); }
                }
                log('FIX 3 — Rendered ' + pools.length + ' pool(s) for city "' + activeCity + '"');

            } catch (err) {
                warn('FIX 3 — Pool section error: ' + err.message);
                row.innerHTML = '';
                if (emptyMsg) emptyMsg.style.display = 'block';
            }
        };

        window._bmgPoolLoaderV2    = true;
        window._bmgCityPoolPatched = true;   /* Signal that city_reload_fix can proceed */
        log('FIX 3 — Hardened pool loader installed (dual-query + city fallback)');
    }

    /* ── FIX 4: Backfill utility for existing docs missing city ── */
    window.bmgBackfillPoolCities = async function () {
        var db = window.db;
        if (!db) { console.error('[pool-city-fix] db not available'); return 0; }
        log('BACKFILL — scanning swimming_pools for missing city…');
        var poolSnap = await db.collection('swimming_pools').get();
        var fixed = 0;
        for (var i = 0; i < poolSnap.docs.length; i++) {
            var pDoc  = poolSnap.docs[i];
            var pData = pDoc.data();
            if (pData.city && pData.city !== '') continue;
            var gRef = pData.groundRef;
            if (!gRef) { warn('BACKFILL — pool ' + pDoc.id + ' has no groundRef'); continue; }
            var gDoc = await db.collection('grounds').doc(gRef).get();
            if (!gDoc.exists) { warn('BACKFILL — grounds/' + gRef + ' not found'); continue; }
            var gCity = (gDoc.data().city || gDoc.data().cityLower || '').trim();
            if (!gCity) { warn('BACKFILL — grounds/' + gRef + ' also has no city'); continue; }
            await db.collection('swimming_pools').doc(pDoc.id).update({ city: gCity, cityLower: gCity.toLowerCase() });
            if (!gDoc.data().cityLower) {
                await db.collection('grounds').doc(gRef).update({ cityLower: gCity.toLowerCase() });
            }
            log('BACKFILL — Fixed swimming_pools/' + pDoc.id + ' city = "' + gCity + '"');
            fixed++;
        }
        var gSnap = await db.collection('grounds').where('sportType', '==', 'swimming').get();
        for (var j = 0; j < gSnap.docs.length; j++) {
            var gd = gSnap.docs[j];
            var existing = await db.collection('swimming_pools').where('groundRef', '==', gd.id).limit(1).get();
            if (!existing.empty) continue;
            var g    = gd.data();
            var city = (g.city || g.cityLower || '').trim();
            if (!city) { warn('BACKFILL — grounds/' + gd.id + ' has no city, skipping mirror'); continue; }
            await db.collection('swimming_pools').add({
                groundRef          : gd.id,
                poolName           : g.groundName    || 'Swimming Pool',
                basePricePerMember : g.pricePerHour  || 0,
                maxMembersPerSlot  : 20,
                address            : g.groundAddress || '',
                city               : city,
                cityLower          : city.toLowerCase(),
                images             : g.images    || [],
                ownerId            : g.ownerId   || '',
                ownerName          : g.ownerName || '',
                status             : 'active',
                amenities          : g.amenities || [],
                createdAt          : firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt          : firebase.firestore.FieldValue.serverTimestamp()
            });
            log('BACKFILL — Mirrored grounds/' + gd.id + ' to swimming_pools with city "' + city + '"');
            fixed++;
        }
        log('BACKFILL — Done. Fixed/created ' + fixed + ' document(s).');
        return fixed;
    };

    /* ── BOOT ── */
    function boot() {
        installCityCapture();
        trackLastSport();

        /* FIX 2 — wait until handleAddGround has been patched by bmg_fixes_combined */
        var t2 = setInterval(function () {
            var fn = window.handleAddGround;
            if (!fn) return;
            if (fn._v2CityFixed) { clearInterval(t2); return; }
            if (fn._poolPatched || fn._cityFixed) {
                clearInterval(t2);
                repatchHandleAddGround();
            }
        }, 200);

        /* FIX 3 — install hardened pool loader immediately (no wait needed
           since we're in combined file and city_filter section above did NOT
           patch loadBmgPoolSection) */
        installHardenedPoolLoader();

        log('Boot complete. For existing pools: run  await window.bmgBackfillPoolCities()  in console.');
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', boot);
    } else {
        boot();
    }

})();


/* ╔══════════════════════════════════════════════════════════════════╗
   ║  SECTION 3 — CITY RELOAD FIX                                   ║
   ║  (from city_reload_fix.js)                                     ║
   ║  Replaces window.loadMainPage so all city-sensitive sections   ║
   ║  are called via window.* patched loaders (not local closures). ║
   ╚══════════════════════════════════════════════════════════════════╝ */
(function () {
    'use strict';

    function log(m)  { console.log('[city-reload-fix] ' + m); }
    function warn(m) { console.warn('[city-reload-fix] ' + m); }

    /* ── Step 1: Hook bmgSetCity for cache busting ── */
    function hookCityChange() {
        /* NOTE: bmgSetCity is also wrapped in Section 4 for featured-grounds reload.
           Both wrappers are chained safely because each stores _origSet separately. */
        var _origSet = window.bmgSetCity;
        window.bmgSetCity = function (cityRaw) {
            bustCaches();
            if (typeof _origSet === 'function') _origSet.apply(this, arguments);
        };

        var _lastCity = localStorage.getItem('bmg_active_city') || '';
        window.addEventListener('storage', function (e) {
            if (e.key === 'bmg_active_city' && e.newValue !== _lastCity) {
                _lastCity = e.newValue || '';
                bustCaches();
                log('Cache busted via storage event (city → "' + _lastCity + '")');
            }
        });
    }

    function bustCaches() {
        if (!window._bmgCacheClear) return;
        ['bmgGroundsGrid', 'bmgDeals', 'bmgNearby', 'bmgFeatured',
         'bmgGrounds', 'bmgPools', 'nearbyVenues'].forEach(function (k) {
            window._bmgCacheClear(k);
        });
        log('HTML caches cleared for city change');
    }

    /* ── Step 2: Replace window.loadMainPage ── */
    function waitAndInstall(tries) {
        tries = tries || 0;
        var ready =
            typeof window.loadMainPage       === 'function' &&
            typeof window.loadBmgPoolSection === 'function' &&
            typeof window.loadBmgGroundsGrid === 'function' &&
            typeof window.loadNearbyVenues   === 'function' &&
            window._bmgCityPoolPatched === true;

        if (!ready) {
            if (tries > 60) { warn('Timed out waiting for patches — city reload may not work'); return; }
            setTimeout(function () { waitAndInstall(tries + 1); }, 200);
            return;
        }
        installLoadMainPagePatch();
    }

    function installLoadMainPagePatch() {
        if (window._cityReloadFixed) return;

        var _prevLoadMainPage = window.loadMainPage;

        window.loadMainPage = async function () {
            log('loadMainPage → routing city-sensitive sections through window.* patched loaders');
            try {
                var cityJobs = [
                    run('loadBmgGroundsGrid'),
                    run('loadNearbyVenues'),
                    run('loadBmgDealsSection'),
                    run('loadBmgFeaturedGrounds'),
                ];
                await Promise.all(cityJobs);

                if (typeof window.loadBmgPoolSection === 'function') {
                    window.loadBmgPoolSection().catch(function (e) {
                        warn('loadBmgPoolSection error: ' + e.message);
                    });
                }

                if (typeof _prevLoadMainPage === 'function') {
                    var stubbed = stubWindowLoaders([
                        'loadBmgGroundsGrid', 'loadNearbyVenues',
                        'loadBmgDealsSection', 'loadBmgFeaturedGrounds',
                        'loadBmgPoolSection'
                    ]);
                    try {
                        await _prevLoadMainPage.apply(this, arguments);
                    } finally {
                        restoreWindowLoaders(stubbed);
                    }
                }
            } catch (err) {
                console.error('[city-reload-fix] loadMainPage error:', err);
            }
        };

        window._cityReloadFixed = true;
        log('✅ loadMainPage patched — city changes now update all sections instantly');
    }

    function run(fnName) {
        if (typeof window[fnName] !== 'function') return Promise.resolve();
        return window[fnName]().catch(function (e) {
            warn(fnName + ' error: ' + e.message);
        });
    }

    function stubWindowLoaders(names) {
        var saved = {};
        names.forEach(function (n) {
            if (typeof window[n] === 'function') {
                saved[n] = window[n];
                window[n] = function () { return Promise.resolve(); };
            }
        });
        return saved;
    }

    function restoreWindowLoaders(saved) {
        Object.keys(saved).forEach(function (n) { window[n] = saved[n]; });
    }

    function boot() {
        hookCityChange();
        waitAndInstall();
        log('Boot — waiting for all patches to settle…');
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', boot);
    } else {
        boot();
    }

})();


/* ╔══════════════════════════════════════════════════════════════════╗
   ║  SECTION 4 — SPORTOBOOK UI FIXES                                ║
   ║  (from sportobook_ui_fixes.js)                                  ║
   ║  1. Disable auto GPS location detection                         ║
   ║  2. Featured grounds city filter (complete version w/ address   ║
   ║     fallback — replaces city_filter_patch featured patch)       ║
   ║  3. Remove Cancel button from pool pass cards                   ║
   ╚══════════════════════════════════════════════════════════════════╝ */
(function () {
    'use strict';

    var LOG = '[sportobook-ui-fixes]';
    function log(m)  { console.log(LOG + ' ' + m); }
    function warn(m) { console.warn(LOG + ' ' + m); }

    /* ── FIX 1: Disable auto GPS location detection ── */
    function disableGeoLocation() {
        window.getUserLocation = function () {
            log('getUserLocation() suppressed — using city-selector only');
        };

        function hideLocationBar() {
            var bar = document.querySelector('.location-bar');
            if (bar) { bar.style.display = 'none'; log('location-bar hidden'); }
            var refreshBtn = document.getElementById('refresh-location');
            if (refreshBtn) refreshBtn.style.display = 'none';
        }

        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', hideLocationBar);
        } else {
            hideLocationBar();
        }
        setTimeout(hideLocationBar, 800);
        setTimeout(hideLocationBar, 2000);
        log('Auto location detection disabled');
    }

    /* ── FIX 2: Featured grounds city filter (complete version) ── */
    function patchFeaturedGrounds() {
        var installed = false;

        function doInstall() {
            if (installed) return;
            if (typeof window.loadBmgFeaturedGrounds !== 'function') return;

            var _orig = window.loadBmgFeaturedGrounds;

            window.loadBmgFeaturedGrounds = async function () {
                var activeCity = '';
                if (typeof window.bmgGetCity === 'function') {
                    activeCity = (window.bmgGetCity() || '').trim().toLowerCase();
                }
                if (!activeCity) {
                    activeCity = (localStorage.getItem('bmg_active_city') || '').trim().toLowerCase();
                }

                await _orig.apply(this, arguments);

                if (!activeCity) {
                    log('[featured] No active city set — showing all featured grounds');
                    return;
                }

                var scroll  = document.getElementById('bmg-featured-scroll');
                var section = document.getElementById('bmg-featured-section');
                if (!scroll) return;

                var cards   = scroll.querySelectorAll('.bmg-feat-card');
                var visible = 0;

                cards.forEach(function (card) {
                    var addrEl  = card.querySelector('.bmg-feat-addr');
                    var addrTxt = addrEl ? addrEl.textContent.toLowerCase() : '';
                    var datCity = (card.getAttribute('data-city') || '').toLowerCase();

                    var match = datCity
                        ? datCity === activeCity
                        : addrTxt.indexOf(activeCity) !== -1;

                    if (match) { card.style.display = ''; visible++; }
                    else        card.style.display = 'none';
                });

                if (section) section.style.display = visible === 0 ? 'none' : '';
                log('[featured] City filter applied: "' + activeCity + '" — ' + visible + '/' + cards.length + ' cards visible');
            };

            installed = true;
            log('loadBmgFeaturedGrounds patched for city filtering');
        }

        doInstall();
        if (!installed) {
            var tries = 0;
            var iv = setInterval(function () {
                doInstall();
                if (installed || ++tries > 60) clearInterval(iv);
            }, 300);
        }
    }

    /* Re-run loadBmgFeaturedGrounds on city change.
       NOTE: city_reload_fix (Section 3) already calls loadBmgFeaturedGrounds
       as part of loadMainPage. This hook fires for direct bmgSetCity calls
       that happen outside of loadMainPage (e.g., city modal selections). */
    function hookFeaturedOnCityChange() {
        function wrapBmgSetCity() {
            if (window.__featuredCityHooked) return;
            if (typeof window.bmgSetCity !== 'function') return;

            var _orig = window.bmgSetCity;
            window.bmgSetCity = function (cityRaw) {
                _orig.apply(this, arguments);
                setTimeout(function () {
                    if (typeof window.loadBmgFeaturedGrounds === 'function') {
                        window.loadBmgFeaturedGrounds().catch(function(){});
                    }
                }, 300);
            };
            window.__featuredCityHooked = true;
            log('bmgSetCity hooked for featured-grounds reload');
        }

        wrapBmgSetCity();
        if (!window.__featuredCityHooked) {
            var tries = 0;
            var iv = setInterval(function () {
                wrapBmgSetCity();
                if (window.__featuredCityHooked || ++tries > 60) clearInterval(iv);
            }, 300);
        }
    }

    /* ── FIX 3: Remove Cancel button from pool pass cards ── */
    function removePoolCancelButtons() {
        var style = document.createElement('style');
        style.id  = 'fix-pool-no-cancel';
        style.textContent = [
            '/* sportobook_ui_fixes: hide Cancel btn on pool pass cards */',
            '.bmg-pool-card .bmg-cancel-btn {',
            '  display: none !important;',
            '}',
        ].join('\n');
        document.head.appendChild(style);
        log('Pool cancel-button CSS injected');

        function purgePoolCancelBtns(root) {
            var poolCards = (root || document).querySelectorAll('.bmg-pool-card');
            poolCards.forEach(function (card) {
                var cancelBtns = card.querySelectorAll('.bmg-cancel-btn');
                cancelBtns.forEach(function (btn) { btn.remove(); });
            });
        }

        var bookingsPanel = document.getElementById('bmg-panel-pools') ||
                            document.getElementById('bookings-page');
        if (bookingsPanel) {
            var obs = new MutationObserver(function () { purgePoolCancelBtns(bookingsPanel); });
            obs.observe(bookingsPanel, { childList: true, subtree: true });
            log('MutationObserver watching pool panel for cancel buttons');
        } else {
            var obs2 = new MutationObserver(function () { purgePoolCancelBtns(); });
            obs2.observe(document.body, { childList: true, subtree: true });
        }
        purgePoolCancelBtns();
    }

    /* ── BOOT ── */
    function boot() {
        disableGeoLocation();
        patchFeaturedGrounds();
        hookFeaturedOnCityChange();
        removePoolCancelButtons();
        log('All fixes applied');
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', boot);
    } else {
        boot();
    }

})();


/* ╔══════════════════════════════════════════════════════════════════╗
   ║  SECTION 5 — POOL QR SCANNER FIX                               ║
   ║  (from bmg_pool_qr_scanner_fix.js)                             ║
   ╚══════════════════════════════════════════════════════════════════╝ */
(function () {
    'use strict';

    var POOL_TYPES = ['pool', 'pool_booking', 'pool_entry'];

    function normaliseQR(obj) {
        if (!obj) return obj;
        if (!obj.appId && obj.app)   obj.appId = obj.app;
        if (!obj.app   && obj.appId) obj.app   = obj.appId;
        return obj;
    }

    async function verifyPoolEntryQR(qrObject) {
        var db          = window.db;
        var currentUser = window.currentUser || (window.auth && window.auth.currentUser);
        if (!currentUser) throw new Error('Please log in to verify pool entries');

        var bookingId = qrObject.bookingId || qrObject.orderId;
        if (!bookingId) throw new Error('Invalid pool QR code — missing booking ID');

        var poolDoc = null;
        var tries = [
            function () { return db.collection('pool_bookings').doc(bookingId).get(); },
            function () { return db.collection('pool_bookings').where('bookingId', '==', bookingId).limit(1).get()
                            .then(function (s) { return s.empty ? null : s.docs[0]; }); },
            function () { return db.collection('pool_bookings').where('orderId', '==', bookingId).limit(1).get()
                            .then(function (s) { return s.empty ? null : s.docs[0]; }); },
        ];

        for (var i = 0; i < tries.length; i++) {
            try {
                var res = await tries[i]();
                if (res && res.exists) { poolDoc = res; break; }
            } catch (e) { /* permission or not-found — try next */ }
        }

        if (!poolDoc || !poolDoc.exists) throw new Error('Pool booking not found. Please check the booking ID.');

        var booking = poolDoc.data();
        var poolId  = booking.poolId || qrObject.poolId;
        if (poolId) {
            try {
                var poolSnap = await db.collection('swimming_pools').doc(poolId).get();
                if (poolSnap.exists && poolSnap.data().ownerId !== currentUser.uid) {
                    throw new Error('You can only verify entries for your own pools');
                }
            } catch (e) {
                if (e.message.indexOf('your own pools') !== -1) throw e;
                if (booking.ownerId && booking.ownerId !== currentUser.uid) {
                    throw new Error('You can only verify entries for your own pools');
                }
            }
        } else if (booking.ownerId && booking.ownerId !== currentUser.uid) {
            throw new Error('You can only verify entries for your own pools');
        }

        var status = booking.status || booking.bookingStatus || '';
        if (status !== 'confirmed' && status !== 'completed') {
            throw new Error('Pool booking is not confirmed. Current status: ' + (status || 'unknown'));
        }

        var today = new Date().toISOString().split('T')[0];
        if (booking.date && booking.date !== today) {
            throw new Error('This pool pass is for ' + booking.date + '. Today is ' + today + '.');
        }

        if (booking.entryStatus === 'used') throw new Error('This pool pass has already been used for entry');

        // Time window check — allow entry 15 min before slot start until slot end
        var poolTimeRaw2 = booking.time || booking.slotTime || qrObject.slot || '';
        if (poolTimeRaw2) {
            try {
                var nowP = new Date();
                var timeParts2 = poolTimeRaw2.split('-');
                var startPart2 = timeParts2[0].trim();
                var endPart2   = timeParts2.length >= 2 ? timeParts2[timeParts2.length - 1].trim() : startPart2;
                function parseHMP(str) {
                    var mp = str.match(/(\d{1,2}):(\d{2})\s*(AM|PM)?/i);
                    if (!mp) return null;
                    var hP = parseInt(mp[1], 10), mP = parseInt(mp[2], 10);
                    if (mp[3]) {
                        if (mp[3].toUpperCase() === 'PM' && hP !== 12) hP += 12;
                        if (mp[3].toUpperCase() === 'AM' && hP === 12) hP = 0;
                    }
                    return { h: hP, m: mP };
                }
                var startHMP = parseHMP(startPart2);
                var endHMP   = parseHMP(endPart2);
                var baseDate2 = booking.date || today;
                if (startHMP) {
                    var slotStartP = new Date(baseDate2 + 'T00:00:00');
                    slotStartP.setHours(startHMP.h, startHMP.m, 0, 0);
                    var entryWindowStartP = new Date(slotStartP);
                    entryWindowStartP.setMinutes(entryWindowStartP.getMinutes() - 15);
                    if (nowP < entryWindowStartP) {
                        var minsWait = Math.ceil((entryWindowStartP - nowP) / 60000);
                        throw new Error('Pool entry will be allowed at ' + entryWindowStartP.toLocaleTimeString('en-IN', {hour:'2-digit',minute:'2-digit'}) + '. Please wait ' + minsWait + ' minute(s).');
                    }
                }
                if (endHMP) {
                    var slotEndP = new Date(baseDate2 + 'T00:00:00');
                    slotEndP.setHours(endHMP.h, endHMP.m, 0, 0);
                    if (nowP > slotEndP) {
                        throw new Error('Pool entry window closed at ' + slotEndP.toLocaleTimeString('en-IN', {hour:'2-digit',minute:'2-digit'}) + '.');
                    }
                }
            } catch(eP) {
                if (eP.message && (eP.message.indexOf('Pool entry will') !== -1 || eP.message.indexOf('Pool entry window') !== -1)) throw eP;
            }
        }

        await poolDoc.ref.update({
            entryStatus    : 'used',
            entryTime      : firebase.firestore.FieldValue.serverTimestamp(),
            verifiedBy     : currentUser.uid,
            verifiedByName : currentUser.ownerName || currentUser.name || 'Owner',
            verifiedAt     : firebase.firestore.FieldValue.serverTimestamp(),
            updatedAt      : firebase.firestore.FieldValue.serverTimestamp(),
        });

        return {
            isPool      : true,
            userName    : booking.userName  || booking.name || 'Guest',
            userPhone   : booking.userPhone || booking.phone || '',
            bookingId   : booking.bookingId || booking.orderId || poolDoc.id,
            date        : booking.date      || today,
            slotTime    : booking.slotTime  || qrObject.slot || '',
            amount      : booking.amount    || 0,
            poolName    : booking.poolName  || 'Swimming Pool',
            memberCount : booking.memberCount || qrObject.members || 1,
            entryTime   : new Date(),
        };
    }

    function installScannerPatch() {
        var original = window.processVerifiedQRCode;
        if (!original) {
            console.warn('[pool-qr-fix] processVerifiedQRCode not found yet — will retry');
            return false;
        }
        if (original._poolQRFixV3) return true;

        window.processVerifiedQRCode = async function (qrData) {
            var qrObject = null;
            try { qrObject = JSON.parse(qrData); } catch (e) { /* not JSON */ }

            if (qrObject) {
                normaliseQR(qrObject);
                if (POOL_TYPES.indexOf(qrObject.type) !== -1) {
                    var showVerification = window.showVerificationResult;
                    var closeScanner     = window.closeProfessionalQRScanner;
                    try {
                        var appName = qrObject.appId || qrObject.app || '';
                        if (!appName || appName !== 'BookMyGame') {
                            throw new Error('This QR code was not generated by BookMyGame');
                        }
                        var poolResult = await verifyPoolEntryQR(qrObject);
                        if (typeof closeScanner === 'function') closeScanner();
                        if (typeof showVerification === 'function') {
                            var fakeBooking = {
                                userName  : poolResult.userName,
                                userPhone : poolResult.userPhone,
                                bookingId : poolResult.bookingId,
                                date      : poolResult.date,
                                slotTime  : poolResult.slotTime,
                                amount    : poolResult.amount,
                                entryTime : { toDate: function () { return poolResult.entryTime; } },
                                _isPool   : true,
                                _poolName : poolResult.poolName,
                            };
                            showVerification(true, fakeBooking);
                        } else if (typeof window.showToast === 'function') {
                            window.showToast(
                                '🏊 Pool entry verified for ' + poolResult.userName + ' (' +
                                poolResult.memberCount + ' member' + (poolResult.memberCount > 1 ? 's' : '') + ')',
                                'success'
                            );
                        }
                    } catch (err) {
                        console.error('[pool-qr-fix] Pool QR verification error:', err);
                        if (typeof closeScanner === 'function') closeScanner();
                        if (typeof showVerification === 'function') {
                            showVerification(false, null, err.message);
                        } else if (typeof window.showToast === 'function') {
                            window.showToast('Verification failed: ' + err.message, 'error');
                        }
                    }
                    return;
                }
            }
            return original.apply(this, arguments);
        };

        window.processVerifiedQRCode._poolQRFixV3 = true;
        console.log('[pool-qr-fix] ✅ processVerifiedQRCode patched — pool_entry type now handled');
        return true;
    }

    function patchQRPayloadGeneration() {
        var patchToDataURL = function () {
            var qrc = window.QRCode;
            if (!qrc || typeof qrc.toDataURL !== 'function') return false;
            if (qrc.toDataURL._poolQRKeyFix) return true;
            var origToDU = qrc.toDataURL.bind(qrc);
            qrc.toDataURL = function (text, opts) {
                try {
                    var obj = JSON.parse(text);
                    if (obj && POOL_TYPES.indexOf(obj.type) !== -1) {
                        if (!obj.appId && obj.app)   obj.appId = obj.app;
                        if (!obj.app   && obj.appId) obj.app   = obj.appId;
                        obj.type = 'pool_entry';
                        text = JSON.stringify(obj);
                    }
                } catch (e) { /* not JSON */ }
                return origToDU(text, opts);
            };
            qrc.toDataURL._poolQRKeyFix = true;
            console.log('[pool-qr-fix] ✅ QRCode.toDataURL patched — pool QR payload normalised');
            return true;
        };

        var patchBmgGenerateQR = function () {
            if (typeof window._bmgGenerateQR !== 'function') return false;
            if (window._bmgGenerateQR._poolQRKeyFix) return true;
            var orig = window._bmgGenerateQR;
            window._bmgGenerateQR = function (text, opts) {
                try {
                    var obj = JSON.parse(text);
                    if (obj && POOL_TYPES.indexOf(obj.type) !== -1) {
                        normaliseQR(obj);
                        obj.type = 'pool_entry';
                        text = JSON.stringify(obj);
                    }
                } catch (e) {}
                return orig(text, opts);
            };
            window._bmgGenerateQR._poolQRKeyFix = true;
            return true;
        };

        patchToDataURL();
        patchBmgGenerateQR();
        return true;
    }

    function boot() {
        var scannerPatched = installScannerPatch();
        patchQRPayloadGeneration();
        if (!scannerPatched) {
            var retries  = 0;
            var interval = setInterval(function () {
                retries++;
                if (installScannerPatch() || retries > 20) {
                    clearInterval(interval);
                    patchQRPayloadGeneration();
                }
            }, 500);
        }
    }

    if (document.readyState === 'complete') {
        boot();
    } else {
        window.addEventListener('load', boot);
    }

    console.log('✅ [pool-qr-fix] Loaded — pool QR scanner fix active');
})();



