      '}',
      '#professional-qr-modal .scanner-btn.torch-btn {',
        'background: rgba(251,191,36,0.12) !important;',
        'color: #fbbf24 !important;',
        'border-color: rgba(251,191,36,0.25) !important;',
      '}',
      '#professional-qr-modal .scanner-btn.torch-btn.active {',
